import{_ as a,c as e,o as m,b as t}from"./app.56f378f3.js";const y='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C\u044B 16\u201422","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C\u044B 16\u201422","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 1.","sans":"\u0936\u0941\u0926\u094D\u0927\u0924\u0924\u094D\u0924\u094D\u0935\u0938\u0928\u094D\u0927\u093E\u0928\u093E\u0926\u094D\u0935\u093E\u092A\u0936\u0941\u0936\u0915\u094D\u0924\u093F\u0903","trans":"\u015Auddhatattvasandh\u0101n\u0101dv\u0101pa\u015Bu\u015Bakti\u1E25","tags":"vim-1","date":"2021-02-11T00:00:00.000Z"},"headers":[{"level":2,"title":"\u041E\u043A\u043E\u043D\u0447\u0430\u043D\u0438\u0435 \u0413\u043B\u0430\u0432\u044B I","slug":"\u043E\u043A\u043E\u043D\u0447\u0430\u043D\u0438\u0435-\u0433n\u0430\u0432\u044B-i"}],"relativePath":"texts/shiva-sutra-vimarshini/1/16-22/index.md"}',i={},p=t('<div class="stanza"><a href="#s1.16" id="s1.16" class="num">1.16</a><div class="sans"><p>\u0905\u0924\u094D\u0930\u0948\u0935\u094B\u092A\u093E\u092F\u093E\u0928\u094D\u0924\u0930\u092E\u093E\u0939\u2014</p><blockquote><p><strong>\u0936\u0941\u0926\u094D\u0927\u0924\u0924\u094D\u0924\u094D\u0935\u0938\u0928\u094D\u0927\u093E\u0928\u093E\u0926\u094D\u0935\u093E\u092A\u0936\u0941\u0936\u0915\u094D\u0924\u093F\u0903\u0965\u0967\u096C</strong></p></blockquote><p>\u0936\u0941\u0926\u094D\u0927\u0902 \u0924\u0924\u094D\u0924\u094D\u0935\u0902 \u092A\u0930\u092E\u0936\u093F\u0935\u093E\u0916\u094D\u092F\u0902 \u0924\u0924\u094D\u0930 \u092F\u0926\u093E \u0935\u093F\u0936\u094D\u0935\u092E\u0928\u0941\u0938\u0928\u094D\u0927\u0924\u094D\u0924\u0947 \u0924\u0928\u094D\u092E\u092F\u092E\u0947\u0935\u0948\u0924\u0926\u093F\u0924\u093F \u0924\u0926\u093E\u0935\u093F\u0926\u094D\u092F\u092E\u093E\u0928\u093E \u092A\u0936\u094D\u0935\u093E\u0916\u094D\u092F\u093E \u092C\u0928\u094D\u0927\u0936\u0915\u094D\u0924\u093F\u0930\u094D\u092F\u0938\u094D\u092F \u0924\u093E\u0926\u0943\u0917\u092F\u0902 \u0938\u0926\u093E\u0936\u093F\u0935\u0935\u0926\u094D\u0935\u093F\u0936\u094D\u0935\u0938\u094D\u092F \u091C\u0917\u0924\u0903 \u092A\u0924\u093F\u0930\u094D\u092D\u0935\u0924\u093F\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u092E\u0932\u094D\u0932\u0915\u094D\u0937\u094D\u092E\u0940\u0915\u094C\u0932\u093E\u0930\u094D\u0923\u0935\u0947</p><blockquote><p>\u0926\u0940\u0915\u094D\u0937\u093E\u0938\u093F\u0926\u094D\u0927\u094C \u0924\u0941 \u092F\u0947 \u092A\u094D\u0930\u094B\u0915\u094D\u0924\u093E\u0903 \u092A\u094D\u0930\u0924\u094D\u092F\u092F\u093E\u0903 \u0938\u094D\u0924\u094B\u092D\u092A\u0942\u0930\u094D\u0935\u0915\u093E\u0903 \u0938\u0928\u094D\u0927\u093E\u0928\u0938\u094D\u092F\u0948\u0935 \u0924\u0947 \u0926\u0947\u0935\u093F \u0915\u0932\u093E\u0902 \u0928\u093E\u0930\u094D\u0939\u0928\u094D\u0924\u093F \u0937\u094B\u0921\u0936\u0940\u092E\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092D\u0948\u0930\u0935\u0947 \u0924\u0941</p><blockquote><p>\u0938\u0930\u094D\u0935\u0902 \u0926\u0947\u0939\u0902 \u091A\u093F\u0928\u094D\u092E\u092F\u0902 \u0939\u093F \u091C\u0917\u0926\u094D\u0935\u093E \u092A\u0930\u093F\u092D\u093E\u0935\u092F\u0947\u0924\u094D \u092F\u0941\u0917\u092A\u0928\u094D\u0928\u093F\u0930\u094D\u0935\u093F\u0915\u0932\u094D\u092A\u0947\u0928 \u092E\u0928\u0938\u093E \u092A\u0930\u092E\u094B\u0926\u094D\u092D\u0935\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0924\u0926\u0947\u0924\u0924\u094D</p><blockquote><p>\u0907\u0924\u093F \u0935\u093E \u092F\u0938\u094D\u092F \u0938\u0902\u0935\u093F\u0924\u094D\u0924\u093F\u0903 \u0915\u094D\u0930\u0940\u0921\u093E\u0924\u094D\u0935\u0947\u0928\u093E\u0916\u093F\u0932\u0902 \u091C\u0917\u0924\u094D \u0938 \u092A\u0936\u094D\u092F\u0928\u094D\u0938\u0924\u0924\u0902 \u092F\u0941\u0915\u094D\u0924\u094B \u091C\u0940\u0935\u0928\u094D\u092E\u0941\u0915\u094D\u0924\u094B \u0928 \u0938\u0902\u0936\u092F\u0903</p></blockquote><p>\u0907\u0924\u093F \u0915\u093E\u0930\u093F\u0915\u092F\u093E \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u094D\u0965\u0967\u096C\u0965</p></div><hr><div class="trans"><p>Atraivop\u0101y\u0101ntaram\u0101ha\u2014</p><blockquote><p><strong>\u015Auddhatattvasandh\u0101n\u0101dv\u0101pa\u015Bu\u015Bakti\u1E25||16||</strong></p></blockquote><p>\u015Auddha\u1E41 tattva\u1E41 parama\u015Biv\u0101khya\u1E41 tatra yad\u0101 vi\u015Bvamanusandhatte tanmayamevaitaditi tad\u0101vidyam\u0101n\u0101 pa\u015Bv\u0101khy\u0101 bandha\u015Baktiryasya t\u0101d\u1E5Bgaya\u1E41 sad\u0101\u015Bivavadvi\u015Bvasya jagata\u1E25 patirbhavati| Tadukta\u1E41 \u015Br\u012Bmallak\u1E63m\u012Bkaul\u0101r\u1E47ave</p><blockquote><p>D\u012Bk\u1E63\u0101siddhau tu ye prokt\u0101\u1E25 pratyay\u0101\u1E25 stobhap\u016Brvak\u0101\u1E25 Sandh\u0101nasyaiva te devi kal\u0101\u1E41 n\u0101rhanti \u1E63o\u1E0Da\u015B\u012Bm||</p></blockquote><p>iti| \u015Ar\u012Bvij\xF1\u0101nabhairave tu</p><blockquote><p>Sarva\u1E41 deha\u1E41 cinmaya\u1E41 hi jagadv\u0101 paribh\u0101vayet Yugapannirvikalpena manas\u0101 paramodbhava\u1E25||</p></blockquote><p>iti| Tadetat</p><blockquote><p>Iti v\u0101 yasya sa\u1E41vitti\u1E25 kr\u012B\u1E0D\u0101tven\u0101khila\u1E41 jagat Sa pa\u015Byansatata\u1E41 yukto j\u012Bvanmukto na sa\u1E41\u015Baya\u1E25||</p></blockquote><p>iti k\u0101rikay\u0101 sa\u1E45g\u1E5Bh\u012Btam||16||</p></div><hr><p>\u0417\u0434\u0435\u0441\u044C <em>(atra eva)</em>, \u041E\u043D --\u0442.\u0435. \u015Aiva, \u0430\u0432\u0442\u043E\u0440 \u015Aivas\u016Btra-s-- \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u043B <em>(\u0101ha)</em> \u0434\u0440\u0443\u0433\u0438\u0435 <em>(antaram)</em> \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430 <em>(up\u0101ya)</em> [\u0434\u043B\u044F \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0441\u0432\u043E\u0435\u0439 \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0441 \u0432\u044B\u0441\u0448\u0438\u043C Bhairava]\u2014</p><blockquote><p><strong>\u0418\u043B\u0438 <em>(v\u0101)</em> \u0447\u0435\u0440\u0435\u0437 \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 <em>(sandh\u0101n\u0101t)</em> \u0441 \u0427\u0438\u0441\u0442\u044B\u043C <em>(\u015Buddha)</em> \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u043C <em>(tattva)</em>, [Yog\u012B \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0442\u0435\u043C, \u0432 \u043A\u043E\u043C \u0441\u043A\u043E\u0432\u044B\u0432\u0430\u044E\u0449\u0430\u044F] \u0441\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em>, [\u043F\u0440\u0438\u0441\u0443\u0449\u0430\u044F] \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u043C\u0443 \u0438 \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u043E\u043C\u0443 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443 <em>(pa\u015Bu)</em>, \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 <em>(a)</em>||16||</strong></p></blockquote><p>\u0427\u0438\u0441\u0442\u044B\u0439 <em>(\u015Buddham)</em> \u041F\u0440\u0438\u043D\u0446\u0438\u043F <em>(tattvam)</em> \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(\u0101khyam)</em> Parama\u015Biva --\u0412\u044B\u0441\u0448\u0438\u0439 \u015Aiva-- <em>(parama\u015Biva)</em>. \u041A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> [ Yog\u012B] \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0432 \u044D\u0442\u043E\u043C [Parama\u015Biva] --\u0442.\u0435. \u043A\u043E\u0433\u0434\u0430 Yog\u012B \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 \u0415\u0433\u043E-- <em>(tatra)</em>, \u043E\u043D \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0441\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u043C <em>(anusandhatte)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E <em>(vi\u015Bvam)</em> [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C:] &quot;\u042D\u0442\u0430 [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F] <em>(etad)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0439 <em>(mayam eva)</em> \u0438\u0437 \u044D\u0442\u043E\u0439 [\u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438] <em>(tad... iti)</em>&quot;; \u0437\u0430\u0442\u0435\u043C <em>(tad\u0101)</em>, \u0442\u0430\u043A\u0438\u043C \u0436\u0435 \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(t\u0101d\u1E5Bk)</em>, \u044D\u0442\u043E\u0442 [Yog\u012B] <em>(ayam)</em> \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(bhavati)</em> \u0432\u043B\u0430\u0434\u044B\u043A\u043E\u0439 <em>(pati\u1E25)</em> \u0432\u0441\u0435\u0433\u043E <em>(vi\u015Bvasya)</em> \u043C\u0438\u0440\u0430 <em>(jagata\u1E25)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u043E <em>(vat)</em> Sad\u0101\u015Biva <em>(sad\u0101\u015Biva)</em>, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C <em>(yasya)</em> \u0441\u043A\u043E\u0432\u044B\u0432\u0430\u044E\u0449\u0430\u044F <em>(bandha)</em> \u0441\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em>, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430\u044F \u043A\u0430\u043A <em>(\u0101khy\u0101)</em> \u043F\u0430\u0448\u0443 <em>(pa\u015Bu)</em>, \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 <em>(avidyam\u0101n\u0101)</em>.|</p><p>\u042D\u0442\u0430 [\u0438\u0441\u0442\u0438\u043D\u0430] <em>(tad)</em> \u0431\u044B\u043B\u0430 [\u0442\u0430\u043A\u0436\u0435] \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0430 <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u0439 <em>(\u015Br\u012Bmad)</em> Lak\u1E63m\u012Bkaul\u0101r\u1E47ava <em>(lak\u1E63m\u012Bkaul\u0101r\u1E47ave)</em>:</p><blockquote><p>&quot;\u0422\u0435 pratyaya-s <em>(pratyay\u0101\u1E25)</em>, \u0441\u043E\u043F\u0440\u043E\u0432\u043E\u0436\u0434\u0430\u0435\u043C\u044B\u0435 <em>(p\u016Brvak\u0101\u1E25)</em> \u0432\u043E\u0441\u043A\u043B\u0438\u0446\u0430\u043D\u0438\u044F\u043C\u0438 \u043F\u043E\u0445\u0432\u0430\u043B\u044B <em>(stobha)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 <em>(ye)</em> \u0431\u044B\u043B\u0438 \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u044B, \u0438\u043B\u0438 \u043F\u0440\u0435\u043F\u043E\u0434\u0430\u043D\u044B <em>(prokt\u0101\u1E25)</em> \u0434\u043B\u044F \u0443\u0441\u043F\u0435\u0445\u0430 <em>(siddhau tu)</em> \u0438\u043D\u0438\u0446\u0438\u0430\u0446\u0438\u0438 <em>(d\u012Bk\u1E63\u0101)</em>, \u043D\u0435 \u0437\u0430\u0441\u043B\u0443\u0436\u0438\u0432\u0430\u044E\u0442 [\u0434\u0430\u0436\u0435] <em>(na arhanti)</em> \u0448\u0435\u0441\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u043E\u0439 <em>(\u1E63o\u1E0Da\u015B\u012Bm)</em> \u0447\u0430\u0441\u0442\u0438 <em>(kal\u0101m)</em> Sandh\u0101na <em>(sandh\u0101nasya eva)</em>, \u041E \u0411\u043E\u0433\u0438\u043D\u044F <em>(devi... iti)</em>&quot;<sup>2</sup>||</p></blockquote><p>[\u0418] \u0432 \u043C\u043D\u043E\u0433\u043E\u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u0439 <em>(\u015Br\u012B)</em> Vij\xF1\u0101nabhairava <em>(vij\xF1\u0101nabhairave tu)</em>:</p><blockquote><p>&quot;\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0442\u044C <em>(paribh\u0101vayet)</em> \u0441 \u0443\u043C\u043E\u043C <em>(manas\u0101)</em>, \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u043C \u043E\u0442 \u043C\u044B\u0441\u043B\u0435\u0439 <em>(nirvikalpena)</em>, \u0432\u0441\u0435 [\u0435\u0433\u043E] <em>(sarvam)</em> \u0442\u0435\u043B\u043E <em>(deham)</em>, \u0438\u043B\u0438 <em>(v\u0101)</em> \u043C\u0438\u0440 <em>(jagat)</em> \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E --\u0442.\u0435. \u043D\u0435 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E-- <em>(yugapad)</em>, \u043A\u0430\u043A \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0438\u0439 \u0438\u0437 <em>(mayam hi)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em>; [\u0435\u0441\u043B\u0438 \u043E\u043D \u0441\u0434\u0435\u043B\u0430\u0435\u0442 \u0442\u0430\u043A, ] \u0442\u043E \u044F\u0432\u0438\u0442\u0441\u044F <em>(udbhava\u1E25)</em> \u0412\u044B\u0441\u0448\u0430\u044F [\u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C] <em>(parama... iti)</em> [\u0435\u043C\u0443]&quot;<sup>3</sup>|</p></blockquote><p>\u0422\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u043E\u0435 \u0436\u0435 [\u0443\u0447\u0435\u043D\u0438\u0435] <em>(tad etad)</em> \u0431\u044B\u043B\u043E \u043E\u0431\u043E\u0431\u0449\u0435\u043D\u043E <em>(sa\u1E45g\u1E5Bh\u012Btam)</em> \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u043C <em>(k\u0101rikay\u0101)</em> [\u0438\u0437 Spandak\u0101rik\u0101-s]:</p><blockquote><p>&quot;\u0418\u043B\u0438 <em>(iti v\u0101)</em> \u043E\u043D <em>(sa\u1E25)</em>, \u043A\u0442\u043E \u0438\u043C\u0435\u0435\u0442 \u044D\u0442\u043E <em>(yasya)</em> \u0437\u043D\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044E <em>(sa\u1E41vitti\u1E25)</em><sup>4</sup> [\u0438] \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E <em>(satatam)</em> \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 [\u0441 \u0412\u044B\u0441\u0448\u0438\u043C \u042F] <em>(yukta\u1E25)</em>, \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442 <em>(pa\u015Byan)</em> \u0432\u0435\u0441\u044C <em>(akhilam)</em> \u043C\u0438\u0440 <em>(jagat)</em> \u043A\u0430\u043A [\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E] \u0438\u0433\u0440\u0443 <em>(kr\u012B\u1E0D\u0101tvena)</em>. \u041E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C \u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438 <em>(j\u012Bvanmukta\u1E25)</em>, \u043D\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u0438\u0445 <em>(na)</em> \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0439 <em>(sa\u1E41\u015Baya\u1E25... iti)</em> [\u0432 \u044D\u0442\u043E\u043C]&quot;| [\u0421\u043C. Spandak\u0101rik\u0101-s II, 5]</p></blockquote><p>||16||</p><hr><ol><li><p>\u0422\u0435\u0440\u043C\u0438\u043D &quot;pratyaya-s&quot; \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u0435\u0440\u0435\u0432\u0435\u0434\u0435\u043D \u043E\u0433\u0440\u043E\u043C\u043D\u044B\u043C \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E\u043C \u0441\u043F\u043E\u0441\u043E\u0431\u043E\u0432: &quot;\u0438\u0434\u0435\u0438, \u0440\u0435\u043B\u0438\u0433\u0438\u043E\u0437\u043D\u044B\u0435 \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438, \u0438 \u0442.\u0434&quot;, \u043D\u043E \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u044D\u0442\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0926\u0947\u0936\u093E\u0926\u093F\u0935\u094D\u092F\u0935\u0939\u093F\u0924\u0935\u093F\u092A\u094D\u0930\u0915\u0943\u0937\u094D\u091F\u0935\u0938\u094D\u0924\u0941\u091C\u094D\u091E\u093E\u0928\u093E\u0928\u093F&quot; - &quot;de\u015B\u0101divyavahitaviprak\u1E5B\u1E63\u1E6Davastuj\xF1\u0101n\u0101ni&quot;, \u0438\u043B\u0438 &quot;\u0437\u043D\u0430\u043D\u0438\u044F \u043E\u0431 \u0443\u0434\u0430\u043B\u0435\u043D\u043D\u044B\u0445 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044F\u0445, \u043E\u0442\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0445 (\u043E\u0442 \u0441\u0435\u0431\u044F) \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E\u043C, \u0438 \u0442.\u0434.&quot; (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u043E\u0442\u0434\u0430\u043B\u0435\u043D\u043D\u044B\u0435 \u043C\u0438\u0440\u044B). \u0412\u043E \u0432\u0440\u0435\u043C\u044F \u043E\u0431\u0440\u044F\u0434\u0430 \u043F\u043E\u0441\u0432\u044F\u0449\u0435\u043D\u0438\u044F \u0438\u043D\u0438\u0446\u0438\u0438\u0440\u0443\u0435\u043C\u044B\u0439 \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 \u044D\u0442\u0438 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u041C\u0438\u043B\u043E\u0441\u0442\u0438 \u0413\u043E\u0441\u043F\u043E\u0434\u0430, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0439\u0441\u044F \u043A\u0430\u043A \u0441\u0430\u043C \u0440\u0438\u0442\u0443\u0430\u043B. \u041E\u0431\u044B\u0447\u043D\u043E \u043F\u0440\u0438\u043D\u044F\u0442\u043E \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u0442\u044C \u0432\u043E\u0441\u043A\u043B\u0438\u0446\u0430\u043D\u0438\u044F \u043F\u043E\u0445\u0432\u0430\u043B\u044B (\u0441\u043A\u0430\u043D\u0434\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043C\u0435\u0436\u0434\u043E\u043C\u0435\u0442\u0438\u044F) \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u0438\u043D\u0438\u0446\u0438\u0430\u0446\u0438\u0438. \u0412 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C, \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u015Aiva \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u0411\u043E\u0433\u0438\u043D\u0435, \u0447\u0442\u043E \u044D\u0442\u043E \u043D\u0435 \u0441\u0442\u043E\u0438\u0442 \u0434\u0430\u0436\u0435 \u0448\u0435\u0441\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u043E\u0439 \u0447\u0430\u0441\u0442\u0438 Sandh\u0101na. \u0418 \u0447\u0442\u043E \u044D\u0442\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442? Sandh\u0101na \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u0430 \u043A\u0430\u043A &quot;\u0936\u0941\u0926\u094D\u0927\u0924\u0924\u094D\u0924\u094D\u0935\u0935\u093F\u092E\u0930\u094D\u0936&quot; - &quot;\u015Buddhatattvavimar\u015Ba&quot;, \u0438\u043B\u0438 &quot;\u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0430&quot;. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u0435 \u0413\u043E\u0441\u043F\u043E\u0434\u0430 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0432 \u0442\u043E\u043C, \u0447\u0442\u043E \u0432\u0441\u0435 \u044D\u0442\u0438 \u0432\u0435\u0449\u0438 \u043D\u0435\u0437\u043D\u0430\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u044B \u043F\u043E \u0441\u0440\u0430\u0432\u043D\u0435\u043D\u0438\u044E \u0441 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0430. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0441\u0430\u043C\u0430 \u0411\u043E\u0433\u0438\u043D\u044F \u0438 \u0435\u0441\u0442\u044C \u044D\u0442\u0430 &quot;vimar\u015Ba&quot;, \u0438\u043B\u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u044C, \u0442\u0430\u043A\u0430\u044F Sandh\u0101na \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u0430 \u0442\u043E\u043B\u044C\u043A\u043E \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0415\u0439. \u041F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 \u041E\u043D\u0430 \u0434\u043E\u043B\u0436\u043D\u0430 \u0431\u044B\u0442\u044C \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 \u043A\u0430\u043A \u043C\u043E\u0441\u0442, \u0432\u0435\u0434\u0443\u0449\u0438\u0439 \u043A \u0427\u0438\u0441\u0442\u043E\u043C\u0443 \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0443 (Parama\u015Biva). \u041D\u0443, \u044D\u0442\u043E \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0435 \u0434\u0430\u043B\u043E \u043B\u0438\u0448\u044C \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435!</p></li><li><p>\u0412 \u0432\u0435\u0440\u0441\u0438\u0438 Vij\xF1\u0101nabhairava, \u043F\u0440\u043E\u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0439 \u0441\u0430\u043C\u0438\u043C K\u1E63emar\u0101ja, \u0442\u0435\u0440\u043C\u0438\u043D &quot;paramodbhava\u1E25&quot; (parama-udbhava\u1E25) \u043C\u0435\u043D\u044F\u0435\u0442\u0441\u044F \u043D\u0430 &quot;\u092A\u0930\u092E\u094B\u0926\u092F\u0903&quot; - &quot;paramodaya\u1E25&quot; (parama-udaya\u1E25), \u043D\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u043F\u0440\u0435\u0436\u043D\u0438\u043C, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 &quot;udbhava\u1E25&quot; \u0438 &quot;udaya\u1E25&quot; \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0441\u0438\u043D\u043E\u043D\u0438\u043C\u0430\u043C\u0438.</p></li><li><p>\u0417\u043D\u0430\u043D\u0438\u0435 \u043E \u0447\u0435\u043C? \u0427\u0442\u043E\u0431\u044B \u043F\u043E\u043D\u044F\u0442\u044C \u044D\u0442\u043E, \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u043F\u0440\u043E\u0447\u0438\u0442\u0430\u0442\u044C \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u044E\u044E \u0447\u0430\u0441\u0442\u044C \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0435\u0433\u043E \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 \u0432 Spandak\u0101rik\u0101-s. \u0412 \u043A\u043E\u043D\u0446\u0435 \u0435\u0433\u043E (II,4) \u0430\u0432\u0442\u043E\u0440 \u0433\u043E\u0432\u043E\u0440\u0438\u0442: &quot;\u0421\u0430\u043C \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u0430\u0442\u043E\u0440 \u0432\u0441\u0435\u0433\u0434\u0430 \u0438 \u0432\u0435\u0437\u0434\u0435 \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0438\u0441\u043F\u044B\u0442\u0443\u0435\u043C\u043E\u0433\u043E&quot;. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u044D\u0442\u043E \u0442\u043E\u0442 \u0432\u0438\u0434 \u0437\u043D\u0430\u043D\u0438\u0439, \u043E \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u0430\u0432\u0442\u043E\u0440 Spandak\u0101rik\u0101-s \u0432 II, 5 (\u0442.\u0435.\u0432 5<sup>\u043C</sup> \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 \u0420\u0430\u0437\u0434\u0435\u043B\u0430 II). \u0422\u0435\u043F\u0435\u0440\u044C \u0441\u043C\u044B\u0441\u043B \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u0440\u043E\u044F\u0441\u043D\u0435\u043D!</p></li></ol></div><div class="stanza"><a href="#s1.17" id="s1.17" class="num">1.17</a><div class="sans"><p>\u0908\u0926\u0943\u0917\u094D\u091C\u094D\u091E\u093E\u0928\u0930\u0942\u092A\u0938\u094D\u092F\u093E\u0938\u094D\u092F \u092F\u094B\u0917\u093F\u0928\u0903\u2014</p><blockquote><p><strong>\u0935\u093F\u0924\u0930\u094D\u0915 \u0906\u0924\u094D\u092E\u091C\u094D\u091E\u093E\u0928\u092E\u094D\u0965\u0967\u096D</strong></p></blockquote><p>\u0935\u093F\u0936\u094D\u0935\u093E\u0924\u094D\u092E\u093E \u0936\u093F\u0935 \u090F\u0935\u093E\u0938\u094D\u092E\u0940\u0924\u093F \u092F\u094B \u0935\u093F\u0924\u0930\u094D\u0915\u094B \u0935\u093F\u091A\u093E\u0930 \u090F\u0924\u0926\u0947\u0935\u093E\u0938\u094D\u092F\u093E\u0924\u094D\u092E\u091C\u094D\u091E\u093E\u0928\u092E\u094D\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092D\u0948\u0930\u0935\u0947</p><blockquote><p>\u0938\u0930\u094D\u0935\u091C\u094D\u091E\u0903 \u0938\u0930\u094D\u0935\u0915\u0930\u094D\u0924\u093E \u091A \u0935\u094D\u092F\u093E\u092A\u0915\u0903 \u092A\u0930\u092E\u0947\u0936\u094D\u0935\u0930\u0903 \u0938 \u090F\u0935\u093E\u0939\u0902 \u0936\u0948\u0935\u0927\u0930\u094D\u092E\u0947\u0924\u093F \u0926\u093E\u0930\u094D\u0922\u094D\u092F\u093E\u091A\u094D\u091B\u093F\u0935\u094B \u092D\u0935\u0947\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0938\u094D\u092A\u0928\u094D\u0926\u0947\u093D\u092A\u093F</p><blockquote><p>... \u0905\u092F\u092E\u0947\u0935\u093E\u0924\u094D\u092E\u0928\u094B \u0917\u094D\u0930\u0939\u0903\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928\u0948\u0924\u0926\u0941\u0915\u094D\u0924\u092E\u094D\u0964 \u0924\u0924\u094D\u0930 \u0939\u094D\u092F\u093E\u0924\u094D\u092E\u0928\u094B \u0917\u094D\u0930\u0939\u0923\u0902 \u0917\u094D\u0930\u0939\u094B \u091C\u094D\u091E\u093E\u0928\u092E\u0947\u0924\u0926\u0947\u0935 \u092F\u0926\u094D\u0935\u093F\u0936\u094D\u0935\u093E\u0924\u094D\u092E\u0915\u0936\u093F\u0935\u093E\u092D\u093F\u0928\u094D\u0928\u0924\u094D\u0935\u092E\u0947\u0937\u094B\u093D\u092A\u094D\u092F\u0930\u094D\u0925\u094B \u0935\u093F\u0935\u0915\u094D\u0937\u093F\u0924\u0903\u0965\u0967\u096D\u0965</p></div><hr><div class="trans"><p>\u012Ad\u1E5Bgj\xF1\u0101nar\u016Bpasy\u0101sya yogina\u1E25\u2014</p><blockquote><p><strong>Vitarka \u0101tmaj\xF1\u0101nam||17||</strong></p></blockquote><p>Vi\u015Bv\u0101tm\u0101 \u015Biva ev\u0101sm\u012Bti yo vitarko vic\u0101ra etadev\u0101sy\u0101tmaj\xF1\u0101nam| Tadukta\u1E41 \u015Br\u012Bvij\xF1\u0101nabhairave</p><blockquote><p>Sarvaj\xF1a\u1E25 sarvakart\u0101 ca vy\u0101paka\u1E25 parame\u015Bvara\u1E25 Sa ev\u0101ha\u1E41 \u015Baivadharmeti d\u0101r\u1E0Dhy\u0101cchivo bhavet||</p></blockquote><p>iti| Spande&#39;pi</p><blockquote><p>... ayamev\u0101tmano graha\u1E25|</p></blockquote><p>ityanenaitaduktam| Tatra hy\u0101tmano graha\u1E47a\u1E41 graho j\xF1\u0101nametadeva yadvi\u015Bv\u0101tmaka\u015Biv\u0101bhinnatvame\u1E63o&#39;pyartho vivak\u1E63ita\u1E25||17||</p></div><hr><p>\u041A\u0430\u0441\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u044D\u0442\u043E\u0433\u043E <em>(asya)</em> Yog\u012B <em>(yogina\u1E25)</em>, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(r\u016Bpasya)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0442\u0430\u043A\u043E\u0435 <em>(\u012Bd\u1E5Bk)</em> \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101na)</em><sup>1</sup>\u2014</p><blockquote><p><strong>\u0422\u0432\u0435\u0440\u0434\u043E\u0435 \u0438 \u043D\u0435\u043F\u043E\u043A\u043E\u043B\u0435\u0431\u0438\u043C\u043E\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(vitarka\u1E25)</em>, [\u0447\u0442\u043E \u042F \u0435\u0441\u0442\u044C \u015Aiva, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(j\xF1\u0101nam)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F <em>(\u0101tma)</em>||17||</strong></p></blockquote><p>\u042D\u0442\u043E\u0442 <em>(etad eva)</em> vitarka <em>(vitarka\u1E25)</em>, [\u0438\u043B\u0438] \u0442\u0432\u0435\u0440\u0434\u043E\u0435 \u0438 \u043D\u0435\u043F\u043E\u043A\u043E\u043B\u0435\u0431\u0438\u043C\u043E\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(vic\u0101ra\u1E25)</em>, \u0447\u0442\u043E <em>(ya\u1E25)</em> &quot;\u042F \u0435\u0441\u0442\u044C <em>(asmi)</em> \u015Aiva <em>(\u015Biva\u1E25 eva)</em>, \u0412\u044B\u0441\u0448\u0435\u0435 \u042F <em>(\u0101tm\u0101)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva... iti)</em>&quot; [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0435\u0433\u043E --Yog\u012B-- <em>(asya)</em> \u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(j\xF1\u0101nam)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F <em>(\u0101tma)</em>|</p><p>\u042D\u0442\u043E \u0436\u0435 <em>(tad)</em> \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u0439 <em>(\u015Br\u012B)</em> Vij\xF1\u0101nabhairava <em>(vij\xF1\u0101nabhairave)</em> [\u0442\u0430\u043A\u0436\u0435]:</p><blockquote><p>&quot;&#39;\u0412\u044B\u0441\u0448\u0438\u0439 <em>(parama)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u044C <em>(\u012B\u015Bvara\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0432\u0441\u0435\u0437\u043D\u0430\u044E\u0449\u0438\u043C <em>(sarvaj\xF1a\u1E25)</em>, \u0432\u0441\u0435\u043C\u043E\u0433\u0443\u0449\u0438\u043C <em>(sarvakart\u0101)</em> \u0438 <em>(ca)</em> \u0432\u0435\u0437\u0434\u0435\u0441\u0443\u0449\u0438\u043C <em>(vy\u0101paka\u1E25)</em>. \u041E\u043D <em>(sa\u1E25 eva)</em> [\u2014 \u044D\u0442\u043E] \u044F \u0441\u0430\u043C <em>(aham)</em>, [\u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443] \u044F \u043E\u0431\u043B\u0430\u0434\u0430\u044E \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430\u043C\u0438 <em>(dharm\u0101)</em> \u0428\u0438\u0432\u044B <em>(\u015Baiva... iti)</em>&#39;. \u0421 \u044D\u0442\u043E\u0439 \u0442\u0432\u0435\u0440\u0434\u043E\u0439 [\u0443\u0431\u0435\u0436\u0434\u0435\u043D\u043D\u043E\u0441\u0442\u044C\u044E] <em>(d\u0101r\u1E0Dhy\u0101t)</em> \u043E\u043D \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(bhavet)</em> \u0428\u0438\u0432\u043E\u0439 <em>(\u015Biva\u1E25)</em>&quot;||</p></blockquote><p>\u0412 Spandak\u0101rik\u0101-s <em>(spande)</em> \u0442\u0430\u043A\u0436\u0435 <em>(api)</em>, \u044D\u0442\u043E [\u0436\u0435 \u0441\u0430\u043C\u043E\u0435 \u0443\u0447\u0435\u043D\u0438\u0435] <em>(etad)</em> \u0431\u044B\u043B\u043E \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E <em>(uktam)</em> \u0432 \u044D\u0442\u043E\u0439 [\u0447\u0430\u0441\u0442\u0438 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430] <em>(anena)</em>:</p><blockquote><p>&quot;... \u0442\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u044D\u0442\u043E <em>(ayam)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435\u043C <em>(graha\u1E25)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F <em>(\u0101tmana\u1E25... iti)</em>&quot;| [\u0421\u043C. Spandak\u0101rik\u0101-s II, 7]</p></blockquote><p>\u0412 \u044D\u0442\u043E\u0439 [\u0447\u0430\u0441\u0442\u0438 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430] <em>(tatra hi)</em>, \u044D\u0442\u043E <em>(etad)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 <em>(graha\u1E25)</em>, [\u0438\u043B\u0438] \u0443\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u043D\u0438\u0435 <em>(graha\u1E47am)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F <em>(\u0101tmana\u1E25)</em>, [\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F, \u0442\u043E\u043B\u044C\u043A\u043E \u0438 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] <em>(eva)</em> \u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(j\xF1\u0101nam)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F <em>(\u0101tmana\u1E25)</em>. \u042D\u0442\u043E <em>(yad)</em> [\u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u043E\u0431 ] \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0438 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0439, \u0438\u043B\u0438 \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435 <em>(abhinnatvam)</em> \u043F\u043E \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044E \u043A \u015Aiva <em>(\u015Biva)</em> \u2014\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 <em>(\u0101tmaka)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em>\u2014... [\u0447\u0442\u043E \u0436,] \u044D\u0442\u043E\u0442 <em>(e\u1E63a\u1E25)</em> [\u0434\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439] \u0441\u043C\u044B\u0441\u043B <em>(artha\u1E25)</em> \u0442\u0430\u043A\u0436\u0435 \u043F\u0440\u0435\u0434\u043F\u043E\u043B\u0430\u0433\u0430\u0435\u0442\u0441\u044F \u0432\u044B\u0440\u0430\u0437\u0438\u0442\u044C <em>(api... vivak\u1E63ita\u1E25)</em> [\u0447\u0435\u0440\u0435\u0437 \u044D\u0442\u043E \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u0435 \u0432 Spandak\u0101rik\u0101-s]<sup>2</sup>||17||</p><ol><li><p>\u0427\u0438\u0442\u0430\u0439\u0442\u0435 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u044E\u044E \u0447\u0430\u0441\u0442\u044C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F \u043D\u0430 \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0438\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043D\u044F\u0442\u044C \u043B\u0443\u0447\u0448\u0435 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0432\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u043A 17<sup>\u043E\u043C\u0443</sup> \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0443.</p></li><li><p>\u041E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u0447\u0442\u043E \u0442\u043E, \u0447\u0442\u043E \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043C\u0435\u0436\u0434\u0443 \u0434\u043B\u0438\u043D\u043D\u044B\u043C\u0438 \u0434\u0435\u0444\u0438\u0441\u0430\u043C\u0438 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A \u015Aiva. \u0414\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435, \u0447\u0442\u043E \u0432\u044B \u043D\u0435 \u043E\u0442\u043B\u0438\u0447\u043D\u044B \u043E\u0442 \u0413\u043E\u0441\u043F\u043E\u0434\u0430, \u0441\u043A\u0440\u044B\u0442\u043E \u0432\u043E \u0444\u0440\u0430\u0437\u0435 &quot;\u0442\u043E\u043B\u044C\u043A\u043E \u044D\u0442\u043E [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435\u043C \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F&quot;, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E K\u1E63emar\u0101ja.</p></li></ol></div><div class="stanza"><a href="#s1.18" id="s1.18" class="num">1.18</a><div class="sans"><p>\u0915\u093F\u091E\u094D\u091A\u093E\u0938\u094D\u092F\u2014</p><blockquote><p><strong>\u0932\u094B\u0915\u093E\u0928\u0928\u094D\u0926\u0903 \u0938\u092E\u093E\u0927\u093F\u0938\u0941\u0916\u092E\u094D\u0965\u0967\u096E</strong></p></blockquote><p>\u0932\u094B\u0915\u094D\u092F\u0924 \u0907\u0924\u093F \u0932\u094B\u0915\u094B \u0935\u0938\u094D\u0924\u0941\u0917\u094D\u0930\u093E\u092E\u094B \u0932\u094B\u0915\u092F\u0924\u0940\u0924\u093F \u091A \u0932\u094B\u0915\u094B \u0917\u094D\u0930\u093E\u0939\u0915\u0935\u0930\u094D\u0917\u0938\u094D\u0924\u0938\u094D\u092E\u093F\u0928\u094D\u0938\u094D\u092B\u0941\u0930\u0924\u093F \u0938\u0924\u093F</p><blockquote><p>\u0917\u094D\u0930\u093E\u0939\u094D\u092F\u0917\u094D\u0930\u093E\u0939\u0915\u0938\u0902\u0935\u093F\u0924\u094D\u0924\u093F\u0903 \u0938\u093E\u092E\u093E\u0928\u094D\u092F\u093E \u0938\u0930\u094D\u0935\u0926\u0947\u0939\u093F\u0928\u093E\u092E\u094D \u092F\u094B\u0917\u093F\u0928\u093E\u0902 \u0924\u0941 \u0935\u093F\u0936\u0947\u0937\u094B\u093D\u092F\u0902 \u0938\u092E\u094D\u092C\u0928\u094D\u0927\u0947 \u0938\u093E\u0935\u0927\u093E\u0928\u0924\u093E\u0965</p></blockquote><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092D\u091F\u094D\u091F\u093E\u0930\u0915\u0928\u093F\u0930\u0942\u092A\u093F\u0924\u0928\u0940\u0924\u094D\u092F\u093E \u092A\u094D\u0930\u092E\u093E\u0924\u0943\u092A\u0926\u0935\u093F\u0936\u094D\u0930\u093E\u0928\u094D\u0924\u094D\u092F\u0935\u0927\u093E\u0928\u0924\u0936\u094D\u091A\u092E\u0924\u094D\u0915\u093E\u0930\u092E\u092F\u094B \u092F \u0906\u0928\u0928\u094D\u0926 \u090F\u0924\u0926\u0947\u0935\u093E\u0938\u094D\u092F \u0938\u092E\u093E\u0927\u093F\u0938\u0941\u0916\u092E\u094D\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0924\u0924\u094D\u0930\u0948\u0935</p><blockquote><p>\u0938\u0930\u094D\u0935\u0902 \u091C\u0917\u0924\u094D\u0938\u094D\u0935\u0926\u0947\u0939\u0902 \u0935\u093E \u0938\u094D\u0935\u093E\u0928\u0928\u094D\u0926\u092D\u0930\u093F\u0924\u0902 \u0938\u094D\u092E\u0930\u0947\u0924\u094D \u092F\u0941\u0917\u092A\u0924\u094D\u0938\u094D\u0935\u093E\u092E\u0943\u0924\u0947\u0928\u0948\u0935 \u092A\u0930\u093E\u0928\u0928\u094D\u0926\u092E\u092F\u094B \u092D\u0935\u0947\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u090F\u0924\u091A\u094D\u091A</p><blockquote><p>\u0907\u092F\u092E\u0947\u0935\u093E\u092E\u0943\u0924\u092A\u094D\u0930\u093E\u092A\u094D\u0924\u093F\u0903...\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928 \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u094D\u0964</p><p>\u0905\u0925 \u091A \u092F\u0926\u0938\u094D\u092F \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u093E\u0930\u093E\u092E\u0938\u094D\u092F \u0938\u092E\u093E\u0927\u093F\u0938\u0941\u0916\u0902 \u0924\u0926\u0947\u0935 \u0924\u0924\u094D\u0924\u093E\u0926\u0943\u0936\u092E\u0935\u0932\u094B\u0915\u092F\u0924\u093E\u0902 \u0932\u094B\u0915\u093E\u0928\u093E\u092E\u093E\u0928\u0928\u094D\u0926\u0938\u0919\u094D\u0915\u094D\u0930\u092E\u0923\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E \u0938\u094D\u0935\u093E\u0928\u0928\u094D\u0926\u093E\u092D\u093F\u0935\u094D\u092F\u0915\u094D\u0924\u093F\u092A\u0930\u094D\u092F\u0935\u0938\u093E\u092F\u093F \u092D\u0935\u0924\u093F\u0964 \u090F\u0924\u0926\u092A\u093F \u0936\u094D\u0930\u0940\u091A\u0928\u094D\u0926\u094D\u0930\u091C\u094D\u091E\u093E\u0928\u0917\u094D\u0930\u0928\u094D\u0925\u0947\u0928 \u092A\u094D\u0930\u093E\u0917\u0941\u0915\u094D\u0924\u0947\u0928 (\u0967-\u096D) \u0938\u0941\u0938\u0902\u0935\u093E\u0926\u092E\u094D\u0965\u0967\u096E\u0965</p></div><hr><div class="trans"><p>Ki\xF1c\u0101sya\u2014</p><blockquote><p><strong>Lok\u0101nanda\u1E25 sam\u0101dhisukham||18||</strong></p></blockquote><p>Lokyata iti loko vastugr\u0101mo lokayat\u012Bti ca loko gr\u0101hakavargastasminsphurati sati</p><blockquote><p>Gr\u0101hyagr\u0101hakasa\u1E41vitti\u1E25 s\u0101m\u0101ny\u0101 sarvadehin\u0101m Yogin\u0101\u1E41 tu vi\u015Be\u1E63o&#39;ya\u1E41 sambandhe s\u0101vadh\u0101nat\u0101||</p></blockquote><p>iti \u015Br\u012Bvij\xF1\u0101nabha\u1E6D\u1E6D\u0101rakanir\u016Bpitan\u012Bty\u0101 pram\u0101t\u1E5Bpadavi\u015Br\u0101ntyavadh\u0101nata\u015Bcamatk\u0101ramayo ya \u0101nanda etadev\u0101sya sam\u0101dhisukham| Tadukta\u1E41 tatraiva</p><blockquote><p>Sarva\u1E41 jagatsvadeha\u1E41 v\u0101 sv\u0101nandabharita\u1E41 smaret Yugapatsv\u0101m\u1E5Btenaiva par\u0101nandamayo bhavet||</p></blockquote><p>iti| Etacca</p><blockquote><p>Iyamev\u0101m\u1E5Btapr\u0101pti\u1E25...|</p></blockquote><p>ityanena sa\u1E45g\u1E5Bh\u012Btam|</p><p>Atha ca yadasya sv\u0101tm\u0101r\u0101masya sam\u0101dhisukha\u1E41 tadeva tatt\u0101d\u1E5B\u015Bamavalokayat\u0101\u1E41 lok\u0101n\u0101m\u0101nandasa\u1E45krama\u1E47ayukty\u0101 sv\u0101nand\u0101bhivyaktiparyavas\u0101yi bhavati| Etadapi \u015Br\u012Bcandraj\xF1\u0101nagranthena pr\u0101guktena (1- 7) susa\u1E41v\u0101dam||18||</p></div><hr><p>\u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E <em>(ki\xF1ca)</em>, \u0443 \u044D\u0442\u043E\u0433\u043E [Yog\u012B] <em>(asya)</em>\u2014</p><blockquote><p><strong>\u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E [\u043A\u043E\u0442\u043E\u0440\u043E\u0435 Yog\u012B \u043E\u0449\u0443\u0449\u0430\u0435\u0442, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u043A\u0430\u043A \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439, \u0438\u043B\u0438 \u0412\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439] <em>(\u0101nanda\u1E25)</em> \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u043C\u0438\u0440\u0430 [\u2014\u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u0438\u0437 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432\u2014] <em>(loka)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0435\u0433\u043E] \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435\u043C <em>(sukham)</em> Sam\u0101dhi <em>(sam\u0101dhi)</em>||18||</strong></p></blockquote><p>\u041B\u043E\u043A\u0430, \u0438\u043B\u0438 \u043C\u0438\u0440 <em>(loka\u1E25)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0438] &quot;\u0442\u043E, \u0447\u0442\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F <em>(lokyate iti)</em>&quot; \u2014\u0442.\u0435. \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E <em>(gr\u0101ma\u1E25)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 <em>(vastu)</em>\u2014, \u0438 <em>(ca)</em> &quot;\u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 <em>(lokayati iti)</em>&quot; \u2014\u0442.\u0435. \u0433\u0440\u0443\u043F\u043F\u0443, \u0438\u043B\u0438 \u0442\u0438\u043F <em>(varga\u1E25)</em> \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u0432 <em>(gr\u0101haka)</em>\u2014. \u0425\u043E\u0442\u044F \u044D\u0442\u043E \u043E\u0447\u0435\u0432\u0438\u0434\u043D\u043E <em>(tasmin sphurati sati)</em><sup>1</sup> [\u043A\u0430\u0436\u0434\u043E\u043C\u0443], \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044E <em>(n\u012Bty\u0101)</em>, \u0441\u0444\u043E\u0440\u043C\u0443\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u043C\u0443 <em>(nir\u016Bpita)</em> \u0432 \u043C\u043D\u043E\u0433\u043E\u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u0439 <em>(\u015Br\u012B)</em> Vij\xF1\u0101nabhairava <em>(vij\xF1\u0101na-bha\u1E6D\u1E6D\u0101raka)</em>:</p><blockquote><p>&quot;\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(sa\u1E41vitti\u1E25)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 <em>(gr\u0101hya)</em> [\u0438] \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u0432 <em>(gr\u0101haka)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0431\u0449\u0438\u043C <em>(s\u0101m\u0101ny\u0101)</em> \u0434\u043B\u044F \u0432\u0441\u0435\u0445 \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u043D\u044B\u0445 <em>(sarva-dehin\u0101m)</em>; \u043D\u043E <em>(tu)</em> \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 Yog\u012B-s <em>(yogin\u0101m)</em> \u044D\u0442\u043E <em>(ayam)</em> [\u0438\u043C\u0435\u0435\u0442] \u043E\u0442\u043B\u0438\u0447\u0438\u0435 <em>(vi\u015Be\u1E63a\u1E25)</em>: \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(sa-avadh\u0101nat\u0101)</em> \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 [\u043C\u0435\u0436\u0434\u0443 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u043C \u0438 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u043C] <em>(sambandhe)</em>&quot;||</p></blockquote><p>[\u0437\u0430\u0442\u0435\u043C,] \u044D\u0442\u043E <em>(etad eva)</em> \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E <em>(\u0101nanda\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(ya\u1E25)</em> \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 <em>(maya\u1E25)</em> camatk\u0101ra --\u0432\u043E\u0441\u0442\u043E\u0440\u0433\u0430 \u0447\u0438\u0441\u0442\u043E\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(camatk\u0101ra)</em>, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F [\u0435\u0433\u043E] \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(avadh\u0101natas)</em> \u043A [\u0435\u0433\u043E] \u043F\u043E\u043A\u043E\u044E <em>(vi\u015Br\u0101nti)</em> \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 <em>(pada)</em> \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E, \u0438\u043B\u0438 \u0412\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E <em>(pram\u0101t\u1E5B)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0435\u0433\u043E <em>(asya)</em> \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435\u043C <em>(sukham)</em> Sam\u0101dhi <em>(sam\u0101dhi)</em><sup>2</sup>|</p><p>\u042D\u0442\u043E [\u0442\u0430\u043A\u0436\u0435] \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(tad uktam)</em> \u0432 \u0442\u043E\u043C \u0436\u0435 [\u0442\u0435\u043A\u0441\u0442\u0435] --\u0442.\u0435. \u0432 Vij\xF1\u0101nabhairava-- <em>(tatra eva)</em>:</p><blockquote><p>&quot;\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u043D\u0438\u0442\u044C, \u0447\u0442\u043E <em>(smaret)</em> \u0432\u0435\u0441\u044C <em>(sarvam)</em> \u043C\u0438\u0440 <em>(jagat)</em>, \u0438\u043B\u0438 <em>(v\u0101)</em> \u0441\u0432\u043E\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 <em>(sva)</em> \u0442\u0435\u043B\u043E <em>(deham)</em> \u043F\u0435\u0440\u0435\u043F\u043E\u043B\u043D\u0435\u043D\u044B <em>(bharitam)</em> \u0441\u0432\u043E\u0438\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C <em>(sva)</em> \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E\u043C <em>(\u0101nanda)</em>. \u041E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E <em>(yugapad)</em> --\u0442.\u0435. \u043A\u043E\u0433\u0434\u0430 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u043A \u043F\u0430\u043C\u044F\u0442\u043E\u0432\u0430\u043D\u0438\u044E \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C--, \u043E\u043D \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D <em>(maya\u1E25 bhavet)</em> \u0412\u044B\u0441\u0448\u0438\u043C <em>(para)</em> \u0412\u043E\u0441\u0442\u043E\u0440\u0433\u043E\u043C <em>(\u0101nanda)</em> \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C\u0443 \u041D\u0435\u043A\u0442\u0430\u0440\u0443 <em>(sva-am\u1E5Btena eva... iti)</em>&quot;||</p></blockquote><p>\u042D\u0442\u0430 \u0436\u0435 [\u0438\u0441\u0442\u0438\u043D\u0430] <em>(etad ca)</em> \u0431\u044B\u043B\u0430 \u043E\u0431\u043E\u0431\u0449\u0435\u043D\u0430 <em>(sa\u1E45g\u1E5Bh\u012Btam)</em> \u0432 \u044D\u0442\u043E\u043C [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435] <em>(anena)</em>:</p><blockquote><p>&quot;\u0422\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u044D\u0442\u043E <em>(iyam)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u0435\u043C <em>(pr\u0101pti\u1E25)</em> \u041D\u0435\u043A\u0442\u0430\u0440\u0430, \u0432\u0435\u0434\u0443\u0449\u0435\u0433\u043E \u043A \u0411\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u0438\u044E <em>(am\u1E5Bta... iti)</em>...&quot;</p></blockquote><p>[\u0421\u043C. Spandak\u0101rik\u0101-s II, 7]</p><p>\u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E <em>(atha ca)</em>, \u044D\u0442\u043E <em>(yad)</em> \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 <em>(sukham)</em> Sam\u0101dhi --\u0442.\u0435. \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E\u0433\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0441\u0432\u043E\u0435\u0433\u043E \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E-- <em>(sam\u0101dhi)</em>, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0449\u0435\u0435 \u0442\u043E\u043C\u0443 <em>(asya)</em>, \u043A\u0442\u043E \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u0442 \u043E\u0433\u0440\u043E\u043C\u043D\u043E\u0435 \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E <em>(\u0101r\u0101masya)</em> \u0432 \u0441\u0432\u043E\u0435\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C <em>(sva)</em> \u0412\u044B\u0441\u0448\u0435\u043C \u042F <em>(\u0101tma)</em>, \u0437\u0430\u0432\u0435\u0440\u0448\u0430\u0435\u0442\u0441\u044F <em>(tad eva... paryavas\u0101yi bhavati)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435\u043C <em>(abhivyakti)</em> \u0435\u0433\u043E <em>(sva)</em> \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 <em>(\u0101nanda)</em> \u0441\u0440\u0435\u0434\u0438 \u043B\u044E\u0434\u0435\u0439 <em>(lok\u0101n\u0101m)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043D\u0430\u0431\u043B\u044E\u0434\u0430\u044E\u0442 <em>(avalokayat\u0101m)</em> \u0435\u0433\u043E --\u0442.\u0435. \u0442\u0430\u043A\u043E\u0439 \u0447\u0435\u043B\u043E\u0432\u0435\u043A-- <em>(t\u0101d\u1E5B\u015Bam)</em> \u0442\u0430\u043C --\u0432 \u044D\u0442\u043E\u043C \u043C\u0435\u0441\u0442\u0435 \u0438 \u044D\u0442\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438-- <em>(tad)</em>. [\u042D\u0442\u043E \u0441\u043B\u0443\u0447\u0430\u0435\u0442\u0441\u044F] \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F <em>(yukty\u0101)</em> \u043F\u0435\u0440\u0435\u0434\u0430\u0447\u0435 <em>(sa\u1E45krama\u1E47a)</em> \u0432\u043E\u0441\u0442\u043E\u0440\u0433\u0430 <em>(\u0101nanda)</em>|</p><p>\u042D\u0442\u043E <em>(etad)</em> \u0442\u0430\u043A\u0436\u0435 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u0435\u0442 <em>(api... su-sa\u1E41v\u0101dam)</em> \u0441\u0442\u0440\u043E\u0444\u0435 <em>(granthena)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u0439 <em>(\u015Br\u012B)</em> Candraj\xF1\u0101na <em>(candraj\xF1\u0101na)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0431\u044B\u043B\u0430 \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0430 <em>(uktena)</em> \u0440\u0430\u043D\u0435\u0435 <em>(pr\u0101k)</em> \u0432 [\u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430] \u0441\u0435\u0434\u044C\u043C\u043E\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C \u043F\u0435\u0440\u0432\u043E\u0439 \u0413\u043B\u0430\u0432\u044B <em>(1-7)</em>||18||</p><hr><ol><li><p>\u042F \u043D\u0435 \u043C\u043E\u0433\u0443 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0438\u0442\u044C \u0441\u043B\u043E\u0432\u0430 \u043F\u043E \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432\u0441\u0435 \u044D\u0442\u043E \u043D\u0435 \u0438\u043C\u0435\u043B\u043E \u0431\u044B \u0441\u043C\u044B\u0441\u043B\u0430 \u043D\u0430 \u0430\u043D\u0433\u043B\u0438\u0439\u0441\u043A\u043E\u043C \u044F\u0437\u044B\u043A\u0435: &quot;\u0432 \u0442\u043E\u043C, \u0447\u0442\u043E (tasmin) \u0432 \u0442\u043E\u043C, \u0447\u0442\u043E \u043E\u0447\u0435\u0432\u0438\u0434\u043D\u043E (sphurati) \u0432 \u0442\u043E\u043C, \u0447\u0442\u043E \u044D\u0442\u043E (sati)&quot;. \u0424\u0440\u0430\u0437\u0430 \u043F\u043E\u0441\u0442\u0440\u043E\u0435\u043D\u0430 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0432 \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u043D\u043E\u043C \u043F\u0430\u0434\u0435\u0436\u0435 (\u0441\u043F\u0435\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0439 \u0442\u0438\u043F \u043A\u043E\u043D\u0441\u0442\u0440\u0443\u043A\u0446\u0438\u0439 \u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435), \u0438 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0432\u0430\u043C \u043D\u0430\u0434\u043E \u0434\u043E\u0431\u0430\u0432\u043B\u044F\u0442\u044C &quot;\u043A\u043E\u0433\u0434\u0430, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A, \u0445\u043E\u0442\u044F \u0438 \u0442.\u043F.&quot; \u0438 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0438\u0442\u044C \u0432\u0441\u0435 \u0432 \u0438\u043C\u0435\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u043C \u043F\u0430\u0434\u0435\u0436\u0435, \u0447\u0442\u043E\u0431\u044B \u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0435\u0435 (\u0444\u0440\u0430\u0437\u0443) \u043D\u0430 \u0430\u043D\u0433\u043B\u0438\u0439\u0441\u043A\u043E\u043C \u044F\u0437\u044B\u043A\u0435. \u0412 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u044F \u0434\u043E\u043B\u0436\u0435\u043D \u0434\u043E\u0431\u0430\u0432\u0438\u0442\u044C &quot;\u0445\u043E\u0442\u044F&quot;. \u042F \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u043B \u0447\u0435\u0442\u043A\u043E \u043F\u0440\u043E\u044F\u0441\u043D\u0438\u0442\u044C \u044D\u0442\u043E\u0442 \u043C\u043E\u043C\u0435\u043D\u0442, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043B\u044E\u0434\u0438 \u043C\u043E\u0433\u0443\u0442 \u043F\u043E\u0434\u0443\u043C\u0430\u0442\u044C, \u0447\u0442\u043E \u044F \u043E\u0431\u043C\u0430\u043D\u044B\u0432\u0430\u044E \u0437\u0434\u0435\u0441\u044C, \u0438\u0433\u043D\u043E\u0440\u0438\u0440\u0443\u044F \u0441\u043C\u044B\u0441\u043B \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0438\u0437 \u044D\u0442\u0438\u0445 \u0442\u0440\u0435\u0445 \u0441\u043B\u043E\u0432. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u0435 \u0441\u043B\u0443\u0447\u0430\u0435\u0432, \u044F \u043D\u0435 \u043C\u043E\u0433\u0443 \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0442\u044C \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0435 \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0442\u043E\u043D\u043A\u043E\u0441\u0442\u0438, \u0442.\u043A. \u044D\u0442\u043E \u043F\u043E\u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043B\u043E \u0431\u044B \u043C\u043D\u043E\u0433\u043E \u043F\u043E\u044F\u0441\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u043F\u0440\u0438\u043C\u0435\u0447\u0430\u043D\u0438\u0439, \u043F\u0440\u043E\u0441\u0442\u043E \u043F\u043E\u0432\u0435\u0440\u044C\u0442\u0435 \u043C\u043D\u0435, \u043F\u043E\u0436\u0430\u043B\u0443\u0439\u0441\u0442\u0430.</p></li><li><p>\u0412 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u0441\u043B\u043E\u0432\u043E &quot;Sam\u0101dhi&quot; \u043D\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u043A\u0430\u043A &quot;\u0418\u0434\u0435\u0430\u043B\u044C\u043D\u0430\u044F \u041A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044F&quot; (\u043A\u0430\u043A \u0432 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0439 \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438 \u0441 \u0437\u0430\u043A\u0440\u044B\u0442\u044B\u043C\u0438 \u0433\u043B\u0430\u0437\u0430\u043C\u0438). \u041D\u0435\u0442, \u0437\u0434\u0435\u0441\u044C \u044D\u0442\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u0441\u0432\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u043A\u0430\u043A \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E, \u0438\u043B\u0438 \u0412\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E. \u042D\u0442\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0428\u0438\u0432\u044B, \u0438 \u043E\u043D\u043E \u0432\u043E\u043E\u0431\u0449\u0435 \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u043E \u043D\u0438\u043A\u0430\u043A\u0438\u043C\u0438 \u0443\u0441\u0438\u043B\u0438\u044F\u043C\u0438! \u041E\u043D\u043E \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0411\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u041C\u0438\u043B\u043E\u0441\u0442\u0438. \u0422.\u0435. \u0440\u0435\u0447\u044C \u0438\u0434\u0435\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u043E \u0415\u0433\u043E \u0421\u0432\u043E\u0431\u043E\u0434\u043D\u043E\u0439 \u0412\u043E\u043B\u0435.</p></li></ol></div><div class="stanza"><a href="#s1.19" id="s1.19" class="num">1.19</a><div class="sans"><p>\u0905\u0925\u0947\u0926\u0943\u0936\u0938\u094D\u092F\u093E\u0938\u094D\u092F \u092F\u094B\u0917\u093F\u0928\u094B \u0935\u093F\u092D\u0942\u0924\u093F\u092F\u094B\u0917\u0902 \u0926\u0930\u094D\u0936\u092F\u0924\u093F\u2014</p><blockquote><p><strong>\u0936\u0915\u094D\u0924\u093F\u0938\u0928\u094D\u0927\u093E\u0928\u0947 \u0936\u0930\u0940\u0930\u094B\u0924\u094D\u092A\u0924\u094D\u0924\u093F\u0903\u0965\u0967\u096F</strong></p></blockquote><p>\u0907\u091A\u094D\u091B\u093E \u0936\u0915\u094D\u0924\u093F\u0930\u0941\u092E\u093E \u0915\u0941\u092E\u093E\u0930\u0940 (\u0967-\u0967\u0969) \u0907\u0924\u093F \u0938\u0942\u0924\u094D\u0930\u0947\u0923 \u092F\u093E\u0938\u094D\u092F \u0936\u0915\u094D\u0924\u093F\u0930\u0941\u0915\u094D\u0924\u093E \u0924\u093E\u092E\u0947\u0935 \u092F\u0926\u093E\u0928\u0941\u0938\u0928\u094D\u0927\u0924\u094D\u0924\u0947 \u0926\u093E\u0930\u094D\u0922\u094D\u092F\u0947\u0928 \u0924\u0928\u094D\u092E\u092F\u0940\u092D\u0935\u0924\u093F \u0924\u0926\u093E \u0924\u0926\u094D\u0935\u0936\u0947\u0928\u093E\u0938\u094D\u092F \u092F\u0925\u093E\u092D\u093F\u092E\u0924\u0902 \u0936\u0930\u0940\u0930\u092E\u0941\u0924\u094D\u092A\u0926\u094D\u092F\u0924\u0947\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u092E\u0943\u0924\u094D\u092F\u0941\u091E\u094D\u091C\u092F\u092D\u091F\u094D\u091F\u093E\u0930\u0915\u0947</p><blockquote><p>\u0924\u0924\u0903 \u092A\u094D\u0930\u0935\u0930\u094D\u0924\u0924\u0947 \u0936\u0915\u094D\u0924\u093F\u0930\u094D\u0932\u0915\u094D\u0937\u094D\u092F\u0939\u0940\u0928\u093E \u0928\u093F\u0930\u093E\u092E\u092F\u093E \u0907\u091A\u094D\u091B\u093E \u0938\u093E \u0924\u0941 \u0935\u093F\u0928\u093F\u0930\u094D\u0926\u093F\u0937\u094D\u091F\u093E \u091C\u094D\u091E\u093E\u0928\u0930\u0942\u092A\u093E \u0915\u094D\u0930\u093F\u092F\u093E\u0924\u094D\u092E\u093F\u0915\u093E\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u092A\u0915\u094D\u0930\u092E\u094D\u092F</p><blockquote><p>\u0938\u093E \u092F\u094B\u0928\u093F\u0903 \u0938\u0930\u094D\u0935\u0926\u0947\u0935\u093E\u0928\u093E\u0902 \u0936\u0915\u094D\u0924\u0940\u0928\u093E\u0902 \u091A\u093E\u092A\u094D\u092F\u0928\u0947\u0915\u0927\u093E \u0905\u0917\u094D\u0928\u0940\u0937\u094B\u092E\u093E\u0924\u094D\u092E\u093F\u0915\u093E \u092F\u094B\u0928\u093F\u0938\u094D\u0924\u0938\u094D\u092F\u093E\u0903 \u0938\u0930\u094D\u0935\u0902 \u092A\u094D\u0930\u0935\u0930\u094D\u0924\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u0915\u094D\u0924\u093F\u0938\u0928\u094D\u0927\u093E\u0928\u092E\u093E\u0939\u093E\u0924\u094D\u092E\u094D\u092F\u0902 \u0932\u0915\u094D\u0937\u094D\u092E\u0940\u0915\u094C\u0932\u093E\u0930\u094D\u0923\u0935\u0947</p><blockquote><p>\u0928 \u0938\u0928\u094D\u0927\u093E\u0928\u0902 \u0935\u093F\u0928\u093E \u0926\u0940\u0915\u094D\u0937\u093E \u0928 \u0938\u093F\u0926\u094D\u0927\u0940\u0928\u093E\u0902 \u091A \u0938\u093E\u0927\u0928\u092E\u094D \u0928 \u092E\u0928\u094D\u0924\u094D\u0930\u094B \u092E\u0928\u094D\u0924\u094D\u0930\u092F\u0941\u0915\u094D\u0924\u093F\u0936\u094D\u091A \u0928 \u092F\u094B\u0917\u093E\u0915\u0930\u094D\u0937\u0923\u0902 \u092F\u0925\u093E\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u093E\u0926\u093F\u0928\u093E \u092A\u094D\u0930\u0924\u093F\u092A\u093E\u0926\u093F\u0924\u092E\u094D\u0964 \u090F\u0924\u091A\u094D\u091A</p><blockquote><p>\u092F\u0925\u0947\u091A\u094D\u091B\u093E\u092D\u094D\u092F\u0930\u094D\u0925\u093F\u0924\u094B \u0927\u093E\u0924\u093E \u091C\u093E\u0917\u094D\u0930\u0924\u094B\u093D\u0930\u094D\u0925\u093E\u0928\u094D\u0939\u0943\u0926\u093F \u0938\u094D\u0925\u093F\u0924\u093E\u0928\u094D \u0938\u094B\u092E\u0938\u0942\u0930\u094D\u092F\u094B\u0926\u092F\u0902 \u0915\u0943\u0924\u094D\u0935\u093E \u0938\u092E\u094D\u092A\u093E\u0926\u092F\u0924\u093F \u0926\u0947\u0939\u093F\u0928\u0903\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928 \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u094D\u0964 \u0926\u0947\u0939\u093F\u0928\u094B\u093D\u0924\u094D\u092F\u0915\u094D\u0924\u0926\u0947\u0939\u0935\u093E\u0938\u0928\u0938\u094D\u092F \u092F\u094B\u0917\u093F\u0928\u094B \u0939\u0943\u0926\u093F \u0938\u094D\u0925\u093F\u0924\u093E\u0928\u0930\u094D\u0925\u093E\u0928\u094D\u0924\u0924\u094D\u0924\u0926\u092A\u0942\u0930\u094D\u0935\u0928\u093F\u0930\u094D\u092E\u093E\u0923\u093E\u0926\u093F\u0930\u0942\u092A\u093E\u0928\u094D\u0927\u093E\u0924\u093E \u092E\u0939\u0947\u0936\u094D\u0935\u0930\u0903 \u092A\u094D\u0930\u0915\u093E\u0936\u093E\u0928\u0928\u094D\u0926\u093E\u0924\u094D\u092E\u0924\u092F\u093E \u0938\u094B\u092E\u0938\u0942\u0930\u094D\u092F\u0930\u0942\u092A\u0935\u093E\u0939\u094B\u0928\u094D\u092E\u0940\u0932\u0928\u0947\u0928 \u0938\u094B\u092E\u0938\u0942\u0930\u094D\u092F\u0938\u093E\u092E\u0930\u0938\u094D\u092F\u093E\u0924\u094D\u092E\u0928\u0936\u094D\u091A \u0936\u0915\u094D\u0924\u0947\u0930\u0941\u0926\u092F\u0902 \u0915\u0943\u0924\u094D\u0935\u093E \u092C\u0939\u093F\u0930\u094D\u092E\u0941\u0916\u0935\u093E\u0939\u093F\u0924\u094D\u0935\u0947\u0928 \u0924\u093E\u092E\u093E\u0938\u093E\u0926\u094D\u092F \u0938\u092E\u094D\u092A\u093E\u0926\u092F\u0924\u0940\u0924\u093F \u0939\u094D\u092F\u0938\u094D\u092F\u093E\u0930\u094D\u0925\u0903</p><blockquote><p>\u0924\u0925\u093E \u0938\u094D\u0935\u092A\u094D\u0928\u0947\u093D\u092A\u094D\u092F\u092D\u0940\u0937\u094D\u091F\u093E\u0930\u094D\u0925\u093E\u0928\u094D...\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u0947\u0924\u091A\u094D\u091B\u094D\u0932\u094B\u0915\u092A\u094D\u0930\u0924\u093F\u092A\u093E\u0926\u093F\u0924\u0938\u094D\u0935\u092A\u094D\u0928\u0938\u094D\u0935\u093E\u0924\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u0902 \u092A\u094D\u0930\u0924\u093F \u0926\u0943\u0937\u094D\u091F\u093E\u0928\u094D\u0924\u0947 \u092F\u094B\u091C\u093F\u0924 \u0907\u0924\u093F \u0938\u094D\u092A\u0928\u094D\u0926\u0928\u093F\u0930\u094D\u0923\u092F\u0947 \u092E\u092F\u0948\u0935 \u0926\u0930\u094D\u0936\u093F\u0924\u092E\u094D\u0965\u0967\u096F\u0965</p></div><hr><div class="trans"><p>Athed\u1E5B\u015Basy\u0101sya yogino vibh\u016Btiyoga\u1E41 dar\u015Bayati\u2014</p><blockquote><p><strong>\u015Aaktisandh\u0101ne \u015Bar\u012Brotpatti\u1E25||19||</strong></p></blockquote><p>Icch\u0101 \u015Baktirum\u0101 kum\u0101r\u012B (1-13) iti s\u016Btre\u1E47a y\u0101sya \u015Baktirukt\u0101 t\u0101meva yad\u0101nusandhatte d\u0101r\u1E0Dhyena tanmay\u012Bbhavati tad\u0101 tadva\u015Ben\u0101sya yath\u0101bhimata\u1E41 \u015Bar\u012Bramutpadyate| Tadukta\u1E41 \u015Br\u012Bm\u1E5Btyu\xF1jayabha\u1E6D\u1E6D\u0101rake</p><blockquote><p>Tata\u1E25 pravartate \u015Baktirlak\u1E63yah\u012Bn\u0101 nir\u0101may\u0101 Icch\u0101 s\u0101 tu vinirdi\u1E63\u1E6D\u0101 j\xF1\u0101nar\u016Bp\u0101 kriy\u0101tmik\u0101||</p></blockquote><p>ityupakramya</p><blockquote><p>S\u0101 yoni\u1E25 sarvadev\u0101n\u0101\u1E41 \u015Bakt\u012Bn\u0101\u1E41 c\u0101pyanekadh\u0101 Agn\u012B\u1E63om\u0101tmik\u0101 yonistasy\u0101\u1E25 sarva\u1E41 pravartate||</p></blockquote><p>iti| \u015Aaktisandh\u0101nam\u0101h\u0101tmya\u1E41 lak\u1E63m\u012Bkaul\u0101r\u1E47ave</p><blockquote><p>Na sandh\u0101na\u1E41 vin\u0101 d\u012Bk\u1E63\u0101 na siddh\u012Bn\u0101\u1E41 ca s\u0101dhanam Na mantro mantrayukti\u015Bca na yog\u0101kar\u1E63a\u1E47a\u1E41 yath\u0101||</p></blockquote><p>ity\u0101din\u0101 pratip\u0101ditam| Etacca</p><blockquote><p>Yathecch\u0101bhyarthito dh\u0101t\u0101 j\u0101grato&#39;rth\u0101nh\u1E5Bdi sthit\u0101n Somas\u016Bryodaya\u1E41 k\u1E5Btv\u0101 samp\u0101dayati dehina\u1E25||</p></blockquote><p>ityanena sa\u1E45g\u1E5Bh\u012Btam| Dehino&#39;tyaktadehav\u0101sanasya yogino h\u1E5Bdi sthit\u0101narth\u0101ntattadap\u016Brvanirm\u0101\u1E47\u0101dir\u016Bp\u0101ndh\u0101t\u0101 mahe\u015Bvara\u1E25 prak\u0101\u015B\u0101nand\u0101tmatay\u0101 somas\u016Bryar\u016Bpav\u0101honm\u012Blanena somas\u016Bryas\u0101marasy\u0101tmana\u015Bca \u015Bakterudaya\u1E41 k\u1E5Btv\u0101 bahirmukhav\u0101hitvena t\u0101m\u0101s\u0101dya samp\u0101dayat\u012Bti hyasy\u0101rtha\u1E25</p><blockquote><p>Tath\u0101 svapne&#39;pyabh\u012B\u1E63\u1E6D\u0101rth\u0101n...|</p></blockquote><p>ityetacchlokapratip\u0101ditasvapnasv\u0101tantrya\u1E41 prati d\u1E5B\u1E63\u1E6D\u0101nte yojita iti spandanir\u1E47aye mayaiva dar\u015Bitam||19||</p></div><hr><p>\u0421\u0435\u0439\u0447\u0430\u0441 <em>(atha)</em>, [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C] \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 <em>(dar\u015Bayati)</em> Vibh\u016Btiyoga --\u0419\u043E\u0433\u0443 \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0441\u0438\u043B-- <em>(vibh\u016Bti-yoga\u1E41)</em> \u0442\u0430\u043A\u043E\u0433\u043E <em>(\u012Bd\u1E5B\u015Basya asya)</em> Yog\u012B <em>(yogina\u1E25)</em>\u2014</p><blockquote><p><strong>\u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F <em>(sandh\u0101ne)</em> \u0441 \u0421\u0438\u043B\u043E\u0439 [\u0412\u043E\u043B\u0438] <em>(\u015Bakti)</em> [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u043F\u0440\u043E\u0434\u0443\u0446\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0435 <em>(utpatti\u1E25)</em> \u0442\u0435\u043B <em>(\u015Bar\u012Bra)</em> [\u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0436\u0435\u043B\u0430\u043D\u0438\u0435\u043C Yog\u012B]||19||</strong></p></blockquote><p>\u0412 \u0442\u0440\u0438\u043D\u0430\u0434\u0446\u0430\u0442\u043E\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 \u043F\u0435\u0440\u0432\u043E\u0439 \u0433\u043B\u0430\u0432\u044B <em>(1-13... s\u016Btre\u1E47a)</em>, [\u0433\u0434\u0435] &quot;\u0421\u0438\u043B\u0430 \u0412\u043E\u043B\u0438 <em>(icch\u0101 \u015Bakti\u1E25)</em> [\u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u043E\u0433\u043E Yog\u012B \u2014 \u044D\u0442\u043E] &#39;\u0412\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u0438\u0435 \u0428\u0438\u0432\u044B&#39; <em>(um\u0101)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C] Kum\u0101r\u012B <em>(kum\u0101r\u012B... iti)</em>&quot;, \u0435\u0433\u043E <em>(asya)</em> \u0421\u0438\u043B\u0430, \u0438\u043B\u0438 \u0428\u0430\u043A\u0442\u0438 <em>(y\u0101... \u015Bakti\u1E25)</em> \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(ukt\u0101)</em>. \u041A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u043E\u043D, [\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u0433\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F], \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0435\u0434\u0438\u043D\u044B\u043C <em>(anusandhatte)</em> \u0441 \u043D\u0435\u0439 --\u0442.\u0435. \u0441 \u0435\u0433\u043E Icch\u0101\u015Bakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u043E\u0439 \u0412\u043E\u043B\u0438-- <em>(t\u0101m eva)</em>; [\u043A\u043E\u0440\u043E\u0447\u0435, \u043A\u043E\u0433\u0434\u0430] \u043E\u043D <em>(bhavati)</em> \u0442\u0432\u0435\u0440\u0434\u043E <em>(d\u0101r\u1E0Dhyena)</em> \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D \u044D\u0442\u043E\u0439 [\u0421\u0438\u043B\u043E\u0439 \u0412\u043E\u043B\u0438] <em>(tad-may\u012B)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C <em>(va\u015Bena)</em> \u044D\u0442\u043E\u0439 [\u0441\u0438\u043B\u044B] <em>(tad)</em> \u0435\u0433\u043E <em>(asya)</em> \u0442\u0435\u043B\u043E <em>(\u015Bar\u012Bram)</em> \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442\u0441\u044F --\u0442.\u0435. \u0441\u043E\u0437\u0434\u0430\u0435\u0442\u0441\u044F-- <em>(utpadyate)</em> \u043F\u043E \u0435\u0433\u043E \u0432\u043E\u043B\u0435--\u0442.\u0435. \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u044E-- <em>(yath\u0101-abhimatam)</em>|</p><p>\u042D\u0442\u043E \u0436\u0435 <em>(tad)</em> \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0435\u0442\u0441\u044F <em>(uktam)</em> \u0432 \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u0439 <em>(\u015Br\u012B... bha\u1E6D\u1E6D\u0101rake)</em> M\u1E5Btyu\xF1jaya --\u0442.\u0435. Netratantra-- <em>(m\u1E5Btyu\xF1jaya)</em> \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441\u043E [\u0441\u0442\u0440\u043E\u0444\u044B 36 \u0441\u0435\u0434\u044C\u043C\u043E\u0439 adhik\u0101ra, \u0438\u043B\u0438 \u0433\u043B\u0430\u0432\u044B] <em>(upakramya)</em>:</p><blockquote><p>&quot;\u041E\u0442\u0441\u044E\u0434\u0430 --\u0442.\u0435. \u0438\u0437 \u044D\u0442\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F Parama\u015Biva, \u0440\u0435\u0430\u043B\u0438\u0437\u043E\u0432\u0430\u043D\u043D\u043E\u0433\u043E Yog\u012B<sup>1</sup> -- <em>(tatas)</em> \u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(pravartate)</em> \u0421\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043B\u0438\u0448\u0435\u043D\u0430 <em>(h\u012Bn\u0101... nis)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u0438\u043C\u0447\u0438\u0432\u043E\u0441\u0442\u0438 <em>(lak\u1E63ya)</em> [\u0438] \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u0439 <em>(\u0101may\u0101)</em><sup>2</sup> . \u042D\u0442\u0430 [\u0421\u0438\u043B\u0430] <em>(s\u0101)</em> \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u0430 <em>(vinirdi\u1E63\u1E6D\u0101)</em> [\u043A\u0430\u043A] Icch\u0101 --\u0412\u043E\u043B\u044F-- <em>(icch\u0101)</em>, \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 <em>(tu)</em>, [\u0432\u043F\u043E\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0438] \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0430\u044F\u0441\u044F \u0432 \u0444\u043E\u0440\u043C\u0435 <em>(r\u016Bp\u0101... \u0101tmik\u0101)</em> J\xF1\u0101na --\u0417\u043D\u0430\u043D\u0438\u044F-- <em>(j\xF1\u0101na)</em> [\u0438] Kriy\u0101 --\u0414\u0435\u0439\u0441\u0442\u0432\u0438\u044F-- <em>(kriy\u0101... iti)</em>&quot;||<sup>4</sup></p></blockquote><p>[\u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0432 40-\u0439 \u0441\u0442\u0440\u043E\u0444\u0435 \u0442\u043E\u0439 \u0436\u0435 adhik\u0101ra, \u0438\u043B\u0438 \u0433\u043B\u0430\u0432\u044B:]</p><blockquote><p>&quot;\u041E\u043D\u0430 --\u0442.\u0435. \u0412\u044B\u0441\u0448\u0430\u044F \u015Aakti-- <em>(s\u0101)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F], \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C\u0438 \u0441\u043F\u043E\u0441\u043E\u0431\u0430\u043C\u0438 <em>(anekadh\u0101)</em>, \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u043C <em>(yoni\u1E25)</em> \u0432\u0441\u0435\u0445 \u0431\u043E\u0433\u043E\u0432 <em>(sarva-dev\u0101n\u0101m)</em>, \u0442\u0430\u043A \u0436\u0435 \u043A\u0430\u043A \u0438 <em>(ca api)</em> \u0441\u0438\u043B, \u0438\u043B\u0438 \u015Bakti-s <em>(\u015Bakt\u012Bn\u0101m)</em>. \u0415\u0435 \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(\u0101tmik\u0101)</em> [\u0435\u0441\u0442\u044C] \u043E\u0433\u043E\u043D\u044C \u0438 \u043B\u0443\u043D\u0430 <em>(agn\u012B\u1E63oma)</em><sup>5</sup>. \u0412\u0441\u0435 <em>(sarvam)</em> \u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(pravartate)</em> \u0438\u0437 \u041D\u0435\u0435 <em>(tasy\u0101\u1E25)</em>&quot;||</p></blockquote><p>\u0412\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(m\u0101h\u0101tmyam)</em> \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F \u0441 \u015Aakti \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u0439 \u043E\u0434\u043D\u043E\u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(\u015Bakti-sandh\u0101na)</em> \u0431\u044B\u043B\u043E \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E <em>(pratip\u0101ditam)</em> in Lak\u1E63m\u012Bkaul\u0101r\u1E47ava <em>(lak\u1E63m\u012B-kaul\u0101r\u1E47ave)</em> [\u0432 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0439 \u0438] \u0434\u0440\u0443\u0433\u0438\u0445 [\u0441\u0442\u0440\u043E\u0444\u0430\u0445] <em>(\u0101din\u0101)</em>:</p><blockquote><p>&quot;\u0411\u0435\u0437 <em>(vin\u0101)</em> \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F [\u0441 \u015Aakti] \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u0439 \u043E\u0434\u043D\u043E\u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(sandh\u0101nam)</em> \u043D\u0435\u0442 \u043D\u0438 <em>(na)</em> \u0438\u043D\u0438\u0446\u0438\u0430\u0446\u0438\u0438 <em>(d\u012Bk\u1E63\u0101)</em>, \u043D\u0438 <em>(na... ca)</em> \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F <em>(s\u0101dhanam)</em> \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0441\u0438\u043B <em>(siddh\u012Bn\u0101m)</em>, \u043D\u0438 <em>(na)</em> \u043C\u0430\u043D\u0442\u0440\u044B <em>(mantra\u1E25)</em>, \u043D\u0438 <em>(ca)</em> \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438 <em>(yukti\u1E25)</em>, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0439 \u0441 \u043C\u0430\u043D\u0442\u0440\u0430\u043C\u0438 <em>(mantra)</em>, \u043D\u0438 <em>(na)</em> \u2014\u043A\u0430\u043A\u043E\u0433\u043E \u0431\u044B \u0442\u043E \u043D\u0438 \u0431\u044B\u043B\u043E <em>(na... yath\u0101)</em>\u2014 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u0442\u0432\u0430 <em>(\u0101kar\u1E63a\u1E47am)</em><sup>6</sup> \u0432 \u0419\u043E\u0433\u0435 <em>(yoga)</em>&quot;||</p></blockquote><p>\u042D\u0442\u043E \u0436\u0435 [\u0443\u0447\u0435\u043D\u0438\u0435] <em>(etad ca)</em> \u0431\u044B\u043B\u043E \u043E\u0431\u043E\u0431\u0449\u0435\u043D\u043E <em>(sa\u1E45g\u1E5Bh\u012Btam)</em> \u0432 \u044D\u0442\u043E\u043C [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435] <em>(anena)</em>:</p><blockquote><p>&quot;\u0422\u0430\u043A \u0436\u0435 \u043A\u0430\u043A <em>(yath\u0101)</em> \u0414\u0435\u0440\u0436\u0430\u0442\u0435\u043B\u044C [\u044D\u0442\u043E\u0433\u043E \u043C\u0438\u0440\u0430] <em>(dh\u0101t\u0101)</em>, \u043A\u043E\u0433\u0434\u0430 \u0435\u0433\u043E \u043F\u0440\u043E\u0441\u044F\u0442 <em>(abhyarthita\u1E25)</em> \u0441 \u0436\u0435\u043B\u0430\u043D\u0438\u0435\u043C <em>(icch\u0101)</em>, \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442 <em>(samp\u0101dayati)</em> [\u0432\u0441\u0435] \u0432\u0435\u0449\u0438 <em>(arth\u0101n)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442 <em>(sthit\u0101n)</em> \u0432 \u0441\u0435\u0440\u0434\u0446\u0435 <em>(h\u1E5Bdi)</em> \u044D\u0442\u043E\u0439 \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u043D\u043E\u0439 \u0434\u0443\u0448\u0438 <em>(dehina\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u0430 <em>(j\u0101grata\u1E25)</em>, \u0432\u044B\u0437\u0432\u0430\u0432 <em>(k\u1E5Btv\u0101)</em> \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(udayam)</em> \u043B\u0443\u043D\u044B <em>(soma)</em> [\u0438] \u0441\u043E\u043B\u043D\u0446\u0430 <em>(s\u016Brya... iti)</em><sup>7</sup>&quot;| [\u0421\u043C. Spandak\u0101rik\u0101-s III, 1]</p></blockquote><p>\u0422\u0432\u043E\u0440\u0435\u0446 <em>(dh\u0101t\u0101)</em>, \u0442.\u0435 \u0412\u0435\u043B\u0438\u043A\u0438\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C --\u044D\u043F\u0438\u0442\u0435\u0442 \u0428\u0438\u0432\u044B-- <em>(mah\u0101-\u012B\u015Bvara\u1E25)</em> \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u0435\u0442 --\u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442-- <em>(samp\u0101dayati)</em> [\u0432\u0441\u0435] \u0432\u0435\u0449\u0438 <em>(arth\u0101n)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F <em>(r\u016Bp\u0101n)</em> \u0440\u0430\u0437\u043D\u044B\u043C\u0438 <em>(tad tad)</em> [\u0438] \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u043D\u043E\u0432\u044B\u043C\u0438 <em>(ap\u016Brva)</em> \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F\u043C\u0438 <em>(nirm\u0101\u1E47a)</em>, \u0438 \u0442.\u043F., <em>(\u0101di)</em> \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0438\u043C\u0438\u0441\u044F <em>(sthit\u0101n)</em> \u0432 \u0441\u0435\u0440\u0434\u0446\u0435 <em>(h\u1E5Bdi)</em> \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u043D\u043E\u0433\u043E <em>(dehina\u1E25)</em> Yog\u012B <em>(yogina\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043D\u0435 \u043E\u0442\u043A\u0430\u0437\u0430\u043B\u0441\u044F \u043E\u0442 <em>(atyakta)</em> \u0441\u0432\u043E\u0435\u0433\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u044F <em>(v\u0101sanasya)</em> [\u043E\u0441\u0442\u0430\u0432\u0430\u0442\u044C\u0441\u044F] \u0432 \u0442\u0435\u043B\u0435 <em>(deha)</em>. [\u0412\u044B\u0441\u0448\u0435\u0435 \u042F \u0434\u0435\u043B\u0430\u0435\u0442 \u044D\u0442\u043E \u0441\u043D\u0430\u0447\u0430\u043B\u0430], \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u044F <em>(unm\u012Blanena)</em> \u043F\u043E\u0442\u043E\u043A <em>(v\u0101ha)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0438\u0439 \u0438\u0437 <em>(r\u016Bpa)</em> \u043B\u0443\u043D\u044B --\u0442.\u0435. ap\u0101na, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438, \u0432\u0445\u043E\u0434\u044F\u0449\u0435\u0439 \u0441 \u0432\u0434\u043E\u0445\u043E\u043C-- <em>(soma)</em> [\u0438] \u0441\u043E\u043B\u043D\u0446\u0430 --\u0442.\u0435. pr\u0101\u1E47a, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438, \u0432\u044B\u0445\u043E\u0434\u044F\u0449\u0435\u0439 \u0441 \u0432\u044B\u0434\u043E\u0445\u043E\u043C-- <em>(s\u016Brya)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C Prak\u0101\u015Ba --\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F \u0441\u0432\u0435\u0442\u0430-- \u0438 \u0100nanda --\u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430-- <em>(prak\u0101\u015Ba-\u0101nanda-\u0101tmatay\u0101)</em>, \u0438 <em>(ca)</em> [\u0437\u0430\u0442\u0435\u043C], \u0432\u044B\u0437\u044B\u0432\u0430\u044F <em>(k\u1E5Btv\u0101)</em> \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(udayam)</em> \u0441\u0438\u043B\u044B, \u0438\u043B\u0438 \u015Bakti --\u0442.\u0435. sam\u0101na-- <em>(\u015Bakte\u1E25)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0439 \u0438\u0437 <em>(\u0101tmana\u1E25)</em> \u0440\u0430\u0432\u043D\u043E\u0432\u0435\u0441\u0438\u044F <em>(s\u0101marasya)</em> \u043B\u0443\u043D\u044B, \u0438\u043B\u0438 ap\u0101na <em>(soma)</em> [\u0438] \u0441\u043E\u043B\u043D\u0446\u0430, \u0438\u043B\u0438 pr\u0101\u1E47a <em>(s\u016Brya)</em><sup>8</sup> . [\u041F\u043E\u0441\u043B\u0435 \u044D\u0442\u043E\u0433\u043E,] \u043F\u043E\u0434\u0430\u0432\u0438\u0432 <em>(\u0101s\u0101dya)</em> \u044D\u0442\u0443 \u015Bakti [\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0443\u044E \u043A\u0430\u043A sam\u0101na] <em>(t\u0101m)</em> --\u0442.\u0435. \u0432\u043E\u0441\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0432 \u043E\u0431\u044B\u0447\u043D\u044B\u0435 \u0444\u0443\u043D\u043A\u0446\u0438\u0438 ap\u0101na \u0438 pr\u0101\u1E47a--, [\u0413\u043E\u0441\u043F\u043E\u0434\u044C \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u0435\u0442] \u0432\u043E\u0432\u043D\u0435 <em>(bahis-mukha-v\u0101hitvena)</em> [\u0436\u0435\u043B\u0430\u043D\u0438\u044F \u044D\u0442\u043E\u0433\u043E Yog\u012B]. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 <em>(iti... artha\u1E25)</em> \u044D\u0442\u043E\u0433\u043E [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 \u0432 Spandak\u0101rik\u0101-s] <em>(asya)</em> \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(hi)</em><sup>9</sup>.</p><blockquote><p>&quot;\u0422\u0430\u043A <em>(tath\u0101)</em> \u0442\u0430\u043A\u0436\u0435 <em>(api)</em> \u0432\u043E \u0441\u043D\u0435 <em>(svapne)</em>, _[\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0432 \u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u043E\u043C \u043A\u0430\u043D\u0430\u043B\u0435, (\u041E\u043D), \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u0432\u0441\u0435\u0433\u0434\u0430 (\u0438) \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u044F\u0441\u043D\u043E] (\u0435\u0433\u043E] \u0436\u0435\u043B\u0430\u0435\u043C\u044B\u0435 <em>(abh\u012B\u1E63\u1E6Da)</em> \u0432\u0435\u0449\u0438 <em>(arth\u0101n... iti)</em>&quot; <em>[\u0442\u043E\u043C\u0443, \u043A\u0442\u043E \u043D\u0435 \u043F\u0440\u0435\u043D\u0435\u0431\u0440\u0435\u0433\u0430\u0435\u0442 \u0441\u0432\u043E\u0435\u0439 \u043C\u043E\u043B\u044C\u0431\u043E\u0439]</em>.<sup>10</sup></p></blockquote><p>[\u0421\u043C. Spandak\u0101rik\u0101-s III, 2]</p><p>\u041A\u0430\u043A \u0431\u044B\u043B\u043E \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u043E <em>(iti... dar\u015Bitam)</em> \u043C\u043D\u043E\u0439 <em>(may\u0101 eva)</em> \u0432 Spandanir\u1E47aya <em>(spandanir\u1E47aye)</em>, [\u0432\u043E\u043F\u0440\u043E\u0441, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u0439\u0441\u044F \u043A] \u0441\u0432\u043E\u0431\u043E\u0434\u0435 [Yog\u012B) _<em>(sv\u0101tantryam)</em> [\u0434\u0430\u0436\u0435] \u0432\u043E \u0441\u043D\u0435 <em>(svapna)</em>, \u043A\u0430\u043A \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u043B\u043E\u0441\u044C <em>(pratip\u0101dita)</em> \u0432 \u044D\u0442\u043E\u0439 <em>(etad)</em> \u0441\u0442\u0440\u043E\u0444\u0435 <em>(\u015Bloka)</em>, \u0431\u044B\u043B \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D _(yojita\u1E25)_\u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u043F\u043E\u043B\u043E\u0436\u043D\u043E\u0433\u043E \u043F\u0440\u0438\u043C\u0435\u0440\u0430 <em>(prati d\u1E5B\u1E63\u1E6D\u0101nte)</em>||19||</p><hr><ol><li><p>\u042F \u0437\u043D\u0430\u044E \u044D\u0442\u043E, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043F\u0440\u043E\u0447\u0438\u0442\u0430\u043B \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0438\u0435 \u0441\u0442\u0440\u043E\u0444\u044B Netratantra. \u0422\u043E\u0442 \u0436\u0435 \u043C\u0443\u0434\u0440\u0435\u0446, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 \u0437\u0434\u0435\u0441\u044C \u015Aivas\u016Btra-s \u2014\u0442.\u0435. K\u1E63emar\u0101ja\u2014 \u0442\u0430\u043A\u0436\u0435 \u0441\u043E\u0441\u0442\u0430\u0432\u0438\u043B \u043E\u0431\u0448\u0438\u0440\u043D\u044B\u0439 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 \u043D\u0430 Netratantra. Parama\u015Biva \u2014 \u044D\u0442\u043E \u043F\u0440\u043E\u0441\u043E\u0442 \u0412\u044B\u0441\u0448\u0430\u044F \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C.</p></li><li><p>\u042D\u0442\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043E \u0421\u0438\u043B\u0430 \u0412\u043E\u043B\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u043D\u0435 \u0432\u0438\u0434\u0438\u043C\u0430 \u0438 \u043D\u0435 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u0430. \u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, \u043D\u0430 \u043D\u0435\u0435 \u043D\u0435 \u0432\u043B\u0438\u044F\u0435\u0442 \u043D\u0435\u0434\u0443\u0433, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u0439 \u043A\u0430\u043A M\u0101y\u0101 (\u0442\u0430\u0442\u0442\u0432\u0430, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F 6 \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439). M\u0101y\u0101\u2014 \u044D\u0442\u043E \u0432\u0443\u0430\u043B\u044C \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0430, \u043F\u043E\u043A\u0440\u044B\u0432\u0430\u044E\u0449\u0430\u044F \u0432\u0430\u0448\u0443 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443.</p></li><li><p>\u042D\u0442\u0430 \u0441\u0442\u0440\u043E\u0444\u0430 \u0438\u043C\u0435\u0435\u0442 \u0442\u0430\u043A\u0436\u0435 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u043E\u0435 \u043F\u0440\u043E\u0447\u0442\u0435\u043D\u0438\u0435 (\u043F\u0440\u043E\u0441\u0442\u043E \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u043E\u0435 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u0435):</p></li></ol><div class="sans"><blockquote><p>\u0924\u0924\u0903 \u092A\u094D\u0930\u0935\u0930\u094D\u0924\u0924\u0947 \u0936\u0915\u094D\u0924\u093F\u0930\u094D\u0932\u0915\u094D\u0937\u094D\u092F\u0939\u0940\u0928\u093E \u0928\u093F\u0930\u093E\u092E\u092F\u093E \u0907\u091A\u094D\u091B\u093E\u092E\u093E\u0924\u094D\u0930\u0935\u093F\u0928\u093F\u0930\u094D\u0926\u093F\u0937\u094D\u091F\u093E \u091C\u094D\u091E\u093E\u0928\u0930\u0942\u092A\u093E \u0915\u094D\u0930\u093F\u092F\u093E\u0924\u094D\u092E\u093F\u0915\u093E\u0965 ;;; ;;; trans Tata\u1E25 pravartate \u015Baktirlak\u1E63yah\u012Bn\u0101 nir\u0101may\u0101 Icch\u0101m\u0101travinirdi\u1E63\u1E6D\u0101 j\xF1\u0101nar\u016Bp\u0101 kriy\u0101tmik\u0101||</p></blockquote></div><blockquote><p>&quot;\u041E\u0442\u0441\u044E\u0434\u0430 --\u0442.\u0435. \u0438\u0437 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F Parama\u015Biva, \u0440\u0435\u0430\u043B\u0438\u0437\u043E\u0432\u0430\u043D\u043D\u043E\u0433\u043E Yog\u012B-- <em>(tatas)</em> \u0438\u0441\u0445\u043E\u0434\u0438\u0442 _(pravartate)_\u0421\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043B\u0438\u0448\u0435\u043D\u0430 <em>(h\u012Bn\u0101... nis)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u0438\u043C\u0447\u0438\u0432\u043E\u0441\u0442\u0438 <em>(lak\u1E63ya)</em> [\u0438] \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u0439 <em>(\u0101may\u0101)</em>, [\u0438] \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0431\u044B\u043B\u0430 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u0430 <em>(vinirdi\u1E63\u1E6D\u0101)</em> \u043D\u0435 \u0438\u043D\u0430\u0447\u0435 [\u043A\u0430\u043A] <em>(m\u0101tra)</em> Icch\u0101 --\u0412\u043E\u043B\u044F-- <em>(icch\u0101)</em>. [\u042D\u0442\u0430 \u0441\u0430\u043C\u0430\u044F \u0412\u043E\u043B\u044F] \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432 \u0444\u043E\u0440\u043C\u0435 <em>(r\u016Bp\u0101... \u0101tmik\u0101)</em> J\xF1\u0101na --\u0417\u043D\u0430\u043D\u0438\u044F-- <em>(j\xF1\u0101na)</em> [\u0438] Kriy\u0101 --\u0414\u0435\u0439\u0441\u0442\u0432\u0438\u044F-- <em>(kriy\u0101)</em>&quot;||</p></blockquote><p>OK, \u0441\u0435\u0439\u0447\u0430\u0441 \u0443 \u0432\u0430\u0441 \u0435\u0441\u0442\u044C \u043E\u0431\u0435 \u0432\u0435\u0440\u0441\u0438\u0438.</p><ol start="5"><li><p>\u0417\u0434\u0435\u0441\u044C \u043E\u0433\u043E\u043D\u044C \u0438 \u043B\u0443\u043D\u0430 \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0442 pr\u0101\u1E47a (\u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0443\u044E \u044D\u043D\u0435\u0440\u0433\u0438\u044E, \u0432\u044B\u0445\u043E\u0434\u044F\u0449\u0443\u044E \u0438\u0437 \u0432\u0430\u0441, \u043A\u043E\u0433\u0434\u0430 \u0432\u044B \u0432\u044B\u0434\u044B\u0445\u0430\u0435\u0442\u0435) \u0438 ap\u0101na (\u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0443\u044E \u044D\u043D\u0435\u0440\u0433\u0438\u044E, \u0432\u0445\u043E\u0434\u044F\u0449\u0443\u044E \u0432 \u0432\u0430\u0441 \u043D\u0430 \u0432\u0434\u043E\u0445\u0435).</p></li><li><p>\u0415\u0441\u043B\u0438 \u0432\u044B \u043E\u0431\u0440\u0430\u0442\u0438\u0442\u0435\u0441\u044C \u043A \u0441\u043B\u043E\u0432\u0430\u0440\u044E, \u0432\u044B \u043D\u0430\u0439\u0434\u0435\u0442\u0435, \u0447\u0442\u043E &quot;\u0101kar\u1E63a\u1E47a&quot; \u0432 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u043C \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u043D\u0430\u0442\u044F\u0436\u0435\u043D\u0438\u0435, \u043F\u0440\u0438\u0431\u043B\u0438\u0436\u0435\u043D\u0438\u0435, \u043F\u0440\u0438\u0432\u043B\u0435\u0447\u0435\u043D\u0438\u0435 \u0438 \u0442.\u043F.&quot;. \u0417\u0434\u0435\u0441\u044C \u044D\u0442\u043E \u0431\u044B\u043B\u043E \u043F\u0435\u0440\u0435\u0432\u0435\u0434\u0435\u043D\u043E \u043C\u043D\u043E\u0439 \u043A\u0430\u043A &quot;\u043C\u0430\u0441\u0442\u0435\u0440\u0441\u0442\u0432\u043E&quot;, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0438\u0441\u0445\u043E\u0434\u043D\u044B\u0439 \u043A\u043E\u0440\u0435\u043D\u044C \u2014 \u044D\u0442\u043E \u043D\u0435 &quot;\u0101k\u1E5B\u1E63&quot;, \u043E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u0430 &quot;k\u1E5B\u1E63&quot; (\u0442\u0430\u043A \u043A\u0430\u043A &quot;\u0101&quot;\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0441\u0442\u0430\u0432\u043A\u043E\u0439, \u0434\u043E\u0431\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u0439 \u043A \u043A\u043E\u0440\u043D\u044E); \u0438 \u043E\u0434\u043D\u043E \u0438\u0437 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0439 &quot;k\u1E5B\u1E63&quot;\u2014 \u044D\u0442\u043E &quot;\u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0441\u0432\u043E\u044E \u0441\u0438\u043B\u0443, \u0441\u0442\u0430\u0442\u044C \u043C\u0430\u0441\u0442\u0435\u0440\u043E\u043C&quot;. \u0422\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u043D\u044F\u0442\u043D\u043E!</p></li><li><p>\u0422\u0435\u0440\u043C\u0438\u043D\u044B \u043B\u0443\u043D\u0430 \u0438 \u0441\u043E\u043B\u043D\u0446\u0435 \u0437\u0430\u0432\u0438\u0441\u044F\u0442 \u043E\u0442 \u0443\u0440\u043E\u0432\u043D\u044F, \u043D\u0430 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0441\u0442\u0440\u0435\u043C\u044F\u0449\u0438\u0439\u0441\u044F. \u0412 \u0100\u1E47avop\u0101ya, \u043B\u0443\u043D\u0430 \u0438 \u0441\u043E\u043B\u043D\u0446\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0442 ap\u0101na \u0438 pr\u0101\u1E47a, \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E (\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u043F\u0440\u0438\u043C\u0435\u0447\u0430\u043D\u0438\u0435 5, \u043E\u043F\u0443\u0431\u043B\u0438\u043A\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u0432\u044B\u0448\u0435). \u0412 \u015A\u0101ktop\u0101ya, \u043E\u043D\u0438 \u0441\u0438\u043C\u0432\u043E\u043B\u0438\u0437\u0438\u0440\u0443\u044E\u0442 J\xF1\u0101na\u015Bakti (\u0421\u0438\u043B\u0443 \u0417\u043D\u0430\u043D\u0438\u044F) \u0438 Kriy\u0101\u015Bakti (\u0421\u0438\u043B\u0443 \u0414\u0435\u0439\u0441\u0442\u0432\u0438\u044F). \u0418 \u043D\u0430\u043A\u043E\u043D\u0435\u0446, \u0432 \u015A\u0101mbhavop\u0101ya \u043E\u043D\u0438 \u0441\u0438\u043C\u0432\u043E\u043B\u0438\u0437\u0438\u0440\u0443\u044E\u0442 Vimar\u015Ba (\u015Aakti) \u0438 Prak\u0101\u015Ba (\u015Aiva).</p></li><li><p>\u0412\u044B\u0441\u0448\u0438\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C , \u0432\u0434\u043E\u0445\u043D\u043E\u0432\u043B\u044F\u044E\u0449\u0438\u0439 \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E Yog\u012B, \u044F\u0432\u043B\u044F\u044F \u0441\u0432\u0435\u0442 \u0438 \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E, \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u0435\u0442 \u043F\u043E\u0442\u043E\u043A ap\u0101na \u0438 pr\u0101\u1E47a (\u0442.\u0435. \u041E\u043D \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430 \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u0442\u044C \u0441\u0432\u043E\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0432\u0434\u043E\u0445 \u0438 \u0432\u044B\u0434\u043E\u0445). \u0417\u0430\u0442\u0435\u043C \u041E\u043D \u043F\u043E\u0434\u043D\u0438\u043C\u0430\u0435\u0442 sam\u0101na, \u0431\u0430\u043B\u0430\u043D\u0441\u0438\u0440\u0443\u044F \u043F\u043E\u0442\u043E\u043A ap\u0101na \u0438 pr\u0101\u1E47a \u0432 \u043E\u0431\u043B\u0430\u0441\u0442\u0438 \u043F\u0443\u043F\u043A\u0430 (\u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0434\u044B\u0445\u0430\u043D\u0438\u044F \u043E\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0437\u0434\u0435\u0441\u044C). \u0412 \u0437\u0430\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435, \u043A\u043E\u0433\u0434\u0430 \u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u043E \u043F\u043E\u0434\u0430\u0432\u043B\u044F\u0435\u0442, \u0438\u043B\u0438 \u0441\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442 sam\u0101na, \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u043F\u043E\u0442\u043E\u043A \u0432\u0434\u043E\u0445\u0430 \u0438 \u0432\u044B\u0434\u043E\u0445\u0430 \u0432\u043E\u0437\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F. \u0412 \u044D\u0442\u043E \u0432\u0440\u0435\u043C\u044F, \u0432\u0441\u0435, \u0447\u0442\u043E \u0436\u0435\u043B\u0430\u0435\u0442 Yog\u012B, \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0435\u0442 \u043F\u0435\u0440\u0435\u0434 \u043D\u0438\u043C. \u0411\u0435\u0437 \u0415\u0433\u043E \u041C\u0438\u043B\u043E\u0441\u0442\u0438 \u043D\u0438\u043A\u0442\u043E \u043D\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u0434\u043E\u0441\u0442\u0438\u0447\u044C \u044D\u0442\u043E\u0433\u043E.</p></li><li><p>\u042F \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u043B \u0434\u043E\u0431\u0430\u0432\u0438\u0442\u044C \u043E\u0441\u0442\u0430\u0432\u0448\u0443\u044E\u0441\u044F \u0447\u0430\u0441\u0442\u044C \u0441\u0442\u0440\u043E\u0444\u044B \u0432 \u0441\u043A\u043E\u0431\u043A\u0435, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0431\u0435\u0437 \u044D\u0442\u043E\u0433\u043E \u0444\u0440\u0430\u0437\u0430 \u043D\u0435 \u0438\u043C\u0435\u043B\u0430 \u0431\u044B \u0441\u043C\u044B\u0441\u043B\u0430. \u0412 \u0434\u0440\u0443\u0433\u0438\u0445 \u0441\u043B\u0443\u0447\u0430\u044F\u0445 \u044F \u0431\u044B \u043C\u043E\u0433 \u0434\u043E\u0431\u0430\u0432\u0438\u0442\u044C \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u0441 \u043C\u043D\u043E\u0433\u043E\u0442\u043E\u0447\u0438\u0435\u043C, \u043D\u043E \u0432 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 \u044F \u043D\u0435 \u043C\u043E\u0433\u0443.</p></li></ol></div><div class="stanza"><a href="#s1.20" id="s1.20" class="num">1.20</a><div class="sans"><p>\u0905\u0928\u094D\u092F\u093E \u0905\u092A\u094D\u092F\u0938\u094D\u092F \u092F\u0925\u093E\u092D\u093F\u0932\u0937\u093F\u0924\u093E\u0903 \u0938\u093F\u0926\u094D\u0927\u092F \u090F\u0924\u0928\u094D\u092E\u093E\u0939\u093E\u0924\u094D\u092E\u094D\u092F\u0947\u0928\u0948\u0935 \u0918\u091F\u0928\u094D\u0924 \u0907\u0924\u094D\u092F\u093E\u0939\u2014</p><blockquote><p><strong>\u092D\u0942\u0924\u0938\u0928\u094D\u0927\u093E\u0928\u092D\u0942\u0924\u092A\u0943\u0925\u0915\u094D\u0924\u094D\u0935\u0935\u093F\u0936\u094D\u0935\u0938\u0919\u094D\u0918\u091F\u094D\u091F\u093E\u0903\u0965\u0968\u0966</strong></p></blockquote><p>\u092D\u0942\u0924\u093E\u0928\u093F \u0936\u0930\u0940\u0930\u092A\u094D\u0930\u093E\u0923\u092D\u093E\u0935\u093E\u0926\u094D\u092F\u093E\u0924\u094D\u092E\u0915\u093E\u0928\u093F \u0924\u0947\u0937\u093E\u0902 \u0915\u094D\u0935\u091A\u093F\u0926\u093E\u092A\u094D\u092F\u093E\u092F\u0928\u093E\u0926\u094C \u0938\u0928\u094D\u0927\u093E\u0928\u0902 \u092A\u0930\u093F\u092A\u094B\u0937\u0923\u0902 \u0935\u094D\u092F\u093E\u0927\u094D\u092F\u093E\u0926\u094D\u092F\u0941\u092A\u0936\u092E\u093E\u0926\u094C \u092A\u0943\u0925\u0915\u094D\u0924\u094D\u0935\u0902 \u0936\u0930\u0940\u0930\u093E\u0926\u0947\u0930\u094D\u0935\u093F\u0936\u094D\u0932\u0947\u0937\u0923\u0902 \u0926\u0947\u0936\u0915\u093E\u0932\u093E\u0926\u093F\u0935\u093F\u092A\u094D\u0930\u0915\u0943\u0937\u094D\u091F\u0938\u094D\u092F \u091A \u0935\u093F\u0936\u094D\u0935\u0938\u094D\u092F \u0938\u0918\u091F\u094D\u091F\u094B \u091C\u094D\u091E\u093E\u0928\u0935\u093F\u0937\u092F\u0940\u0915\u093E\u0930\u094D\u092F\u0924\u094D\u0935\u093E\u0926\u093F\u0915\u094B\u093D\u0938\u094D\u092F \u092A\u0942\u0930\u094D\u0935\u094B\u0915\u094D\u0924\u0936\u0915\u094D\u0924\u093F\u0938\u0928\u094D\u0927\u093E\u0928\u0947 \u0938\u0924\u093F \u091C\u093E\u092F\u0924\u0947\u0964 \u090F\u0924\u091A\u094D\u091A \u0938\u0930\u094D\u0935\u093E\u0917\u092E\u0947\u0937\u0941 \u0938\u093E\u0927\u0928\u093E\u0927\u093F\u0915\u093E\u0930\u0947\u0937\u094D\u0935\u0938\u094D\u0924\u093F\u0964 \u0924\u0926\u0947\u0935 \u0938\u094D\u092A\u0928\u094D\u0926\u0947</p><blockquote><p>\u0926\u0941\u0930\u094D\u092C\u0932\u094B\u093D\u092A\u093F \u0924\u0926\u093E\u0915\u094D\u0930\u092E\u094D\u092F \u092F\u0924\u0903 \u0915\u093E\u0930\u094D\u092F\u0947 \u092A\u094D\u0930\u0935\u0930\u094D\u0924\u0924\u0947 \u0906\u091A\u094D\u091B\u093E\u0926\u092F\u0947\u0926\u094D\u092C\u0941\u092D\u0941\u0915\u094D\u0937\u093E\u0902 \u091A \u0924\u0925\u093E \u092F\u094B\u093D\u0924\u093F\u092C\u0941\u092D\u0941\u0915\u094D\u0937\u093F\u0924\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964</p><blockquote><p>\u0917\u094D\u0932\u093E\u0928\u093F\u0930\u094D\u0935\u093F\u0932\u0941\u0923\u094D\u0920\u093F\u0915\u093E \u0926\u0947\u0939\u0947 \u0924\u0938\u094D\u092F\u093E\u0936\u094D\u091A\u093E\u091C\u094D\u091E\u093E\u0928\u0924\u0903 \u0938\u0943\u0924\u093F\u0903 \u0924\u0926\u0941\u0928\u094D\u092E\u0947\u0937\u0935\u093F\u0932\u0941\u092A\u094D\u0924\u0902 \u091A\u0947\u0924\u094D\u0915\u0941\u0924\u0903 \u0938\u093E \u0938\u094D\u092F\u093E\u0926\u0939\u0947\u0924\u0941\u0915\u093E\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964</p><blockquote><p>\u092F\u0925\u093E \u0939\u094D\u092F\u0930\u094D\u0925\u094B\u093D\u0938\u094D\u092B\u0941\u091F\u094B \u0926\u0943\u0937\u094D\u091F\u0903 \u0938\u093E\u0935\u0927\u093E\u0928\u0947\u093D\u092A\u093F \u091A\u0947\u0924\u0938\u093F \u092D\u0942\u092F\u0903 \u0938\u094D\u092B\u0941\u091F\u0924\u0930\u094B \u092D\u093E\u0924\u093F \u0938\u094D\u0935\u092C\u0932\u094B\u0926\u094D\u092F\u094B\u0917\u092D\u093E\u0935\u093F\u0924\u0903\u0965<br> \u0924\u0925\u093E \u092F\u0924\u094D\u092A\u0930\u092E\u093E\u0930\u094D\u0925\u0947\u0928 \u092F\u0947\u0928 \u092F\u0924\u094D\u0930 \u092F\u0925\u093E \u0938\u094D\u0925\u093F\u0924\u092E\u094D \u0924\u0924\u094D\u0924\u0925\u093E \u092C\u0932\u092E\u093E\u0915\u094D\u0930\u092E\u094D\u092F \u0928 \u091A\u093F\u0930\u093E\u0924\u094D\u0938\u092E\u094D\u092A\u094D\u0930\u0935\u0930\u094D\u0924\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u093E\u0926\u093F\u0928\u093E \u0935\u093F\u092D\u0942\u0924\u093F\u0938\u094D\u092A\u0928\u094D\u0926\u0947 \u0938\u094B\u092A\u092A\u0924\u094D\u0924\u093F\u0915\u0902 \u0926\u0930\u094D\u0936\u093F\u0924\u092E\u094D\u0965\u0968\u0966\u0965</p></div><hr><div class="trans"><p>Any\u0101 apyasya yath\u0101bhila\u1E63it\u0101\u1E25 siddhaya etanm\u0101h\u0101tmyenaiva gha\u1E6Danta ity\u0101ha\u2014</p><blockquote><p><strong>Bh\u016Btasandh\u0101nabh\u016Btap\u1E5Bthaktvavi\u015Bvasa\u1E45gha\u1E6D\u1E6D\u0101\u1E25||20||</strong></p></blockquote><p>Bh\u016Bt\u0101ni \u015Bar\u012Brapr\u0101\u1E47abh\u0101v\u0101dy\u0101tmak\u0101ni te\u1E63\u0101\u1E41 kvacid\u0101py\u0101yan\u0101dau sandh\u0101na\u1E41 paripo\u1E63a\u1E47a\u1E41 vy\u0101dhy\u0101dyupa\u015Bam\u0101dau p\u1E5Bthaktva\u1E41 \u015Bar\u012Br\u0101dervi\u015Ble\u1E63a\u1E47a\u1E41 de\u015Bak\u0101l\u0101diviprak\u1E5B\u1E63\u1E6Dasya ca vi\u015Bvasya sagha\u1E6D\u1E6Do j\xF1\u0101navi\u1E63ay\u012Bk\u0101ryatv\u0101diko&#39;sya p\u016Brvokta\u015Baktisandh\u0101ne sati j\u0101yate| Etacca sarv\u0101game\u1E63u s\u0101dhan\u0101dhik\u0101re\u1E63vasti| Tadeva spande</p><blockquote><p>Durbalo&#39;pi tad\u0101kramya yata\u1E25 k\u0101rye pravartate \u0100cch\u0101dayedbubhuk\u1E63\u0101\u1E41 ca tath\u0101 yo&#39;tibubhuk\u1E63ita\u1E25||</p></blockquote><p>iti|</p><blockquote><p>Gl\u0101nirvilu\u1E47\u1E6Dhik\u0101 dehe tasy\u0101\u015Bc\u0101j\xF1\u0101nata\u1E25 s\u1E5Bti\u1E25 Tadunme\u1E63avilupta\u1E41 cetkuta\u1E25 s\u0101 sy\u0101dahetuk\u0101||</p></blockquote><p>iti|</p><blockquote><p>Yath\u0101 hyartho&#39;sphu\u1E6Do d\u1E5B\u1E63\u1E6Da\u1E25 s\u0101vadh\u0101ne&#39;pi cetasi Bh\u016Bya\u1E25 sphu\u1E6Dataro bh\u0101ti svabalodyogabh\u0101vita\u1E25| Tath\u0101 yatparam\u0101rthena yena yatra yath\u0101 sthitam Tattath\u0101 balam\u0101kramya na cir\u0101tsampravartate||</p></blockquote><p>ity\u0101din\u0101 vibh\u016Btispande sopapattika\u1E41 dar\u015Bitam||20||</p></div><hr><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0432\u0435\u043B\u0438\u0447\u0438\u044E <em>(m\u0101h\u0101tmyena eva)</em> \u044D\u0442\u043E\u0433\u043E --\u0442.\u0435. \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044E \u0441 \u0435\u0433\u043E Icch\u0101\u015Bakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u043E\u0439 \u0412\u043E\u043B\u0438-- <em>(etad)</em>, \u0434\u0440\u0443\u0433\u0438\u0435 <em>(any\u0101\u1E25)</em> \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0438\u043B\u044B <em>(siddhaya\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 <em>(yath\u0101)</em> \u0436\u0435\u043B\u0430\u0435\u0442 [Yog\u012B] <em>(abhila\u1E63it\u0101\u1E25)</em>, \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0430\u044E\u0442\u0441\u044F <em>(gha\u1E6Dante)</em> \u0438\u043C <em>(asya)</em> \u0442\u0430\u043A\u0436\u0435 <em>(api)</em>. \u041E\u0431 \u044D\u0442\u043E\u043C [\u015Aiva] \u0441\u043A\u0430\u0437\u0430\u043B [\u0432 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435] <em>(iti \u0101ha)</em>\u2014</p><blockquote><p><strong>[\u0414\u0440\u0443\u0433\u0438\u0435 \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0438\u043B\u044B \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u043E\u0433\u043E Yog\u012B \u0442\u0430\u043A\u043E\u0432\u044B: \u0441\u0438\u043B\u0430] \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F <em>(sandh\u0101na)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 <em>(bh\u016Bta)</em>; [\u0441\u0438\u043B\u0430] \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u044F <em>(p\u1E5Bthaktva)</em> \u0432\u0441\u0435\u0445 \u0438\u0445--\u0442.\u0435. \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432-- <em>(bh\u016Bta)</em> [\u0438 \u0441\u0438\u043B\u0430] \u0432\u043E\u0441\u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F --sa\u1E45gha\u1E6D\u1E6Da-- <em>(sa\u1E45gha\u1E6D\u1E6D\u0101\u1E25)</em> \u0432\u0441\u0435\u0433\u043E <em>(vi\u015Bva)</em>, [\u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u043E \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E\u043C \u0438 \u0432\u0440\u0435\u043C\u0435\u043D\u0435\u043C]||20||</strong></p></blockquote><p>The bh\u016Bta-s --\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B-- <em>(bh\u016Bt\u0101ni)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u0442 \u0438\u0437 <em>(\u0101tmak\u0101ni)</em> \u0442\u0435\u043B\u0430 <em>(\u015Bar\u012Bra)</em>, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(pr\u0101\u1E47a)</em>, \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 <em>(bh\u0101va)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>. Sandh\u0101na --\u043E\u0431\u044A\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435-- <em>(sandh\u0101nam)</em> \u0442\u0435\u0445 [\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432] <em>(te\u1E63\u0101m)</em>, --\u0442.\u0435. bh\u016Btasandh\u0101na--, [\u044D\u0442\u043E \u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435, \u0447\u0442\u043E \u0438] \u0441\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 <em>(paripo\u1E63a\u1E47am)</em> \u0443\u0432\u0435\u043B\u0438\u0447\u0435\u043D\u0438\u044E \u0431\u043B\u0430\u0433\u043E\u0434\u0435\u043D\u0441\u0442\u0432\u0438\u044F <em>(\u0101py\u0101yana)</em>, \u0438 \u0442.\u0434. <em>(\u0101dau)</em> \u0432 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0441\u043B\u0443\u0447\u0430\u044F\u0445 <em>(kvacid)</em><sup>1</sup> . P\u1E5Bthaktva <em>(p\u1E5Bthaktvam)</em> [\u2014 \u044D\u0442\u043E] \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435 <em>(vi\u015Ble\u1E63a\u1E47am)</em> \u0442\u0435\u043B\u0430 <em>(\u015Bar\u012Bra)</em>, \u0438 \u0442.\u0434. <em>(\u0101de\u1E25)</em> \u0434\u043B\u044F \u043E\u0431\u043B\u0435\u0433\u0447\u0435\u043D\u0438\u044F <em>(upa\u015Bama)</em> \u0431\u043E\u043B\u0435\u0437\u043D\u0435\u0439 <em>(vy\u0101dhi)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em> \u0438 \u0442\u043E\u043C\u0443 \u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0435 <em>(\u0101dau)</em><sup>2</sup> . \u0418 \u0432\u043E\u0441\u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 <em>(sa\u1E45gha\u1E6D\u1E6Da\u1E25)</em> \u0432\u0441\u0435\u0433\u043E <em>(vi\u015Bvasya)</em>, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u043E <em>(viprak\u1E5B\u1E63\u1E6Dasya)</em>, \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E\u043C <em>(de\u015Ba)</em>, \u0432\u0440\u0435\u043C\u0435\u043D\u0435\u043C <em>(k\u0101la)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, _\u2014 \u044D\u0442\u043E] \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0435\u043D\u0438\u0435 [\u0432\u0441\u0435\u0445 \u044D\u0442\u0438\u0445 \u0432\u0435\u0449\u0435\u0439] <em>(k\u0101ryatv\u0101)</em> \u0432 \u043E\u0431\u044A\u0435\u043A\u0442\u044B [\u0435\u0433\u043E] \u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na-vi\u1E63ay\u012B)</em>, \u0438 \u0442.\u043F. <em>(\u0101dika\u1E25)</em><sup>3</sup>. [\u042D\u0442\u0430 \u0433\u0440\u0443\u043F\u043F\u0430 \u0438\u0437 \u0442\u0440\u0435\u0445 \u0441\u0438\u043B] \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442\u0441\u044F <em>(j\u0101yate)</em> \u0438\u043C <em>(asya)</em>, \u043A\u043E\u0433\u0434\u0430 \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 <em>(sandh\u0101ne sati)</em> \u0441 \u0421\u0438\u043B\u043E\u0439 [\u0412\u043E\u043B\u0438] <em>(\u015Bakti)</em>, \u043A\u0430\u043A \u043E\u043F\u0438\u0441\u0430\u043D\u043E <em>(ukta)</em> \u0432\u044B\u0448\u0435 <em>(p\u016Brva)</em>|</p><p>\u042D\u0442\u043E <em>(etad ca)</em> \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u0435\u0442\u0441\u044F --\u0442.\u0435 \u0431\u044B\u043B\u043E \u0440\u0430\u0441\u0441\u043C\u043E\u0442\u0440\u0435\u043D\u043E-- <em>(asti)</em> \u0432\u043E \u0432\u0441\u0435\u0445 <em>(sarva)</em> \u0100gama-s --\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u0445 \u041F\u0438\u0441\u0430\u043D\u0438\u044F\u0445-- <em>(\u0101game\u1E63u)</em>, \u0432 \u0433\u043B\u0430\u0432\u0430\u0445 <em>(adhik\u0101re\u1E63u)</em> s\u0101dhana --\u043C\u0435\u0442\u043E\u0434\u0430\u0445 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u0432, \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u0442\u0432\u0430 \u0438 \u0442.\u043F.-- <em>(s\u0101dhana)</em>|</p><p>\u042D\u0442\u043E <em>(tad)</em> \u0436\u0435 \u0441\u0430\u043C\u043E\u0435 [\u0443\u0447\u0435\u043D\u0438\u0435] <em>(eva)</em> \u0431\u044B\u043B\u043E \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u043E <em>(dar\u015Bitam)</em> \u0441 \u043E\u0431\u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u044B\u043C\u0438 \u0430\u0440\u0433\u0443\u043C\u0435\u043D\u0442\u0430\u043C\u0438 _(sopapattikam)_\u0432 [\u0440\u0430\u0437\u0434\u0435\u043B\u0435] Vibh\u016Btispanda --\u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0438\u043B\u044B, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0435 \u0438\u0437 \u0421\u043F\u0430\u043D\u0434\u044B-- <em>(vibh\u016Bti-spande)</em> \u0432 Spandak\u0101rik\u0101-s <em>(spande)</em> \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0445 \u0438] \u0434\u0440\u0443\u0433\u0438\u0445 [\u0441\u0442\u0440\u043E\u0444] <em>(\u0101din\u0101)</em>|</p><blockquote><p>&quot;\u0414\u0430\u0436\u0435 <em>(api)</em> \u0441\u043B\u0430\u0431\u044B\u0439 \u0447\u0435\u043B\u043E\u0432\u0435\u043A <em>(durbala\u1E25)</em>, \u0443\u0445\u0432\u0430\u0442\u0438\u0432\u0448\u0438\u0439\u0441\u044F \u0437\u0430 <em>(\u0101kramya)</em> \u044D\u0442\u043E [\u0421\u043F\u0430\u043D\u0434\u0443, \u0438\u043B\u0438 \u041A\u043E\u0441\u043C\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u0421\u0438\u043B\u0443] <em>(tad)</em>, \u0432\u043E\u0432\u043B\u0435\u043A\u0430\u0435\u0442\u0441\u044F [\u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441] <em>(pravartate)</em> \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0441\u0434\u0435\u043B\u0430\u043D\u043E <em>(k\u0101rye)</em> [\u0438 \u0432\u043F\u043E\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0438 \u0434\u043E\u0431\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0443\u0441\u043F\u0435\u0445\u0430] \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443 \u0441\u0430\u043C\u043E\u043C\u0443 \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0443 <em>(yatas)</em>. \u0422\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435 <em>(ca tath\u0101)</em>, \u0442\u043E\u0442, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u043D\u0435\u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E \u0433\u043E\u043B\u043E\u0434\u0435\u043D <em>(ati-bubhuk\u1E63ita\u1E25)</em>, \u043F\u0440\u0435\u043E\u0434\u043E\u043B\u0435\u0432\u0430\u0435\u0442 <em>(\u0101ch\u0101dayet)</em> [\u0441\u0432\u043E\u0435] \u0436\u0435\u043B\u0430\u043D\u0438\u0435 \u0435\u0441\u0442\u044C <em>(bubhuk\u1E63\u0101m... iti)</em>&quot;| [\u0421\u043C. Spandak\u0101rik\u0101-s III, 6]</p></blockquote><blockquote><p>&quot;\u0414\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u044F <em>(gl\u0101ni\u1E25)</em> [\u043F\u043E\u0434\u043E\u0431\u043D\u0430] \u0433\u0440\u0430\u0431\u0438\u0442\u0435\u043B\u044E <em>(vilu\u1E47\u1E6Dhik\u0101)</em> \u0432 \u0442\u0435\u043B\u0435 <em>(dehe)</em>. \u041E\u043D\u0430 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(tasy\u0101\u1E25 ca... s\u1E5Bti\u1E25)</em> \u0438\u0437 \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0430 <em>(aj\xF1\u0101nata\u1E25)</em>. \u0415\u0441\u043B\u0438 <em>(ced)</em> \u043E\u043D\u0430 \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0435\u043D\u0430 <em>(viluptam)</em> \u044D\u0442\u043E\u0439 <em>(tad)</em> Unme\u1E63a --\u0441\u043C\u043E\u0442\u0440\u0438\u0442\u0435 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C-- <em>(unme\u1E63a)</em>, \u043A\u0430\u043A <em>(kutas)</em> \u043C\u043E\u0436\u0435\u0442 \u044D\u0442\u0430 [\u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u044F] \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C <em>(s\u0101 sy\u0101t)</em> \u0431\u0435\u0437 [\u0441\u0432\u043E\u0435\u0439] \u043F\u0440\u0438\u0447\u0438\u043D\u044B <em>(ahetuk\u0101... iti)</em>?&quot;| [\u0421\u043C. Spandak\u0101rik\u0101-s III, 8]</p></blockquote><blockquote><p>&quot;\u041D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(hi)</em>, \u0442\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435, \u043A\u0430\u043A <em>(yath\u0101)</em> \u0432\u0435\u0449\u044C <em>(artha\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F <em>(d\u1E5B\u1E63\u1E6Da\u1E25)</em> \u043D\u0435\u0432\u043D\u044F\u0442\u043D\u043E <em>(asphu\u1E6Dam)</em> [\u043F\u043E\u043D\u0430\u0447\u0430\u043B\u0443], \u0434\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 <em>(api)</em>[\u043D\u0435\u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E] \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0439 <em>(sa-avadh\u0101ne)</em> \u0443\u043C <em>(cetasi)</em> [\u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0432\u043E\u0432\u043B\u0435\u0447\u0435\u043D\u043D\u044B\u043C \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F], \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0435\u0442 <em>(bh\u0101ti)</em> \u0431\u043E\u043B\u0435\u0435 \u044F\u0432\u0441\u0442\u0432\u0435\u043D\u043D\u043E <em>(sphu\u1E6Datara\u1E25)</em> \u0432\u043F\u043E\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0438 <em>(bh\u016Byas)</em>, \u043A\u043E\u0433\u0434\u0430 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442 <em>(bh\u0101vita\u1E25)</em> \u0441 \u0431\u043E\u043B\u044C\u0448\u0438\u043C \u043D\u0430\u043F\u0440\u044F\u0436\u0435\u043D\u0438\u0435\u043C <em>(udyoga)</em> \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva)</em> \u0441\u0438\u043B\u044B <em>(bala)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tath\u0101)</em>, \u0437\u0430\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u044F <em>(\u0101kramya)</em>\xA0[\u041A\u043E\u0441\u043C\u0438\u0447\u0435\u0441\u043A\u0443\u044E] \u0421\u0438\u043B\u0443 <em>(balam)</em>, \u043B\u044E\u0431\u0430\u044F \u0432\u0435\u0449\u044C <em>(yad)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E <em>(param\u0101rthena)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(sthitam)</em> \u0432 \u043B\u044E\u0431\u043E\u0439 \u0444\u043E\u0440\u043C\u0435 <em>(yena)</em>, \u0432 \u043B\u044E\u0431\u043E\u043C \u043C\u0435\u0441\u0442\u0435 <em>(yatra)</em>, \u0432 \u043B\u044E\u0431\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 <em>(yath\u0101)</em>, \u044D\u0442\u0430 [\u0441\u0430\u043C\u0430\u044F \u0432\u0435\u0449\u044C] <em>(tad)</em> \u043D\u0435\u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E <em>(na cir\u0101t)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(sampravartate)</em> \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(tath\u0101... iti)</em>&quot;| [\u0421\u043C. Spandak\u0101rik\u0101-s III, 4-5]</p></blockquote><p>||20||</p><hr><ol><li><p>\u041D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0442\u0435\u043B\u043E, \u0443\u043C\u0438\u0440\u0430\u044E\u0449\u0435\u0435 \u043E\u0442 \u0433\u043E\u043B\u043E\u0434\u0430, \u043C\u043E\u0436\u0435\u0442 \u043F\u0438\u0442\u0430\u0442\u044C\u0441\u044F \u044D\u0442\u0438\u043C \u0432\u0435\u043B\u0438\u043A\u0438\u043C Yog\u012B, \u043F\u0440\u043E\u0441\u0442\u043E \u043F\u043E\u0436\u0435\u043B\u0430\u0432, \u0447\u0442\u043E\u0431\u044B \u044D\u0442\u043E \u0442\u0435\u043B\u043E \u0432\u0441\u0442\u0443\u043F\u0438\u043B\u043E \u0432 \u043A\u043E\u043D\u0442\u0430\u043A\u0442 \u0441 \u043F\u0438\u0449\u0435\u0439. \u041D\u0435\u0442 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0441\u0442\u0438 \u0434\u043B\u044F \u043D\u0435\u0433\u043E \u043F\u0440\u0438\u043D\u043E\u0441\u0438\u0442\u044C \u043F\u0438\u0449\u0443 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438.</p></li><li><p>\u041D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u043E\u043D \u043C\u043E\u0436\u0435\u0442 \u043E\u0442\u0434\u0435\u043B\u0438\u0442\u044C \u043E\u043F\u0443\u0445\u043E\u043B\u044C \u043E\u0442 \u0442\u0435\u043B\u0430, \u0447\u0442\u043E\u0431\u044B \u0432\u044B\u043B\u0435\u0447\u0438\u0442\u044C\u0441\u044F.</p></li><li><p>\u041D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u043E\u043D \u043C\u043E\u0436\u0435\u0442 \u0437\u043D\u0430\u0442\u044C, \u0447\u0442\u043E \u0441\u043B\u0443\u0447\u0438\u043B\u043E\u0441\u044C \u0432 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0439 \u043C\u043E\u043C\u0435\u043D\u0442 \u0432 \u043F\u0440\u043E\u0448\u043B\u043E\u043C \u0438\u043B\u0438 \u0431\u0443\u0434\u0443\u0449\u0435\u043C. \u0418\u043B\u0438 \u0435\u0449e, \u043E\u043D \u043C\u043E\u0436\u0435\u0442 \u0437\u043D\u0430\u0442\u044C, \u0447\u0442\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0432 \u0434\u0440\u0443\u0433\u043E\u043C \u0443\u0433\u043E\u043B\u043A\u0435 \u043F\u043B\u0430\u043D\u0435\u0442\u044B \u043F\u0440\u044F\u043C\u043E \u0441\u0435\u0439\u0447\u0430\u0441. \u041E\u043D \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u0434\u0435\u043B\u0430\u0442\u044C \u0432\u0441\u0435 \u044D\u0442\u0438 \u0432\u0435\u0449\u0438 \u043F\u043E \u0441\u0432\u043E\u0435\u0439 \u0432\u043E\u043B\u0435, \u0445\u043E\u0442\u044F \u0431\u043E\u043B\u044C\u0448\u0443\u044E \u0447\u0430\u0441\u0442\u044C \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u043E\u043D\u0438 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0442 \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E \u0438\u0437-\u0437\u0430 \u0435\u0433\u043E \u044D\u043A\u0441\u0442\u0440\u0430\u043E\u0440\u0434\u0438\u043D\u0430\u0440\u043D\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F.</p></li></ol><p>\u0425\u043E\u0442\u044F \u0412\u044B\u0441\u0448\u0435\u0435 \u042F \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0432\u043E \u0432\u0441\u0435\u043C, \u044D\u0442\u0438 \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0438\u043B\u044B, \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0435 \u0432 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435, \u043D\u0430\u0441\u0442\u043E\u043B\u044C\u043A\u043E \u0434\u0430\u043B\u0435\u043A\u0438 \u043E\u0442 \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432, \u043F\u043E\u043B\u043D\u044B\u0445 \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u0447\u0442\u043E &quot;\u043F\u043E-\u0432\u0438\u0434\u0438\u043C\u043E\u043C\u0443&quot; \u0431\u0435\u0441\u043F\u043E\u043B\u0435\u0437\u043D\u043E \u043F\u0438\u0441\u0430\u0442\u044C \u043E \u0442\u0430\u043A\u0438\u0445 \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u044B\u0445 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044F\u0445, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u043B\u044E\u0434\u0435\u0439 \u043F\u0440\u043E\u0441\u0442\u043E \u043D\u0438\u0447\u0435\u0433\u043E \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u043F\u043E\u043D\u044F\u0442\u044C \u0432 \u044D\u0442\u043E\u043C (\u0432\u043A\u043B\u044E\u0447\u0430\u044F \u043F\u043E\u0447\u0442\u0438 \u0432\u0441\u0435\u0445 \u0434\u0443\u0445\u043E\u0432\u043D\u044B\u0445 \u0438\u0441\u043A\u0430\u0442\u0435\u043B\u0435\u0439, \u043A\u043E\u043D\u0435\u0447\u043D\u043E... \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0440\u0430\u0437\u043D\u0438\u0446\u0430 \u0437\u0430\u043A\u043B\u044E\u0447\u0430\u0435\u0442\u0441\u044F \u0432 \u0442\u043E\u043C, \u0447\u0442\u043E \u0434\u0443\u0445\u043E\u0432\u043D\u044B\u0435 \u043B\u044E\u0434\u0438 \u0438\u043C\u0435\u044E\u0442 &quot;\u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0435 \u044D\u0433\u043E, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0434\u0443\u043C\u0430\u0435\u0442, \u0447\u0442\u043E \u043E\u043D\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043F\u043E\u043D\u0438\u043C\u0430\u044E\u0442 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E&quot;, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u0443 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u0435\u0441\u0442\u044C \u043C\u0438\u0440\u0441\u043A\u0438\u0435 \u044D\u0433\u043E, \u043A\u043E\u0442\u043E\u0440\u044B\u043C \u043F\u0440\u043E\u0441\u0442\u043E \u0432\u0441\u0435 \u044D\u0442\u043E \u043D\u0435 \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u043E... \u0432 \u043B\u044E\u0431\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u044D\u0442\u043E \u0442\u043E\u0442 \u0436\u0435 \u0441\u0430\u043C\u044B\u0439 \u0431\u0438\u0447, \u043D\u043E \u043F\u043E-\u0434\u0440\u0443\u0433\u043E\u043C\u0443 \u043E\u043A\u0440\u0430\u0448\u0435\u043D). \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0432\u0441\u0435 \u043E\u043D\u0438 \u041D\u0415 \u044D\u043A\u0441\u0442\u0440\u0430\u043E\u0440\u0434\u0438\u043D\u0430\u0440\u043D\u044B. \u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, &quot;\u0432\u0438\u0434\u0438\u043C\u043E&quot; \u0441\u043C\u0435\u0448\u043D\u043E \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C \u043E\u0431\u043E \u0432\u0441\u0435\u0445 \u044D\u0442\u0438\u0445 \u0443\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u0432\u0435\u0449\u0430\u0445, \u0432\u0438\u0434\u044F \u0431\u0435\u0441\u043F\u043E\u043C\u043E\u0449\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F \u0432\u0435\u0434\u0443\u0442 \u0441\u0435\u0431\u044F \u043A\u0430\u043A \u043D\u0438\u0449\u0438\u0435, \u0442\u0435\u0440\u043F\u044F\u0449\u0438\u0435 \u0431\u0435\u0434\u0441\u0442\u0432\u0438\u0435. \u041D\u0443, \u044F \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438 \u041F\u0438\u0441\u0430\u043D\u0438\u0435 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E, \u0445\u043E\u0442\u044F \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0432\u0435\u043B\u0438\u043A\u0438\u0445 Yog\u012B-s \u0432 \u044D\u0442\u043E\u043C \u043C\u0438\u0440\u0435, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u043E \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 K\u1E63emar\u0101ja, \u043C\u043E\u0436\u043D\u043E \u0431\u044B\u043B\u043E \u0431\u044B \u043F\u0435\u0440\u0435\u0441\u0447\u0438\u0442\u0430\u0442\u044C \u043F\u0430\u043B\u044C\u0446\u0430\u043C\u0438 \u043E\u0434\u043D\u043E\u0439 \u0440\u0443\u043A\u0438.</p><p>\u0412 \u0446\u0435\u043B\u043E\u043C, \u043C\u043E\u044F \u0437\u0430\u0434\u0430\u0447\u0430 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430 \u044D\u0442\u043E\u0433\u043E \u0442\u0440\u0443\u0434\u043D\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F \u0432\u044B\u0433\u043B\u044F\u0434\u0438\u0442 \u043A\u0430\u043A \u0448\u0443\u0442\u043A\u0430, \u0438\u043B\u0438 \u043F\u043E\u0442\u0435\u0440\u044F \u0432\u0440\u0435\u043C\u0435\u043D\u0438, \u0435\u0441\u043B\u0438 \u0443\u0447\u0438\u0442\u044B\u0432\u0430\u0442\u044C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u0440\u0435\u0434\u043D\u0435\u0433\u043E \u0443\u0447\u0435\u043D\u0438\u043A\u0430 \u0419\u043E\u0433\u0438. \u0412\u043E \u0432\u0441\u044F\u043A\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u0438\u043C\u0435\u044E\u0442\u0441\u044F \u0431\u043E\u043B\u0435\u0435 \u0432\u0435\u0441\u043A\u0438\u0435 \u0430\u0440\u0433\u0443\u043C\u0435\u043D\u0442\u044B, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044E\u0449\u0438\u0435 \u043C\u043E\u0438 \u0443\u0441\u0438\u043B\u0438\u044F: \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043F\u0435\u0440\u0432\u044B\u0439 \u0440\u0430\u0437\u0434\u0435\u043B \u015Aivas\u016Btra-s \u043A\u0430\u0441\u0430\u0435\u0442\u0441\u044F \u015A\u0101mbhavop\u0101ya (\u043C\u0435\u0442\u043E\u0434\u043E\u0432, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u0445\u0441\u044F \u043A \u015Aiva), \u0432\u0441\u0435 \u044D\u0442\u0438 \u0443\u0447\u0435\u043D\u0438\u044F \u0438 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F \u043F\u0440\u0435\u0434\u043D\u0430\u0437\u043D\u0430\u0447\u0435\u043D\u044B \u0434\u043B\u044F \u0432\u0435\u043B\u0438\u043A\u0438\u0445 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0435\u0439, \u0438\u0434\u0443\u0449\u0438\u0445 \u043F\u043E \u044D\u0442\u043E\u043C\u0443 \u043F\u0443\u0442\u0438 (\u0434\u043B\u044F \u043E\u0447\u0435\u043D\u044C \u043D\u0435\u043C\u043D\u043E\u0433\u0438\u0445, \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435). \u041E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u0443\u0447\u0435\u043D\u0438\u043A\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u0435 \u0441\u0432\u043E\u0435\u043C \u0434\u043E\u043B\u0436\u043D\u044B \u0438\u0434\u0442\u0438 \u043F\u0443\u0442\u0435\u043C \u0100\u1E47avop\u0101ya (\u043C\u0435\u0442\u043E\u0434\u043E\u0432, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u0445\u0441\u044F \u043A \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430\u043C), \u0431\u0443\u0434\u0443\u0442 \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u0441\u0432\u043E\u0435\u043C\u0443 \u0443\u0440\u043E\u0432\u043D\u044E. \u0417\u043D\u0430\u043D\u0438\u0435 \u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043E\u043D\u0438 \u043C\u043E\u0433\u0443\u0442 \u0434\u043E\u0441\u0442\u0438\u0447\u044C, \u043C\u043E\u0436\u0435\u0442 \u0442\u0430\u043A\u0436\u0435 \u0432\u043E\u0437\u0432\u044B\u0441\u0438\u0442\u044C. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u043D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E \u044D\u0442\u043E \u043A\u0430\u0436\u0435\u0442\u0441\u044F \u0430\u0431\u0441\u0443\u0440\u0434\u043E\u043C \u043D\u0430 \u043F\u0435\u0440\u0432\u044B\u0439 \u0432\u0437\u0433\u043B\u044F\u0434 \u0442\u0440\u0430\u0442\u0438\u0442\u044C \u0441\u0442\u043E\u043B\u044C\u043A\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438, \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u044F \u0432\u0441\u0435 \u044D\u0442\u0438 \u043E\u043F\u0438\u0441\u0430\u043D\u0438\u044F \u043E \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F\u0445 \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E Yog\u012B, \u043A\u043E\u0433\u0434\u0430 &quot;\u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438&quot; 99% \u0438\u0441\u043A\u0430\u0442\u0435\u043B\u0435\u0439 \u0435\u0434\u0432\u0430 \u043B\u0438 \u043C\u043E\u0433\u0443\u0442 \u043C\u0435\u0434\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043D\u0430 \u0412\u044B\u0441\u0448\u0435\u0435 \u042F \u043F\u0440\u0438\u043C\u0435\u0440\u043D\u043E 15 \u043C\u0438\u043D\u0443\u0442 \u0432 \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u043C \u0440\u0435\u0436\u0438\u043C\u0435 \u043A\u0430\u0436\u0434\u044B\u0439 \u0434\u0435\u043D\u044C, \u0432 \u043A\u043E\u043D\u0446\u0435 \u043A\u043E\u043D\u0446\u043E\u0432 \u044D\u0442\u043E \u0438\u043C\u0435\u0435\u0442 \u043A\u0430\u043A\u043E\u0439-\u0442\u043E \u0441\u043C\u044B\u0441\u043B, \u0435\u0441\u043B\u0438 \u0443\u0447\u0435\u0441\u0442\u044C, \u0447\u0442\u043E \u043F\u0435\u0440\u0432\u0430\u044F \u0413\u043B\u0430\u0432\u0430 \u0441\u0432\u044F\u0437\u0430\u043D\u0430 \u0441 \u0432\u044B\u0441\u0448\u0438\u043C \u015A\u0101mbhavop\u0101ya.</p><p>\u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, \u0435\u0441\u0442\u044C \u043E\u0434\u043D\u0430 \u0431\u043E\u043B\u0435\u0435 \u0433\u043B\u0443\u0431\u043E\u043A\u0430\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u0430 \u0434\u043B\u044F \u043C\u0435\u043D\u044F \u0432\u0437\u044F\u0442\u044C \u043D\u0430 \u0441\u0435\u0431\u044F \u0442\u0440\u0443\u0434 \u0434\u0435\u043B\u0430\u0442\u044C \u0432\u0441\u0435 \u044D\u0442\u043E...\u043D\u0443, \u044D\u0442\u043E \u043C\u043E\u0435 \u043F\u043E\u0434\u043D\u043E\u0448\u0435\u043D\u0438\u0435 \u0412\u043B\u0430\u0434\u044B\u043A\u0435 \u0432\u0441\u0435\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, \u043A\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0414\u0435\u043B\u0430\u0442\u0435\u043B\u0435\u043C \u0432\u0441\u0435\u0445 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439 \u0438 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0438\u043C \u0410\u0432\u0442\u043E\u0440\u043E\u043C \u0432\u0441\u0435\u0445 \u0421\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0445 \u041F\u0438\u0441\u0430\u043D\u0438\u0439. \u041F\u0443\u0441\u0442\u044C \u044D\u0442\u043E\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430 \u0432\u0441\u0435\u0433\u0434\u0430 \u043F\u0440\u0435\u0432\u043E\u0437\u043D\u043E\u0441\u044F\u0442! \u042D\u0442\u043E\u0442 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 \u043F\u043E\u044F\u0432\u0438\u043B\u0441\u044F \u0432 \u043E\u0441\u043E\u0431\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u043C\u043E\u0435\u0433\u043E \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430. \u041E\u0447\u0435\u043D\u044C \u0445\u043E\u0440\u043E\u0448\u043E, \u0442\u043E\u0433\u0434\u0430 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0439\u0442\u0435 \u0447\u0438\u0442\u0430\u0442\u044C \u0443\u0447\u0435\u043D\u0438\u044F.</p></div><div class="stanza"><a href="#s1.21" id="s1.21" class="num">1.21</a><div class="sans"><p>\u092F\u0926\u093E \u0924\u0941 \u092E\u093F\u0924\u0938\u093F\u0926\u094D\u0927\u0940\u0930\u0928\u092D\u093F\u0932\u0937\u094D\u092F\u0928\u094D\u0935\u093F\u0936\u094D\u0935\u093E\u0924\u094D\u092E\u092A\u094D\u0930\u0925\u093E\u092E\u093F\u091A\u094D\u091B\u0924\u093F \u0924\u0926\u093E\u0938\u094D\u092F\u2014</p><blockquote><p><strong>\u0936\u0941\u0926\u094D\u0927\u0935\u093F\u0926\u094D\u092F\u094B\u0926\u092F\u093E\u091A\u094D\u091A\u0915\u094D\u0930\u0947\u0936\u0924\u094D\u0935\u0938\u093F\u0926\u094D\u0927\u093F\u0903\u0965\u0968\u0967</strong></p></blockquote><p>\u0935\u0948\u0936\u094D\u0935\u093E\u0924\u094D\u092E\u094D\u092F\u092A\u094D\u0930\u0925\u093E\u0935\u093E\u091E\u094D\u091B\u092F\u093E \u092F\u0926\u093E \u0936\u0915\u094D\u0924\u093F\u0902 \u0938\u0928\u094D\u0927\u0924\u094D\u0924\u0947 \u0924\u0926\u093E \u0905\u0939\u092E\u0947\u0935 \u0938\u0930\u094D\u0935\u092E\u093F\u0924\u093F \u0936\u0941\u0926\u094D\u0927\u0935\u093F\u0926\u094D\u092F\u093E\u092F\u093E \u0909\u0926\u092F\u093E\u0926\u094D\u0935\u093F\u0936\u094D\u0935\u093E\u0924\u094D\u092E\u0915\u0938\u094D\u0935\u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u0947\u0936\u0924\u094D\u0935\u0930\u0942\u092A\u0902 \u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u094D\u092F\u092E\u0938\u094D\u092F \u0938\u093F\u0927\u094D\u092F\u0924\u093F\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947</p><blockquote><p>\u0924\u0938\u094D\u092E\u093E\u0924\u094D\u0938\u093E \u0924\u0941 \u092A\u0930\u093E \u0935\u093F\u0926\u094D\u092F\u093E \u092F\u0938\u094D\u092E\u093E\u0926\u0928\u094D\u092F\u093E \u0928 \u0935\u093F\u0926\u094D\u092F\u0924\u0947 \u0935\u093F\u0928\u094D\u0926\u0924\u0947 \u0939\u094D\u092F\u0924\u094D\u0930 \u092F\u0941\u0917\u092A\u0924\u094D\u0938\u093E\u0930\u094D\u0935\u091C\u094D\u091E\u094D\u092F\u093E\u0926\u093F\u0917\u0941\u0923\u093E\u0928\u094D\u092A\u0930\u093E\u0928\u094D\u0965<br> \u0935\u0947\u0926\u0928\u093E\u0928\u093E\u0926\u093F\u0927\u0930\u094D\u092E\u0938\u094D\u092F \u092A\u0930\u092E\u093E\u0924\u094D\u092E\u0924\u094D\u0935\u092C\u094B\u0927\u0928\u093E \u0935\u0930\u094D\u091C\u0928\u093E\u092A\u0930\u092E\u093E\u0924\u094D\u092E\u0924\u094D\u0935\u0947 \u0924\u0938\u094D\u092E\u093E\u0926\u094D\u0935\u093F\u0926\u094D\u092F\u0947\u0924\u093F \u0938\u094B\u091A\u094D\u092F\u0924\u0947\u0965<br> \u0924\u0924\u094D\u0930\u0938\u094D\u0925\u094B \u0935\u094D\u092F\u091E\u094D\u091C\u092F\u0947\u0924\u094D\u0924\u0947\u091C\u0903 \u092A\u0930\u0902 \u092A\u0930\u092E\u0915\u093E\u0930\u0923\u092E\u094D \u092A\u0930\u0938\u094D\u092E\u093F\u0902\u0938\u094D\u0924\u0947\u091C\u0938\u093F \u0935\u094D\u092F\u0915\u094D\u0924\u0947 \u0924\u0924\u094D\u0930\u0938\u094D\u0925\u0903 \u0936\u093F\u0935\u0924\u093E\u0902 \u0935\u094D\u0930\u091C\u0947\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0924\u0926\u0947\u0924\u0924\u094D</p><blockquote><p>\u0926\u093F\u0926\u0943\u0915\u094D\u0937\u092F\u0947\u0935 \u0938\u0930\u094D\u0935\u093E\u0930\u094D\u0925\u093E\u0928\u094D\u092F\u0926\u093E \u0935\u094D\u092F\u093E\u092A\u094D\u092F\u093E\u0935\u0924\u093F\u0937\u094D\u0920\u0924\u0947 \u0924\u0926\u093E \u0915\u093F\u0902 \u092C\u0939\u0941\u0928\u094B\u0915\u094D\u0924\u0947\u0928 \u0938\u094D\u0935\u092F\u092E\u0947\u0935\u093E\u0935\u092D\u094B\u0924\u094D\u0938\u094D\u092F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928\u0948\u0935 \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u094D\u0965\u0968\u0967\u0965</p></div><hr><div class="trans"><p>Yad\u0101 tu mitasiddh\u012Branabhila\u1E63yanvi\u015Bv\u0101tmaprath\u0101micchati tad\u0101sya\u2014</p><blockquote><p><strong>\u015Auddhavidyoday\u0101ccakre\u015Batvasiddhi\u1E25||21||</strong></p></blockquote><p>Vai\u015Bv\u0101tmyaprath\u0101v\u0101\xF1chay\u0101 yad\u0101 \u015Bakti\u1E41 sandhatte tad\u0101 ahameva sarvamiti \u015Buddhavidy\u0101y\u0101 uday\u0101dvi\u015Bv\u0101tmakasva\u015Bakticakre\u015Batvar\u016Bpa\u1E41 m\u0101he\u015Bvaryamasya sidhyati| Tadukta\u1E41 svacchande</p><blockquote><p>Tasm\u0101ts\u0101 tu par\u0101 vidy\u0101 yasm\u0101dany\u0101 na vidyate Vindate hyatra yugapats\u0101rvaj\xF1y\u0101digu\u1E47\u0101npar\u0101n| Vedan\u0101n\u0101didharmasya param\u0101tmatvabodhan\u0101 Varjan\u0101param\u0101tmatve tasm\u0101dvidyeti socyate| Tatrastho vya\xF1jayetteja\u1E25 para\u1E41 paramak\u0101ra\u1E47am Parasmi\u1E41stejasi vyakte tatrastha\u1E25 \u015Bivat\u0101\u1E41 vrajet||</p></blockquote><p>iti| Tadetat</p><blockquote><p>Did\u1E5Bk\u1E63ayeva sarv\u0101rth\u0101nyad\u0101 vy\u0101py\u0101vati\u1E63\u1E6Dhate Tad\u0101 ki\u1E41 bahunoktena svayamev\u0101vabhotsyate||</p></blockquote><p>ityanenaiva sa\u1E45g\u1E5Bh\u012Btam||21||</p></div><hr><p>\u041E\u0434\u043D\u0430\u043A\u043E <em>(tu)</em>, \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> [\u044D\u0442\u043E\u0442 \u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B] \u043D\u0435 \u0436\u0430\u0436\u0434\u0435\u0442 <em>(anabhila\u1E63yan)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445 <em>(mita)</em> \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0441\u0438\u043B <em>(siddh\u012B\u1E25)</em>, [\u0430] \u0436\u0435\u043B\u0430\u0435\u0442 <em>(icchati)</em> \u0440\u0430\u0441\u0448\u0438\u0440\u0438\u0442\u044C [\u0441\u0435\u0431\u044F] --\u0438\u043B\u0438 \u044D\u043A\u0441\u043F\u0430\u043D\u0441\u0438\u0438-- <em>(prath\u0101m)</em> \u043A\u0430\u043A \u0412\u044B\u0441\u0448\u0435\u0435 \u042F <em>(\u0101tma)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em> [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u0441 \u043D\u0438\u043C <em>(asya)</em>\u2014</p><blockquote><p><strong>\u041F\u043E\u043B\u043D\u043E\u0435 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 <em>(siddhi\u1E25)</em> \u0433\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u0430 <em>(\u012B\u015Batva)</em> \u043D\u0430\u0434 \u043A\u043E\u043B\u043B\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0439 \u0433\u0440\u0443\u043F\u043F\u043E\u0439 \u0441\u0438\u043B <em>(cakra)</em> [\u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F Yog\u012B] \u0447\u0435\u0440\u0435\u0437 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(uday\u0101t)</em> \u015Auddhavidy\u0101 <em>(\u015Buddhavidy\u0101)</em>||21||</strong></p></blockquote><p>\u041A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> [Yog\u012B], \u0441 \u0436\u0435\u043B\u0430\u043D\u0438\u0435\u043C <em>(v\u0101\xF1chay\u0101)</em> \u0440\u0430\u0441\u0448\u0438\u0440\u0438\u0442\u044C [\u0441\u0435\u0431\u044F] --\u0438\u043B\u0438 \u044D\u043A\u0441\u043F\u0430\u043D\u0441\u0438\u0438-- <em>(prath\u0101)</em> \u043A\u0430\u043A \u0412\u044B\u0441\u0448\u0435\u0435 \u042F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vai\u015Bva-\u0101tmya)</em>, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0435\u0434\u0438\u043D\u044B\u043C \u0441 \u0435\u0433\u043E \u0421\u0438\u043B\u043E\u0439 [\u0412\u043E\u043B\u0438] \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u0433\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044F <em>(\u015Baktim sandhatte)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em> \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044E <em>(uday\u0101t)</em> \u015Auddhavidy\u0101 <em>(\u015Buddhavidy\u0101y\u0101\u1E25)</em>, [\u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0439\u0441\u044F \u043A\u0430\u043A \u043E\u0449\u0443\u0449\u0435\u043D\u0438\u0435, \u0447\u0442\u043E] &quot;\u042F [\u0435\u0441\u0442\u044C] <em>(aham eva)</em> \u0432\u0441\u0435 <em>(sarvam iti)</em>&quot;, \u0435\u043C\u0443 \u0443\u0434\u0430\u0435\u0442\u0441\u044F \u0434\u043E\u0441\u0442\u0438\u0447\u044C <em>(sidhyati)</em> \u0441\u0432\u043E\u0435\u0433\u043E <em>(asya)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u043A\u0430\u043A Mahe\u015Bvara, \u0412\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u041F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044F -\u044D\u043F\u0438\u0442\u0435\u0442 \u015Aiva-- <em>(m\u0101he\u015Bvaryam)</em> \u0432 \u0444\u043E\u0440\u043C\u0435 <em>(r\u016Bpam)</em> \u0433\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u0430 <em>(\u012B\u015Batva)</em> \u043D\u0430\u0434 \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 _(sva)_\u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0439 <em>(vi\u015Bv\u0101tmaka)</em> \u043A\u043E\u043B\u043B\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0439 \u0433\u0440\u0443\u043F\u043F\u043E\u0439 <em>(cakra)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em>|<sup>1</sup></p><p>\u042D\u0442\u043E <em>(tad)</em> \u0431\u044B\u043B\u043E [\u0442\u0430\u043A\u0436\u0435] \u043E\u043F\u0438\u0441\u0430\u043D\u043E <em>(uktam)</em> \u0432 Svacchandatantra <em>(svacchande)</em>:</p><blockquote><p>&quot;\u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(tasm\u0101t)</em>, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yasm\u0101t)</em> \u043D\u0435\u0442 <em>(na vidyate)</em> \u0434\u0440\u0443\u0433\u043E\u0433\u043E <em>(any\u0101)</em>, \u041E\u043D\u0430 <em>(s\u0101)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E <em>(tu)</em> \u0412\u044B\u0441\u0448\u0435\u0439 <em>(par\u0101)</em> Vidy\u0101 --\u0442.\u0435. \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0417\u043D\u0430\u043D\u0438\u0435\u043C-- <em>(vidy\u0101)</em>. \u0417\u0434\u0435\u0441\u044C --\u043A\u043E\u0433\u0434\u0430 \u0412\u044B\u0441\u0448\u0430\u044F Vidy\u0101 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442-- <em>(atra)</em> \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E <em>(ca)</em> [Yog\u012B] \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 <em>(vindate)</em> \u0432\u044B\u0441\u0448\u0438\u0435 <em>(par\u0101n)</em> \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430 <em>(gu\u1E47\u0101n)</em> \u0432\u0441\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F <em>(s\u0101rvaj\xF1ya)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E <em>(yugapad)</em>. [1] \u041E\u043D\u0430 \u043F\u0440\u043E\u0432\u043E\u0434\u0438\u0442 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435 <em>(vedan\u0101)</em> \u0431\u0435\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438 [\u0413\u043E\u0441\u043F\u043E\u0434\u0430] --\u0442.\u0435. \u0415\u0433\u043E \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u044B, \u0438\u043B\u0438 Sv\u0101tantrya-- <em>(an\u0101di-dharmasya)</em>; [2] \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0430\u0435\u0442 \u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F/\u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u044F <em>(bodhan\u0101)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F <em>(parama-\u0101tmatva)</em>; [\u0438] [3] \u0443\u0441\u0442\u0440\u0430\u043D\u044F\u0435\u0442 <em>(varjan\u0101)</em> \u0442\u043E, \u0447\u0442\u043E \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F <em>(a-parama-\u0101tmatve)</em>; \u0438\u0437-\u0437\u0430 [\u0432\u0441\u0435\u0433\u043E] \u044D\u0442\u043E\u0433\u043E <em>(tasm\u0101t)</em> \u041E\u043D\u0430 <em>(s\u0101)</em> \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(ucyate)</em> &#39;Vidy\u0101&#39; <em>(vidy\u0101 iti)__.</em> \u0423\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u0439 <em>(stha\u1E25)</em> \u0442\u0430\u043C --\u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438, \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E\u043C \u043E\u0442 \u0443\u043C\u0430 (unman\u0101), \u0442.\u0435. \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F-- <em>(tatra)</em>, \u043E\u043D \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442 <em>(vya\xF1jayet)</em> \u0412\u044B\u0441\u0448\u0438\u0439 <em>(param)</em> \u0421\u0432\u0435\u0442 <em>(tejas)</em> --\u0442.\u0435. \u0421\u0432\u0435\u0442 \u0413\u043E\u0441\u043F\u043E\u0434\u0430--, \u0412\u044B\u0441\u0448\u0443\u044E <em>(parama)</em> \u041F\u0440\u0438\u0447\u0438\u043D\u0443 <em>(k\u0101ra\u1E47am)</em>. \u0422\u043E\u0442, \u043A\u0442\u043E \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D <em>(stha\u1E25)</em> \u0432 \u044D\u0442\u043E\u043C <em>(tatra)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0438 --vyakta-- _(vyakte)_\u0412\u044B\u0441\u0448\u0435\u0433\u043E --para-- <em>(parasmin)</em> \u0421\u0432\u0435\u0442\u0430 --tejas-- <em>(tejasi)</em> \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 _(vrajet)_\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u015Aiva <em>(\u015Bivat\u0101m... iti)</em>&quot;||<sup>2</sup></p></blockquote><p>[\u0421\u043C. IV, 396-397 \u0432 Svacchandatantra]</p><p>\u0422\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435 <em>(tad etad)</em> \u0431\u044B\u043B\u043E \u0440\u0435\u0437\u044E\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u043E <em>(sa\u1E45g\u1E5Bh\u012Btam)</em> \u044D\u0442\u043E\u0439 <em>(anena eva)</em> [\u0441\u0442\u0440\u043E\u0444\u043E\u0439 \u0432 Spandak\u0101rik\u0101-s]:</p><blockquote><p>&quot;\u041A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> [Yog\u012B], \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0439 \u0432\u0438\u0434\u0435\u0442\u044C <em>(did\u1E5Bk\u1E63ay\u0101)</em>, \u0442\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u0442\u044C <em>(iva)</em>, \u0432\u0441\u0435 <em>(sarva)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u044B <em>(arth\u0101n)</em>, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 <em>(avati\u1E63\u1E6Dhate)</em>, \u043F\u0440\u043E\u043D\u0438\u0437\u044B\u0432\u0430\u044F <em>(vy\u0101pya)</em> [\u0438\u0445 \u0432\u0441\u0435\u0445], \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>, \u043A\u0430\u043A\u043E\u0439 [\u0441\u043C\u044B\u0441\u043B] <em>(kim)</em> \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C <em>(uktena)</em> \u043C\u043D\u043E\u0433\u043E [\u043E\u0431 \u044D\u0442\u043E\u043C] <em>(bahun\u0101)</em>? \u041E\u043D \u0431\u0443\u0434\u0435\u0442 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u044C, \u0438\u043B\u0438 \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0442\u044C [\u044D\u0442\u043E] <em>(avabhotsyate)</em> \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0441\u0430\u043C\u043E\u043C\u0443 \u0441\u0435\u0431\u0435 <em>(svayam eva... iti)</em>!&quot;| [\u0421\u043C. Spandak\u0101rik\u0101-s III, 11]</p></blockquote><p>||21||</p><hr><ol><li><p>\u0422\u0435\u0440\u043C\u0438\u043D \u015Auddhavidy\u0101 \u2014 \u044D\u0442\u043E \u043D\u0435 \u043F\u044F\u0442\u0430\u044F \u0442\u0430\u0442\u0442\u0432\u0430, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0442\u0430\u043A\u0436\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F Sadvidy\u0101. \u0417\u0434\u0435\u0441\u044C \u044D\u0442\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0427\u0438\u0441\u0442\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435&quot;, \u0442.\u0435. \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u044E\u0449\u0435\u0435 \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0442\u044C &quot;\u042F \u0435\u0441\u0442\u044C \u0432\u0441\u0435&quot;. \u042D\u0442\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043E\u0449\u0443\u0449\u0430\u0435\u0442 \u0428\u0438\u0432\u0443 \u0432\u043E \u0432\u0441\u0435\u043C, \u0442\u0430\u043A\u0436\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u015Aivavy\u0101pti. \u0414\u043E\u0431\u0438\u0432\u0448\u0438\u0441\u044C \u0442\u0430\u043A\u043E\u0433\u043E \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u044F, \u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0428\u0438\u0432\u044B \u0438 \u0432 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0425\u043E\u0437\u044F\u0438\u043D\u043E\u043C \u0432\u0441\u0435\u0439 \u0433\u0440\u0443\u043F\u043F\u044B \u0441\u0438\u043B, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0439\u0441\u044F \u043A\u0430\u043A \u044D\u0442\u0430 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F.</p></li><li><p>\u0417\u043D\u0430\u0447\u0435\u043D\u0438\u044F \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0442\u0435\u0440\u043C\u0438\u043D\u043E\u0432 \u0432 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u043C \u0431\u0430\u0437\u0438\u0440\u0443\u044E\u0442\u0441\u044F \u0437\u0434\u0435\u0441\u044C \u043D\u0430 \u043E\u0431\u0448\u0438\u0440\u043D\u044B\u0445 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F\u0445 \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0438 \u043D\u0430 Svacchandatantra. \u041D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u043E\u043D \u0443\u0442\u043E\u0447\u043D\u044F\u0435\u0442, \u0447\u0442\u043E &quot;vedan\u0101&quot;\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 &quot;\u0935\u093F\u091A\u093E\u0930\u0923\u093E&quot; - &quot;vic\u0101ra\u1E47\u0101&quot; (\u0440\u0430\u0437\u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435, \u043F\u0440\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u0442.\u043F.). \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u043C\u043E\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u0431\u044B\u043B &quot;\u043F\u0440\u043E\u0432\u043E\u0434\u0438\u0442 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435&quot;. \u0414\u0440\u0443\u0433\u0438\u0435 \u0442\u0435\u0440\u043C\u0438\u043D\u044B, \u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A &quot;bodhan\u0101&quot;, \u0432\u043A\u043B\u044E\u0447\u0430\u044E\u0449\u0438\u0435 \u043A\u0430\u043A \u043E\u0431\u044B\u0447\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 (\u0435\u0433\u043E \u043C\u043E\u0436\u043D\u043E \u043D\u0430\u0439\u0442\u0438 \u0432 \u0441\u043B\u043E\u0432\u0430\u0440\u044F\u0445), \u0442\u0430\u043A \u0438 \u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0439, \u0434\u0430\u043D\u043D\u044B\u0439 \u043C\u0443\u0434\u0440\u0435\u0446\u043E\u043C \u0442\u0430\u0439\u043D\u043E\u0439 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u043F\u0440\u043E\u0441\u0442\u043E \u043F\u043E\u0432\u0435\u0440\u044C\u0442\u0435 \u043C\u043D\u0435, \u0434\u0440\u0443\u0437\u044C\u044F, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044F \u0432\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u043D\u043E \u0437\u043D\u0430\u044E, \u0447\u0442\u043E \u0434\u0435\u043B\u0430\u044E. \u041D\u0438\u043A\u0430\u043A\u043E\u0433\u043E \u043E\u0431\u043C\u0430\u043D\u0430, \u0431\u0443\u0434\u044C\u0442\u0435 \u0443\u0432\u0435\u0440\u0435\u043D\u044B.</p></li></ol></div><div class="stanza"><a href="#s1.22" id="s1.22" class="num">1.22</a><div class="sans"><p>\u092F\u0926\u093E \u0924\u0941 \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u093E\u0930\u093E\u092E\u0924\u093E\u092E\u0947\u0935\u0947\u091A\u094D\u091B\u0924\u093F \u0924\u0926\u093E\u0938\u094D\u092F\u2014</p><blockquote><p><strong>\u092E\u0939\u093E\u0939\u094D\u0930\u0926\u093E\u0928\u0941\u0938\u0928\u094D\u0927\u093E\u0928\u093E\u0928\u094D\u092E\u0928\u094D\u0924\u094D\u0930\u0935\u0940\u0930\u094D\u092F\u093E\u0928\u0941\u092D\u0935\u0903\u0965\u0968\u0968</strong></p></blockquote><p>\u092A\u0930\u093E \u092D\u091F\u094D\u091F\u093E\u0930\u093F\u0915\u093E \u0938\u0902\u0935\u093F\u0926\u093F\u091A\u094D\u091B\u093E\u0936\u0915\u094D\u0924\u093F\u092A\u094D\u0930\u092E\u0941\u0916\u0902 \u0938\u094D\u0925\u0942\u0932\u092E\u0947\u092F\u092A\u0930\u094D\u092F\u0928\u094D\u0924\u0902 \u0935\u093F\u0936\u094D\u0935\u0902 \u0935\u092E\u0928\u094D\u0924\u0940 \u0916\u0947\u091A\u0930\u0940\u091A\u0915\u094D\u0930\u093E\u0926\u094D\u092F\u0936\u0947\u0937\u0935\u093E\u0939\u092A\u094D\u0930\u0935\u0930\u094D\u0924\u0915\u0924\u094D\u0935\u0938\u094D\u0935\u091A\u094D\u091B\u0924\u094D\u0935\u093E\u0928\u093E\u0935\u0943\u0924\u0924\u094D\u0935\u0917\u092D\u0940\u0930\u0924\u094D\u0935\u093E\u0926\u093F\u0927\u0930\u094D\u092E\u092F\u094B\u0917\u093E\u0928\u094D\u092E\u0939\u093E\u0939\u094D\u0930\u0926\u0938\u094D\u0924\u0938\u094D\u092F\u093E\u0928\u0941\u0938\u0928\u094D\u0927\u093E\u0928\u093E\u0926\u094D \u0905\u0928\u094D\u0924\u0930\u094D\u092E\u0941\u0916\u0924\u092F\u093E\u0928\u093E\u0930\u0924\u0902 \u0924\u0924\u094D\u0924\u093E\u0926\u093E\u0924\u094D\u092E\u094D\u092F\u0935\u093F\u092E\u0930\u094D\u0936\u0928\u093E\u0926\u094D\u0935\u0915\u094D\u0937\u094D\u092F\u092E\u093E\u0923\u0938\u094D\u092F \u0936\u092C\u094D\u0926\u0930\u093E\u0936\u093F\u0938\u094D\u092B\u093E\u0930\u093E\u0924\u094D\u092E\u0915\u092A\u0930\u093E\u0939\u0928\u094D\u0924\u093E\u0935\u093F\u092E\u0930\u094D\u0936\u092E\u092F\u0938\u094D\u092F \u092E\u0928\u094D\u0924\u094D\u0930\u0935\u0940\u0930\u094D\u092F\u0938\u094D\u092F\u093E\u0928\u0941\u092D\u0935\u0903 \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u0930\u0942\u092A\u0924\u092F\u093E \u0938\u094D\u092B\u0941\u0930\u0923\u0902 \u092D\u0935\u0924\u093F\u0964 \u0905\u0924 \u090F\u0935 \u0936\u094D\u0930\u0940\u092E\u093E\u0932\u093F\u0928\u0940\u0935\u093F\u091C\u092F\u0947</p><blockquote><p>\u092F\u093E \u0938\u093E \u0936\u0915\u094D\u0924\u093F\u0930\u094D\u091C\u0917\u0926\u094D\u0927\u093E\u0924\u0941\u0903...\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u092A\u0915\u094D\u0930\u092E\u094D\u092F\u0947\u091A\u094D\u091B\u093E\u0926\u093F\u092A\u094D\u0930\u092E\u0941\u0916\u092A\u091E\u094D\u091A\u093E\u0936\u0926\u094D\u092D\u0947\u0926\u0930\u0942\u092A\u0924\u092F\u093E \u092E\u093E\u0924\u0943\u0915\u093E\u092E\u093E\u0932\u093F\u0928\u0940\u0930\u0942\u092A\u0924\u093E\u092E\u0936\u0947\u0937\u0935\u093F\u0936\u094D\u0935\u092E\u092F\u0940\u0902 \u0936\u0915\u094D\u0924\u0947\u0903 \u092A\u094D\u0930\u0926\u0930\u094D\u0936\u094D\u092F \u0924\u0924 \u090F\u0935 \u092E\u0928\u094D\u0924\u094D\u0930\u094B\u0926\u094D\u0927\u093E\u0930\u094B \u0926\u0930\u094D\u0936\u093F\u0924 \u0907\u0924\u093F \u092A\u0930\u0948\u0935 \u0936\u0915\u094D\u0924\u093F\u0930\u094D\u092E\u0939\u093E\u0939\u094D\u0930\u0926\u0938\u094D\u0924\u0924\u0938\u094D\u0924\u0926\u0928\u0941\u0938\u0928\u094D\u0927\u093E\u0928\u093E\u0928\u094D\u092E\u093E\u0924\u0943\u0915\u093E\u092E\u093E\u0932\u093F\u0928\u0940\u0938\u0924\u0924\u094D\u0924\u094D\u0935\u092E\u0928\u094D\u0924\u094D\u0930\u0935\u0940\u0930\u094D\u092F\u093E\u0928\u0941\u092D\u0935 \u0907\u0924\u093F \u092F\u0941\u0915\u094D\u0924\u092E\u0941\u0915\u094D\u0924\u092E\u094D\u0964 \u090F\u0924\u0926\u0947\u0935</p><blockquote><p>\u0924\u0926\u093E\u0915\u094D\u0930\u092E\u094D\u092F \u092C\u0932\u0902 \u092E\u0928\u094D\u0924\u094D\u0930\u093E\u0903...\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u093E\u0926\u094D\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E \u092D\u0919\u094D\u0917\u094D\u092F\u093E \u092A\u094D\u0930\u0924\u093F\u092A\u093E\u0926\u093F\u0924\u092E\u094D\u0964</p><p>\u0924\u0926\u0947\u0935\u0902 \u091A\u0948\u0924\u0928\u094D\u092F\u092E\u093E\u0924\u094D\u092E\u093E (\u0967-\u0967) \u0907\u0924\u094D\u092F\u0941\u092A\u0915\u094D\u0930\u092E\u094D\u092F \u0924\u0924\u094D\u0938\u094D\u0935\u093E\u0924\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u093E\u0935\u092D\u093E\u0938\u093F\u0924\u0924\u0926\u0916\u094D\u092F\u093E\u0924\u093F\u092E\u092F\u0902 \u0938\u0930\u094D\u0935\u092E\u0947\u0935 \u092C\u0928\u094D\u0927\u0902 \u092F\u0925\u094B\u0915\u094D\u0924\u094B\u0926\u094D\u092F\u092E\u093E\u0924\u094D\u092E\u0915\u092D\u0948\u0930\u0935\u0938\u092E\u093E\u092A\u0924\u094D\u0924\u093F\u0903 \u092A\u094D\u0930\u0936\u092E\u092F\u0928\u094D\u0924\u0940 \u0935\u093F\u0936\u094D\u0935\u0902 \u0938\u094D\u0935\u093E\u0928\u0928\u094D\u0926\u093E\u092E\u0943\u0924\u092E\u092F\u0902 \u0915\u0930\u094B\u0924\u093F \u0938\u0930\u094D\u0935\u093E\u0936\u094D\u091A \u0938\u093F\u0926\u094D\u0927\u0940\u0930\u094D\u092E\u0928\u094D\u0924\u094D\u0930\u0935\u0940\u0930\u094D\u092F\u093E\u0928\u0941\u092A\u094D\u0930\u0935\u0947\u0936\u093E\u0928\u094D\u0924\u093E \u0926\u0926\u093E\u0924\u093F\u0964 \u0907\u0924\u093F \u0936\u093E\u092E\u094D\u092D\u0935\u094B\u092A\u093E\u092F\u092A\u094D\u0930\u0925\u0928\u093E\u0924\u094D\u092E\u093E\u092F\u0902 \u092A\u094D\u0930\u0925\u092E \u0909\u0928\u094D\u092E\u0947\u0937 \u0909\u0915\u094D\u0924\u0903\u0964 \u0905\u0924\u094D\u0930 \u0924\u0941 \u092E\u0927\u094D\u092F\u0947 \u0936\u0915\u094D\u0924\u093F\u0938\u094D\u0935\u0930\u0942\u092A\u092E\u0941\u0915\u094D\u0924\u0902 \u0924\u0924\u094D\u0936\u093E\u092E\u094D\u092D\u0935\u0930\u0942\u092A\u0938\u094D\u092F \u0936\u0915\u094D\u0924\u093F\u092E\u0924\u094D\u0924\u093E\u092A\u094D\u0930\u0926\u0930\u094D\u0936\u0928\u093E\u092D\u093F\u092A\u094D\u0930\u093E\u092F\u0947\u0923\u0947\u0924\u093F \u0936\u093F\u0935\u092E\u094D\u0965\u0968\u0968\u0965</p></div><hr><div class="trans"><p>Yad\u0101 tu sv\u0101tm\u0101r\u0101mat\u0101mevecchati tad\u0101sya\u2014</p><blockquote><p><strong>Mah\u0101hrad\u0101nusandh\u0101n\u0101nmantrav\u012Bry\u0101nubhava\u1E25||22||</strong></p></blockquote><p>Par\u0101 bha\u1E6D\u1E6D\u0101rik\u0101 sa\u1E41vidicch\u0101\u015Baktipramukha\u1E41 sth\u016Blameyaparyanta\u1E41 vi\u015Bva\u1E41 vamant\u012B khecar\u012Bcakr\u0101dya\u015Be\u1E63av\u0101hapravartakatvasvacchatv\u0101n\u0101v\u1E5Btatvagabh\u012Bratv\u0101didharmayog\u0101nmah\u0101hradastasy\u0101nusandh\u0101n\u0101d antarmukhatay\u0101n\u0101rata\u1E41 tatt\u0101d\u0101tmyavimar\u015Ban\u0101dvak\u1E63yam\u0101\u1E47asya \u015Babdar\u0101\u015Bisph\u0101r\u0101tmakapar\u0101hant\u0101vimar\u015Bamayasya mantrav\u012Bryasy\u0101nubhava\u1E25 sv\u0101tmar\u016Bpatay\u0101 sphura\u1E47a\u1E41 bhavati| Ata eva \u015Br\u012Bm\u0101lin\u012Bvijaye</p><blockquote><p>Y\u0101 s\u0101 \u015Baktirjagaddh\u0101tu\u1E25...|</p></blockquote><p>ityupakramyecch\u0101dipramukhapa\xF1c\u0101\u015Badbhedar\u016Bpatay\u0101 m\u0101t\u1E5Bk\u0101m\u0101lin\u012Br\u016Bpat\u0101ma\u015Be\u1E63avi\u015Bvamay\u012B\u1E41 \u015Bakte\u1E25 pradar\u015Bya tata eva mantroddh\u0101ro dar\u015Bita iti paraiva \u015Baktirmah\u0101hradastatastadanusandh\u0101n\u0101nm\u0101t\u1E5Bk\u0101m\u0101lin\u012Bsatattvamantrav\u012Bry\u0101nubhava iti yuktamuktam| Etadeva</p><blockquote><p>Tad\u0101kramya bala\u1E41 mantr\u0101\u1E25...|</p></blockquote><p>ity\u0101dyukty\u0101 bha\u1E45gy\u0101 pratip\u0101ditam|</p><p>Tadeva\u1E41 caitanyam\u0101tm\u0101 (1-1) ityupakramya tatsv\u0101tantry\u0101vabh\u0101sitatadakhy\u0101timaya\u1E41 sarvameva bandha\u1E41 yathoktodyam\u0101tmakabhairavasam\u0101patti\u1E25 pra\u015Bamayant\u012B vi\u015Bva\u1E41 sv\u0101nand\u0101m\u1E5Btamaya\u1E41 karoti sarv\u0101\u015Bca siddh\u012Brmantrav\u012Bry\u0101nuprave\u015B\u0101nt\u0101 dad\u0101ti| Iti \u015B\u0101mbhavop\u0101yaprathan\u0101tm\u0101ya\u1E41 prathama unme\u1E63a ukta\u1E25| Atra tu madhye \u015Baktisvar\u016Bpamukta\u1E41 tat\u015B\u0101mbhavar\u016Bpasya \u015Baktimatt\u0101pradar\u015Ban\u0101bhipr\u0101ye\u1E47eti \u015Bivam||22||</p></div><hr><p>\u041D\u043E <em>(tu)</em> \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> [\u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B] \u0436\u0435\u043B\u0430\u0435\u0442 <em>(icchati)</em> \u043B\u0438\u0448\u044C <em>(eva)</em> \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0442\u044C \u0432\u043E\u0441\u0442\u043E\u0440\u0433 <em>(\u0101r\u0101mat\u0101m)</em> \u0432 \u0441\u0432\u043E\u0435\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C <em>(sva)</em> \u0412\u044B\u0441\u0448\u0435\u043C \u042F <em>(\u0101tma)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em> \u043E\u043D --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E &quot;\u0435\u0433\u043E&quot; \u0438\u043B\u0438 &quot;\u0435\u043C\u0443&quot;-- <em>(asya)</em>\u2014</p><blockquote><p><strong>\u0427\u0435\u0440\u0435\u0437 \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 <em>(anusandh\u0101n\u0101t)</em> \u0441 \u0412\u0435\u043B\u0438\u043A\u0438\u043C <em>(mah\u0101)</em> \u041E\u0437\u0435\u0440\u043E\u043C <em>(hrada)</em>, [Yog\u012B \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442] \u043E\u043F\u044B\u0442 <em>(anubhava\u1E25)</em> \u0436\u0438\u0432\u043E\u0442\u0432\u043E\u0440\u044F\u0449\u0435\u0433\u043E \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430 --\u0441\u0438\u043B\u044B, \u0438\u043B\u0438 \u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430-- <em>(v\u012Brya)</em> [\u0432\u0441\u0435\u0445) _\u043C\u0430\u043D\u0442\u0440 <em>(mantra)</em>||22||</strong></p></blockquote><p>\u0421\u0430\u043C\u043E\u0435 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u0435 <em>(bha\u1E6D\u1E6D\u0101rik\u0101)</em> \u0412\u044B\u0441\u0448\u0435\u0435 <em>(par\u0101)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(sa\u1E41vid)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044D\u043C\u0430\u043D\u0438\u0440\u0443\u0435\u0442 _(vamant\u012B)<em>\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E <em>(vi\u015Bvam)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0449\u0443\u044E\u0441\u044F <em>(pramukham)</em> \u0441 \u0421\u0438\u043B\u044B \u0412\u043E\u043B\u0438 <em>(icch\u0101 \u015Bakti)</em> [\u0438] \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044E\u0449\u0443\u044E\u0441\u044F <em>(paryantam)</em> \u0433\u0440\u0443\u0431\u044B\u043C\u0438 <em>(sth\u016Bla)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438 <em>(meya)</em> <sup>1</sup> , [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0412\u0435\u043B\u0438\u043A\u0438\u043C <em>(mah\u0101)</em> \u041E\u0437\u0435\u0440\u043E\u043C <em>(hrada\u1E25)</em> \u0438\u0437-\u0437\u0430 \u0435\u0433\u043E \u0430\u0441\u0441\u043E\u0446\u0438\u0430\u0446\u0438\u0438 <em>(yog\u0101t)</em> \u0441 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A\u0430\u043C\u0438 <em>(dharma)</em>, [\u0442\u0430\u043A\u0438\u043C\u0438 \u043A\u0430\u043A):</em> [1] \u043F\u0440\u0438\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u0432 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 <em>(pravartakatva)</em> \u0432\u0441\u0435\u0445 <em>(a\u015Be\u1E63a)</em> \u0442\u043E\u043A\u043E\u0432, \u0438\u043B\u0438 \u043F\u043E\u0442\u043E\u043A\u043E\u0432 <em>(v\u0101ha)</em>, [\u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A) _\u0433\u0440\u0443\u043F\u043F\u0430 <em>(cakra)</em> Khecar\u012B <em>(khecar\u012B)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em><sup>2</sup>, [2] \u043D\u0430\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u0447\u0438\u0441\u0442\u044B\u043C \u0438 \u043F\u0440\u043E\u0437\u0440\u0430\u0447\u043D\u044B\u043C <em>(svacchatva)</em>, [3] \u043D\u0435-\u0441\u043E\u043A\u0440\u044B\u0442\u043E\u0441\u0442\u044C, \u0438\u043B\u0438 \u043D\u0435 \u0437\u0430\u0432\u0443\u0430\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0441\u0442\u044C <em>(an\u0101v\u1E5Btatva)</em>, [4] \u0433\u043B\u0443\u0431\u0438\u043D\u043D\u043E\u0441\u0442\u044C <em>(gabh\u012Bratva)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>. \u0427\u0435\u0440\u0435\u0437 \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 <em>(anusandh\u0101n\u0101t)</em> \u0441 \u044D\u0442\u0438\u043C [\u0412\u0435\u043B\u0438\u043A\u0438\u043C \u041E\u0437\u0435\u0440\u043E\u043C] <em>(tasya)</em>, [\u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438,] \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u044F \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u044B\u043C <em>(antarmukhatay\u0101... vimar\u015Ban\u0101t)</em> \u0432 [\u0441\u0432\u043E\u0435\u043C] \u043D\u0435\u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0430\u044E\u0449\u0435\u043C\u0441\u044F <em>(an\u0101ratam)</em> \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435 <em>(t\u0101d\u0101tmya)</em> \u0441 \u043D\u0438\u043C <em>(tad)</em>, [\u0442\u043E\u0433\u0434\u0430] \u0441\u0438\u044F\u0435\u0442 \u0432\u043E\u0432\u043D\u0435 <em>(sphura\u1E47a\u1E41 bhavati)</em>, \u043A\u0430\u043A \u0444\u043E\u0440\u043C\u0430 <em>(r\u016Bpatay\u0101)</em> \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F <em>(sva-\u0101tma)</em>, \u043E\u043F\u044B\u0442 <em>(anubhava\u1E25)</em> \u0436\u0438\u0432\u043E\u0442\u0432\u043E\u0440\u044F\u0449\u0435\u0433\u043E \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430--\u0441\u0438\u043B\u044B, \u0438\u043B\u0438 \u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430-- <em>(v\u012Bryasya)</em> [\u0432\u0441\u0435\u0445] \u043C\u0430\u043D\u0442\u0440 <em>(mantra)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 --\u0436\u0438\u0432\u043E\u0442\u0432\u043E\u0440\u044F\u0449\u0438\u0439 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A-- \u043F\u043E\u043B\u043E\u043D <em>(mayasya)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E <em>(par\u0101)</em> \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(ahant\u0101-vimar\u015Ba)</em>, \u0440\u0430\u0441\u0448\u0438\u0440\u044F\u044E\u0449\u0435\u0433\u043E\u0441\u044F <em>(sph\u0101ra-\u0101tmaka)</em> [\u0432 \u0444\u043E\u0440\u043C\u0435] \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 <em>(r\u0101\u015Bi)</em> \u0441\u043B\u043E\u0432 <em>(\u015Babda)</em>|</p><p>\u0418\u043C\u0435\u043D\u043D\u043E \u043F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(atas eva)</em>, \u0432 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u0439 <em>(\u015Br\u012B)</em> M\u0101lin\u012Bvijaya <em>(m\u0101lin\u012Bvijaye)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>(upakramya)</em>:</p><blockquote><p>&quot;\u041E\u043D\u0430 <em>(s\u0101)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F <em>(y\u0101)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0421\u0438\u043B\u043E\u0439 <em>(\u015Bakti\u1E25)</em> \u0422\u0432\u043E\u0440\u0446\u0430 <em>(dh\u0101tu\u1E25)</em> \u043C\u0438\u0440\u0430 <em>(jagat... iti)__...</em>&quot;| [\u0421\u043C. III, 5 \u0432 M\u0101lin\u012Bvijaya]</p></blockquote><p>[\u0438] \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u044F <em>(pradar\u015Bya)</em> \u0444\u043E\u0440\u043C\u0443 <em>(r\u016Bpat\u0101m)</em> M\u0101t\u1E5Bk\u0101 [\u0438] M\u0101lin\u012B <em>(m\u0101t\u1E5Bk\u0101-m\u0101lin\u012B)</em> \u2014\u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 <em>(may\u012Bm)</em> \u0432\u0441\u044E <em>(a\u015Be\u1E63a)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E <em>(vi\u015Bva)</em>\u2014 \u015Aakti --\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0421\u0438\u043B\u0443 \u0413\u043E\u0441\u043F\u043E\u0434\u0430-- <em>(\u015Bakte\u1E25)</em>, \u043A\u0430\u043A \u0441\u043E\u0437\u0434\u0430\u043D\u043D\u0443\u044E <em>(r\u016Bpatay\u0101)</em> \u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u0438\u0435\u043C <em>(bheda)</em> \u043F\u044F\u0442\u0438\u0434\u0435\u0441\u044F\u0442\u0438 [\u0431\u0443\u043A\u0432] <em>(pa\xF1c\u0101\u015Bat)</em>, \u0432\u043E\u0437\u0433\u043B\u0430\u0432\u043B\u044F\u0435\u043C\u0443\u044E <em>(pramukha)</em> [\u0441\u0438\u043B\u043E\u0439] \u0412\u043E\u043B\u0438 <em>(icch\u0101)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u0431\u044B\u043B\u043E \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u043E <em>(dar\u015Bita\u1E25)</em> \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(uddh\u0101ra\u1E25)</em> \u043C\u0430\u043D\u0442\u0440\u044B --\u0442.\u0435. &quot;Aham&quot;, \u0438\u043B\u0438 \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(mantra)</em> \u0438\u0437 \u044D\u0442\u043E\u0439 [\u0441\u0430\u043C\u043E\u0439 \u015Aakti] <em>(tatas eva)</em>|<sup>3</sup></p><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(iti)</em>, \u0412\u044B\u0441\u0448\u0430\u044F <em>(par\u0101)</em> \u015Aakti <em>(\u015Bakti\u1E25)</em> \u0421\u0430\u043C\u0430 <em>(eva)</em> [\u0435\u0441\u0442\u044C] \u0412\u0435\u043B\u0438\u043A\u043E\u0435 <em>(mah\u0101)</em> \u041E\u0437\u0435\u0440\u043E <em>(hrada\u1E25)</em>. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(tatas)</em>, \u0431\u044B\u043B\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(iti yuktam uktam)</em>, [\u0447\u0442\u043E] \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044E <em>(anusandh\u0101n\u0101t)</em> \u0441 \u041D\u0435\u0439 <em>(tad)</em> [Yog\u012B \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442]\u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u0435 <em>(anubhava\u1E25)</em> \u0436\u0438\u0432\u043E\u0442\u0432\u043E\u0440\u044F\u0449\u0435\u0433\u043E \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430 --\u0441\u0438\u043B\u044B, \u0438\u043B\u0438 \u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430-- <em>(v\u012Brya)</em> [\u0432\u0441\u0435\u0445] \u043C\u0430\u043D\u0442\u0440 <em>(mantra)</em>, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(satattva)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] M\u0101t\u1E5Bk\u0101 [\u0438] M\u0101lin\u012B <em>(m\u0101t\u1E5Bk\u0101-m\u0101lin\u012B)</em>|</p><p>\u042D\u0442\u043E <em>(etad eva)</em> [\u0431\u044B\u043B\u043E] \u043A\u043E\u0441\u0432\u0435\u043D\u043D\u043E <em>(bha\u1E45gy\u0101)</em> \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u043E <em>(pratip\u0101ditam)</em> \u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 <em>(\u0101di)</em> \u0444\u0440\u0430\u0437\u043E\u0439 <em>(ukty\u0101)</em> [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0433\u043E \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 \u0432 Spandak\u0101rik\u0101-s]:</p><blockquote><p>&quot;\u0417\u0430\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u044F <em>(\u0101kramya)</em> \u044D\u0442\u0443 <em>(tad)</em> \u0421\u0438\u043B\u0443 <em>(balam)</em>, Mantra-s <em>(mantr\u0101\u1E25)</em>...&quot;| [\u0421\u043C. Spandak\u0101rik\u0101-s II, 1]</p></blockquote><p>\u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(tad)</em>, \u043D\u0430\u0447\u0430\u0432 [\u044D\u0442\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u0435] <em>(upakramya)</em> \u0442\u0430\u043A <em>(evam)</em>: &quot;\u0412\u0441\u0435\u0437\u043D\u0430\u044E\u0449\u0435\u0435 \u0438 \u0432\u0441\u0435\u043C\u043E\u0433\u0443\u0449\u0435\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(caitanyam)</em> [\u0435\u0441\u0442\u044C] \u0412\u044B\u0441\u0448\u0435\u0435 \u042F, \u0438\u043B\u0438 \u0438\u0441\u0442\u0438\u043D\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(\u0101tm\u0101... iti)</em>&quot; \u2014\u0430\u0444\u043E\u0440\u0438\u0437\u043C 1 \u043F\u0435\u0440\u0432\u043E\u0439 \u0413\u043B\u0430\u0432\u044B <em>(1-1)</em>\u2014\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435 <em>(sam\u0101patti\u1E25)</em> \u0411\u0445\u0430\u0439\u0440\u0430\u0432\u044B <em>(bhairava)</em> --\u0442.\u0435. \u0421\u0430\u043C\u043E-\u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044F-- \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(\u0101tmaka)</em> \u0432\u043D\u0435\u0437\u0430\u043F\u043D\u043E\u0439 \u0432\u0441\u043F\u044B\u0448\u043A\u043E\u0439, \u0438\u043B\u0438 \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u0438\u0435\u043C \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(udyama)</em>, \u043A\u0430\u043A \u0431\u044B\u043B\u043E \u043E\u043F\u0438\u0441\u0430\u043D\u043E [\u0432 \u043F\u044F\u0442\u043E\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435] <em>(yath\u0101 ukta)</em>, \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0430\u0435\u0442 <em>(pra\u015Bamayant\u012B)</em> \u0432\u0441\u0435 <em>(sarvam eva)</em> \u0440\u0430\u0431\u0441\u0442\u0432\u043E <em>(bandham)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0438\u0437 <em>(mayam)</em> \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F <em>(akhy\u0101ti)</em> \u043E\u0431 \u042D\u0442\u043E\u043C --\u043E \u0411\u0445\u0430\u0439\u0440\u0430\u0432\u0435-- <em>(tad)</em>, \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u0435 <em>(avabh\u0101sita)</em> \u0415\u0433\u043E <em>(tad)</em> \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u043E\u0439 <em>(sv\u0101tantrya)</em>. [\u0422\u0430\u043A\u043E\u0435 \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435 \u0411\u0445\u0430\u0439\u0440\u0430\u0432\u044B] \u0434\u0435\u043B\u0430\u0435\u0442 <em>(karoti)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E <em>(vi\u015Bvam)</em>, \u043F\u043E\u043B\u043D\u043E\u0439 <em>(mayam)</em> \u041D\u0435\u043A\u0442\u0430\u0440\u0430 <em>(am\u1E5Bta)</em> \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C\u0443 <em>(sva)</em> \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0443 <em>(\u0101nanda)</em>; \u0438 <em>(ca)</em> \u0434\u0430\u0440\u0443\u0435\u0442 <em>(dad\u0101ti)</em> \u0432\u0441\u0435 _(sarv\u0101\u1E25)_\u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0438\u043B\u044B, \u0438\u043B\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430 <em>(siddh\u012B\u1E25)</em> \u0432\u043F\u043B\u043E\u0442\u044C \u0434\u043E <em>(ant\u0101\u1E25)</em> [\u0435\u0433\u043E] \u0432\u0445\u043E\u0434\u0430 <em>(anuprave\u015Ba)</em> \u0432 \u0436\u0438\u0432\u043E\u0442\u0432\u043E\u0440\u044F\u0449\u0438\u0439 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A --\u0441\u0438\u043B\u044B, \u0438\u043B\u0438 \u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430-- <em>(v\u012Brya)</em> [\u0432\u0441\u0435\u0445] \u043C\u0430\u043D\u0442\u0440 <em>(mantra)</em>|</p><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(iti)</em>, \u044D\u0442\u0430 <em>(ayam)</em> \u043F\u0435\u0440\u0432\u0430\u044F <em>(prathama\u1E25)</em> \u0413\u043B\u0430\u0432\u0430 <em>(unme\u1E63a\u1E25)</em> \u0431\u044B\u043B\u0430 \u043F\u043E\u0441\u0442\u0440\u043E\u0435\u043D\u0430 <em>(ukta\u1E25)</em> \u043A\u0430\u043A \u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0430\u0446\u0438\u044F <em>(prathana-\u0101tm\u0101)</em> \u015A\u0101mbhavop\u0101ya --\u043C\u0435\u0442\u043E\u0434\u043E\u0432, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u0445\u0441\u044F \u043A \u015Aambhu, \u0442.\u0435. \u015Aiva-- <em>(\u015B\u0101mbhava-up\u0101ya)</em>|</p><p>\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 <em>(tu)</em>, \u0437\u0434\u0435\u0441\u044C <em>(atra)</em> \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 <em>(madhye)</em>, \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(sva-r\u016Bpam)</em> \u015Aakti <em>(\u015Bakti)</em> \u0431\u044B\u043B\u0430 \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u0430 <em>(uktam)</em>. \u042D\u0442\u043E <em>(tad)</em> [\u0431\u044B\u043B\u043E \u0441\u0434\u0435\u043B\u0430\u043D\u043E] \u0441 \u0446\u0435\u043B\u044C\u044E <em>(abhipr\u0101ye\u1E47a)</em>, (\u0447\u0442\u043E\u0431\u044B) \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C <em>(pradar\u015Bana)</em> \u0421\u0438\u043B\u0443 <em>(pratip\u0101ditam)</em>, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0443\u044E\u0441\u044F \u043A \u015Aiva <em>(\u015B\u0101mbhava-r\u016Bpasya)</em>. \u0414\u0430 \u0431\u0443\u0434\u0435\u0442 \u0431\u043B\u0430\u0433\u043E\u0434\u0435\u043D\u0441\u0442\u0432\u0438\u0435 [\u0434\u043B\u044F \u0432\u0441\u0435\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432] <em>(iti \u015Bivam)</em>!||22||</p><hr><ol><li><p>\u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0441 \u0442\u0440\u0435\u0442\u044C\u0435\u0439 \u0442\u0430\u0442\u0442\u0432\u044B, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 (Sad\u0101\u015Biva) \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0432 \u0433\u0440\u0443\u0431\u044B\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u0445, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0438\u0445 \u0438\u0437 Mah\u0101bh\u016Bta-s (\u0442\u0430\u0442\u0442\u0432\u044B 32-36).</p></li><li><p>Khecar\u012B, Gocar\u012B, Dikcar\u012B \u0438 Bh\u016Bcar\u012B \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u043C\u0438 \u0433\u0440\u0443\u043F\u043F\u0430\u043C\u0438 \u0441\u0438\u043B (\u015Bakti-s). \u041F\u0435\u0440\u0432\u0430\u044F \u0433\u0440\u0443\u043F\u043F\u0430 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u043C\u0443 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u043C\u0443, \u0432\u0442\u043E\u0440\u0430\u044F \u2014 \u043A \u0435\u0433\u043E \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0443-\u044D\u0433\u043E-\u0443\u043C\u0443, \u0442\u0440\u0435\u0442\u044C\u044F \u0441\u0432\u044F\u0437\u0430\u043D\u0430 \u0441 \u0432\u043D\u0435\u0448\u043D\u0438\u043C\u0438 \u0447\u0443\u0432\u0441\u0442\u0432\u0430\u043C\u0438 \u0438 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u044F\u044F \u2014 \u0441 \u0433\u0440\u0443\u0431\u044B\u043C\u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438 (\u0442.\u0435. \u0432\u043D\u0435\u0448\u043D\u0438\u043C\u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438).</p></li><li><p>\u042F \u0434\u043E\u043B\u0436\u0435\u043D \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C \u0432\u0430\u043C \u0432 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0441\u0442\u0435\u043F\u0435\u043D\u0438 \u044D\u0442\u043E \u0442\u0440\u0443\u0434\u043D\u044B\u0439 \u0430\u0431\u0437\u0430\u0446. \u0421\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0439 \u0430\u043B\u0444\u0430\u0432\u0438\u0442 \u0438\u043C\u0435\u0435\u0442 \u0434\u0432\u0430 \u0441\u043F\u043E\u0441\u043E\u0431\u0430 \u043F\u043E\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u044F: M\u0101t\u1E5Bk\u0101 [\u0438] M\u0101lin\u012B. \u041F\u0435\u0440\u0432\u044B\u0439 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u0443\u0435\u0442\u0441\u044F \u0443\u043F\u043E\u0440\u044F\u0434\u043E\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0438\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0435\u0443\u043F\u043E\u0440\u044F\u0434\u043E\u0447\u0435\u043D\u043D\u044B\u043C (\u0438\u043B\u0438 \u0441\u043C\u0435\u0448\u0430\u043D\u043D\u044B\u043C) \u0441\u043F\u043E\u0441\u043E\u0431\u043E\u043C \u043F\u043E\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u044F . \u0423\u043F\u043E\u0440\u044F\u0434\u043E\u0447\u0435\u043D\u043D\u044B\u0439 \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0441 &quot;a&quot; \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0432 &quot;ha&quot;, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u043D\u0435\u0443\u043F\u043E\u0440\u044F\u0434\u043E\u0447\u0435\u043D\u043D\u044B\u0439 \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0441 &quot;na&quot; \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0432 &quot;pha&quot;. Aham (\u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0449\u0438\u0439 &quot;\u042F&quot;), \u043A\u0430\u043A \u043C\u0430\u043D\u0442\u0440\u0430 \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043E \u0437\u0434\u0435\u0441\u044C \u0437\u0430\u043A\u043B\u044E\u0447\u0435\u043D\u0430 \u0432\u0441\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F (\u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432\u043A\u043B\u044E\u0447\u0435\u043D\u044B &quot;a&quot; \u0438 &quot;ha&quot;, \u0432\u0435\u0441\u044C \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0439 \u0430\u043B\u0444\u0430\u0432\u0438\u0442 \u0432 \u0435\u0433\u043E \u0444\u043E\u0440\u043C\u0435 M\u0101t\u1E5Bk\u0101). \u041F\u0440\u043E\u0438\u0441\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u044D\u0442\u0438\u0445 \u0434\u0432\u0443\u0445 \u0444\u043E\u0440\u043C \u043F\u043E\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u044F \u0430\u043B\u0444\u0430\u0432\u0438\u0442\u0430 \u0438\u0434\u0435\u0442 \u0438\u0437 \u0434\u0432\u0443\u0445 \u0432\u0430\u0436\u043D\u044B\u0445 \u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u0438\u0439, \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0445 \u0432 \u0422\u0440\u0438\u043A\u0435: Svacchandatantra \u0438 M\u0101lin\u012Bvijaya (\u0442\u0430\u043A\u0436\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u0430\u044F M\u0101lin\u012Bvijayottara). Svacchandatantra \u0442\u043E\u043B\u044C\u043A\u043E \u0443\u043F\u043E\u043C\u0438\u043D\u0430\u0435\u0442 \u0444\u043E\u0440\u043C\u0443 \u0430\u043B\u0444\u0430\u0432\u0438\u0442\u0430 M\u0101t\u1E5Bk\u0101, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A M\u0101lin\u012Bvijaya \u043F\u043E\u043E\u0449\u0440\u044F\u0435\u0442 \u043F\u043E\u0434\u0432\u0438\u0436\u043D\u0438\u043A\u043E\u0432 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u0444\u043E\u0440\u043C\u0443 M\u0101lin\u012B. \u0421\u043F\u043E\u0431\u043E\u0431 \u0443\u043F\u043E\u0440\u044F\u0434\u043E\u0447\u0438\u0432\u0430\u043D\u0438\u044F \u0431\u0443\u043A\u0432 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0447\u0435\u043D\u044C \u0432\u0430\u0436\u043D\u044B\u043C \u0434\u043B\u044F \u0440\u0438\u0442\u0443\u0430\u043B\u043E\u0432 ny\u0101sa, \u0433\u0434\u0435 \u043A\u0430\u0436\u0434\u0430\u044F \u0447\u0430\u0441\u0442\u044C \u0442\u0435\u043B\u0430 \u0430\u0441\u0441\u043E\u0446\u0438\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0441 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u0439 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u0439 \u0431\u0443\u043A\u0432\u043E\u0439/\u0437\u0432\u0443\u043A\u043E\u043C.</p></li></ol><p>\u0412\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435: &quot;\u2014\u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0432\u0441\u044E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E\u2014&quot; \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A &quot;\u0444\u043E\u0440\u043C\u0435 M\u0101t\u1E5Bk\u0101 [\u0438] M\u0101lin\u012B&quot;. \u0414\u043B\u044F \u0443\u0434\u043E\u0431\u0441\u0442\u0432\u0430 \u043C\u043D\u0435 \u043F\u0440\u0438\u0448\u043B\u043E\u0441\u044C \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u0434\u0432\u0430 \u0434\u043B\u0438\u043D\u043D\u044B\u0445 \u0434\u0435\u0444\u0438\u0441\u0430 \u0438\u043B\u0438 \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u0431\u044B\u043B\u043E \u0431\u044B \u0442\u0440\u0443\u0434\u043D\u0435\u0435 \u043F\u043E\u043D\u044F\u0442\u044C, \u0447\u0435\u043C \u0442\u043E, \u0447\u0442\u043E \u0443\u0436\u0435 \u0435\u0441\u0442\u044C.</p><p>\u0412 \u0437\u0430\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435, \u0435\u0449\u0435 \u043E\u0434\u043D\u0430 \u0432\u0435\u0449\u044C: M\u0101t\u1E5Bk\u0101 \u0442\u0430\u043A\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 \u043A\u0430\u043A P\u016Brvam\u0101lin\u012B, \u0430 M\u0101lin\u012B \u0442\u0430\u043A\u0436\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u044E\u0442 Uttaram\u0101lin\u012B. \u041B\u0430\u0434\u043D\u043E, \u043D\u0430 \u0441\u0435\u0433\u043E\u0434\u043D\u044F \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u0440\u0430\u0441\u043A\u0440\u044B\u0442\u044B\u0445 \u0442\u0430\u0439\u043D.</p></div><div class="stanza"><h2 id="\u043E\u043A\u043E\u043D\u0447\u0430\u043D\u0438\u0435-\u0433n\u0430\u0432\u044B-i" tabindex="-1">\u041E\u043A\u043E\u043D\u0447\u0430\u043D\u0438\u0435 \u0413\u043B\u0430\u0432\u044B I <a class="header-anchor" href="#\u043E\u043A\u043E\u043D\u0447\u0430\u043D\u0438\u0435-\u0433n\u0430\u0432\u044B-i" aria-hidden="true">#</a></h2><div class="sans"><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u092E\u0928\u094D\u092E\u0939\u093E\u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u093E\u091A\u093E\u0930\u094D\u092F\u093E\u092D\u093F\u0928\u0935\u0917\u0941\u092A\u094D\u0924\u092A\u093E\u0926\u092A\u0926\u094D\u092E\u094B\u092A\u091C\u0940\u0935\u093F\u0936\u094D\u0930\u0940\u0915\u094D\u0937\u0947\u092E\u0930\u093E\u091C\u0935\u093F\u0930\u091A\u093F\u0924\u093E\u092F\u093E\u0902 \u0936\u093F\u0935\u0938\u0942\u0924\u094D\u0930\u0935\u093F\u092E\u0930\u094D\u0936\u093F\u0928\u094D\u092F\u093E\u0902 \u0936\u093E\u092E\u094D\u092D\u0935\u094B\u092A\u093E\u092F\u092A\u094D\u0930\u0915\u093E\u0936\u0928\u0902 \u0928\u093E\u092E \u092A\u094D\u0930\u0925\u092E \u0909\u0928\u094D\u092E\u0947\u0937\u0903\u0965\u0967\u0965</p></div><hr><div class="trans"><p>Iti \u015Br\u012Bmanmah\u0101m\u0101he\u015Bvar\u0101c\u0101ry\u0101bhinavaguptap\u0101dapadmopaj\u012Bvi\u015Br\u012Bk\u1E63emar\u0101javiracit\u0101y\u0101\u1E41 \u015Bivas\u016Btravimar\u015Biny\u0101\u1E41 \u015B\u0101mbhavop\u0101yaprak\u0101\u015Bana\u1E41 n\u0101ma prathama unme\u1E63a\u1E25||1||</p></div><hr><p>\u0417\u0434\u0435\u0441\u044C \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F <em>(iti)</em> \u043F\u0435\u0440\u0432\u0430\u044F <em>(prathama\u1E25)</em> \u0413\u043B\u0430\u0432\u0430 <em>(unme\u1E63a\u1E25)</em>, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u0430\u044F <em>(n\u0101ma)</em> \u015A\u0101mbhavop\u0101yaprak\u0101\u015Bana --[\u0413\u043B\u0430\u0432\u0430], \u0440\u0430\u0441\u043A\u0440\u044B\u0432\u0430\u044E\u0449\u0430\u044F \u043C\u0435\u0442\u043E\u0434\u044B, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u0435\u0441\u044F \u043A \u015Aambhu, \u0442.\u0435. \u015Aiva-- <em>(\u015B\u0101mbhava-up\u0101ya-prak\u0101\u015Banam)</em>, \u0432 \u015Aivas\u016Btravimar\u015Bin\u012B <em>(\u015Bivas\u016Btravimar\u015Biny\u0101m)</em>, \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u0439 <em>(viracit\u0101y\u0101m)</em> \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u044B\u043C <em>(\u015Br\u012B)</em> K\u1E63emar\u0101ja <em>(k\u1E63emar\u0101ja)</em>, \u0437\u0430\u0432\u0438\u0441\u044F\u0449\u0438\u043C \u043E\u0442 <em>(upaj\u012Bvi)</em> \u043B\u043E\u0442\u043E\u0441\u043D\u044B\u0445 \u0441\u0442\u043E\u043F --\u0442.\u0435. \u0441\u0442\u043E\u043F, \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u044B\u0445 \u043A\u0430\u043A \u043B\u043E\u0442\u043E\u0441-- <em>(p\u0101da-padma)</em> \u0432\u044B\u0434\u0430\u044E\u0449\u0435\u0433\u043E\u0441\u044F _(\u015Br\u012Bmat)_\u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0433\u043E \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A\u0430 <em>(\u0101c\u0101rya)</em> \u0410\u0431\u0445\u0438\u043D\u0430\u0432\u0430\u0433\u0443\u043F\u0442\u044B <em>(abhinavagupta)</em>, \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E <em>(mah\u0101)</em> \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u0433\u043E Mahe\u015Bvara, \u0412\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430 --\u044D\u043F\u0438\u0442\u0435\u0442 \u015Aiva-- <em>(m\u0101he\u015Bvara)</em>||1||</p></div>',8),o=[p];function r(s,n,u,v,d,h){return m(),e("div",null,o)}var c=a(i,[["render",r]]);export{y as __pageData,c as default};
